def _profiles_routing_matrix(
    *,
    configured_profiles: list[str],
    storage_profiles: list[Any],
    lane_specs: list[dict[str, Any]],
) -> str:
    configured = set(configured_profiles)
    storage_by_name = {str(profile.name): profile for profile in storage_profiles}
    lane_cards = []
    storage_ready = 0
    configured_ready = 0
    placeholder_only = 0
    for spec in lane_specs:
        profile_names = [str(name) for name in spec["profiles"]]
        matched_storage = [storage_by_name[name] for name in profile_names if name in storage_by_name]
        matched_config = [name for name in profile_names if name in configured]
        if matched_storage:
            readiness = "storage_ready"
            storage_ready += 1
            target_href = "#profiles-storage"
            target_label = "Storage Profiles"
            profile_summary = ", ".join(
                f"{profile.name} ({profile.cost_tier})" for profile in matched_storage
            )
        elif matched_config:
            readiness = "configured_ready"
            configured_ready += 1
            target_href = "#profiles-configured"
            target_label = "Configured Profiles"
            profile_summary = ", ".join(matched_config)
        else:
            readiness = "placeholder_only"
            placeholder_only += 1
            target_href = "#profiles-future"
            target_label = "Future Profile Lanes"
            profile_summary = "none stored yet"
        use_for = ", ".join(str(item) for item in spec["use_for"])
        filter_text = " ".join(
            [
                str(spec["key"]),
                str(spec["label"]),
                str(spec["summary"]),
                use_for,
                " ".join(profile_names),
                str(spec["cost"]),
                readiness,
                profile_summary,
                "inactive provider routing provider inactive",
            ]
        ).lower()
        lane_cards.append(
            "".join(
                [
                    f"<article class='profiles-matrix-card' data-profile-lane-key='{_e(spec['key'])}' data-profile-lane-status='{_e(readiness)}' data-profile-lane-provider-active='false' "
                    "data-profile-filter-item='true' "
                    f"data-profile-filter-lane='{_e(spec['key'])}' "
                    "data-profile-filter-kind='matrix_lane' "
                    f"data-profile-filter-readiness='{_e(readiness)}' "
                    f"data-profile-filter-cost='{_e(str(spec['cost']))}' "
                    f"data-profile-filter-text='{_e(filter_text)}'>",
                    f"<h3>{_e(spec['label'])}</h3>",
                    f"<p>{_e(spec['summary'])}</p>",
                    f"<p><strong>Status:</strong> inactive provider routing; {_e(readiness.replace('_', ' '))}.</p>",
                    f"<p><strong>Profiles:</strong> {_e(profile_summary)}</p>",
                    f"<p><strong>Use for:</strong> {_e(use_for)}</p>",
                    f"<a class='profiles-matrix-link' href='{_e(target_href)}'>{_e(target_label)}</a>",
                    "</article>",
                ]
            )
        )
    rows = [
        ("profiles_matrix_lane_count", str(len(lane_specs))),
        ("profiles_matrix_storage_ready_lanes", str(storage_ready)),
        ("profiles_matrix_configured_ready_lanes", str(configured_ready)),
        ("profiles_matrix_placeholder_only_lanes", str(placeholder_only)),
        ("profiles_matrix_provider_routing_active", "false"),
        ("profiles_matrix_model_routing_enabled", "false"),
        ("profiles_matrix_provider_calls_taken", "0"),
        ("profiles_matrix_network_actions_taken", "0"),
        ("profiles_matrix_external_effects_created", "false"),
    ]
    return "".join(
        [
            "<section id='profiles-routing-matrix' class='panel profiles-routing-matrix' data-profiles-routing-matrix='true'><h2>Profile Routing Matrix</h2>",
            "<p class='muted'>A read-only map of future routing lanes, matched local profile records, cost posture, and inactive provider boundaries.</p>",
            "<div class='profiles-matrix-grid' data-profiles-matrix-grid='true'>",
            "".join(lane_cards),
            "</div>",
            "<details class='profiles-matrix-evidence' data-profiles-matrix-evidence='true'><summary>Profiles routing matrix evidence</summary>",
            _kv(rows),
            _ul(
                [
                    f"profiles_matrix_lane: {_e(str(spec['label']))} provider_routing_active=false model_routing_enabled=false"
                    for spec in lane_specs
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _profile_filter_line(
    lane: str,
    kind: str,
    rendered: str,
    *,
    status: str = "unknown",
    cost: str = "unknown",
    extra: str = "",
) -> str:
    rendered_text = re.sub(r"<[^>]+>", " ", rendered)
    text = " ".join([lane, kind, status, cost, extra, rendered_text, "provider inactive"]).lower()
    return (
        f"<span data-profile-filter-item='true' "
        f"data-profile-filter-lane='{_e(lane)}' "
        f"data-profile-filter-kind='{_e(kind)}' "
        f"data-profile-filter-readiness='{_e(status)}' "
        f"data-profile-filter-cost='{_e(cost)}' "
        f"data-profile-filter-text='{_e(text)}'>{rendered}</span>"
    )


def _profile_routing_filter(
    *,
    total_filter_items: int,
    matrix_count: int,
    configured_count: int,
    storage_count: int,
    future_count: int,
) -> str:
    lanes = [
        ("all", "All"),
        ("planning", "Planning"),
        ("coding", "Coding"),
        ("review", "Review"),
        ("docs", "Docs"),
        ("cheap-model", "Cheap"),
        ("frontier-model", "Frontier"),
        ("storage", "Storage"),
        ("configured", "Configured"),
    ]
    buttons = "".join(
        [
            (
                f"<button type='button' class='profile-filter-button' "
                f"data-profile-filter-kind='{_e(key)}' "
                f"aria-pressed='{'true' if key == 'all' else 'false'}'>{_e(label)}</button>"
            )
            for key, label in lanes
        ]
    )
    return "".join(
        [
            "<section id='profile-routing-filter' class='panel profile-routing-filter' "
            "data-profile-routing-filter='true' "
            "data-profile-routing-filter-storage-key='clankeros-profile-routing-filter'>",
            "<h2>Profile Routing Filter</h2>",
            "<p class='muted'>Narrow the inactive profile-routing matrix and profile rows without activating providers.</p>",
            "<div class='profile-filter-controls' data-profile-filter-controls='true'>",
            buttons,
            "<label class='profile-filter-search'>Find "
            "<input type='search' data-profile-filter-query='true' placeholder='profile, lane, cost, use case...'></label>",
            "<button type='button' class='profile-filter-reset' data-profile-filter-reset='true'>Reset filter</button>",
            "<span class='profile-filter-memory-status' data-profile-filter-view-status='true'>View: default</span>",
            "</div>",
            (
                f"<p class='muted' data-profile-filter-status='true'>"
                f"Showing {total_filter_items} of {total_filter_items} profile rows.</p>"
            ),
            "<p class='muted' data-profile-filter-empty='true' hidden>No profile rows match this filter.</p>",
            "<details class='profile-filter-evidence' data-profile-routing-filter-evidence='true'>"
            "<summary>Profile routing filter evidence</summary>",
            _kv(
                [
                    ("profile_filter_status", "available"),
                    ("profile_filter_total_rendered_rows", str(total_filter_items)),
                    ("profile_filter_matrix_rows", str(matrix_count)),
                    ("profile_filter_configured_rows", str(configured_count)),
                    ("profile_filter_storage_rows", str(storage_count)),
                    ("profile_filter_future_rows", str(future_count)),
                    ("profile_filter_lanes", "all planning coding review docs cheap-model frontier-model storage configured"),
                    ("profile_filter_persistence", "browser_local_view_memory"),
                    ("profile_filter_memory_storage", "localStorage:clankeros-profile-routing-filter"),
                    ("profile_filter_memory_fields", "lane query"),
                    ("profile_filter_default", "all"),
                    ("profile_filter_reset", "available"),
                    ("profile_filter_provider_routing_active", "false"),
                    ("profile_filter_model_routing_enabled", "false"),
                    ("profile_filter_write_on_get", "false"),
                    ("profile_filter_provider_calls_taken", "0"),
                    ("profile_filter_network_actions_taken", "0"),
                    ("profile_filter_external_effects_created", "false"),
                    ("profile_filter_push_created", "false"),
                    ("profile_filter_pr_created", "false"),
                    ("profile_filter_deploy_created", "false"),
                ]
            ),
            _ul(
                [
                    "profile_filter: filters already-rendered local profile rows and matrix cards only",
                    "profile_filter: restores lane and query from browser storage",
                    "profile_filter_safety: no provider, model routing, execution, push, PR, deploy, or external mutation",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _profiles_operator_workbench(
    root: Path,
    *,
    configured_profiles: list[str],
    storage_profiles: list[Any],
    future_lanes: list[str],
    profile_path_exists: bool,
) -> str:
    enabled_profiles = [profile for profile in storage_profiles if profile.enabled]
    disabled_profiles = [profile for profile in storage_profiles if not profile.enabled]
    adapter_configured = [
        profile for profile in storage_profiles if profile.adapter_config_json
    ]
    write_allowed = [
        profile
        for profile in storage_profiles
        if str(profile.permissions_json.get("write", "deny")) not in {"deny", "false", "0"}
    ]
    use_for_values = {
        str(item)
        for profile in storage_profiles
        for item in profile.use_for_json
        if item
    }
    workspace = _load_workspace_state(root)
    status = "future_ready"
    first_target = "Planning"
    next_action = "Review future profile lanes"
    target_href = "#profiles-future"
    target_label = "Future Profile Lanes"
    primary_summary = "Future lanes are prepared, but provider routing remains inactive."
    if storage_profiles:
        status = "storage_ready"
        first_target = storage_profiles[0].name
        next_action = "Review storage profile"
        target_href = "#profiles-storage"
        target_label = "Storage Profiles"
        primary_summary = f"{storage_profiles[0].name} is stored locally for future routing review."
    elif configured_profiles:
        status = "configured_ready"
        first_target = configured_profiles[0]
        next_action = "Review configured profile"
        target_href = "#profiles-configured"
        target_label = "Configured Profiles"
        primary_summary = f"{configured_profiles[0]} is present in .clanker/profiles.yml."
    resume_href = "/resume" if workspace.get("open_goal") or workspace.get("open_project") else "/goals"
    resume_label = "/resume" if resume_href == "/resume" else "/goals"
    resume_summary = (
        f"Saved context: {workspace.get('open_goal') or workspace.get('open_project') or 'none'}."
        if resume_href == "/resume"
        else "No saved context yet."
    )
    rows = [
        ("profiles_workbench_status", status),
        ("profiles_workbench_profiles_file", "present" if profile_path_exists else "missing"),
        ("profiles_workbench_configured_profiles", str(len(configured_profiles))),
        ("profiles_workbench_storage_profiles", str(len(storage_profiles))),
        ("profiles_workbench_enabled_profiles", str(len(enabled_profiles))),
        ("profiles_workbench_disabled_profiles", str(len(disabled_profiles))),
        ("profiles_workbench_future_lanes", str(len(future_lanes))),
        ("profiles_workbench_adapter_configured", str(len(adapter_configured))),
        ("profiles_workbench_write_allowed_profiles", str(len(write_allowed))),
        ("profiles_workbench_use_for_labels", str(len(use_for_values))),
        ("profiles_workbench_first_target", first_target),
        ("profiles_workbench_next_action", next_action),
        ("profiles_workbench_target_surface", SafeHtml(f"<a href='{_e(target_href)}'>{_e(target_label)}</a>")),
        ("profiles_workbench_resume_surface", SafeHtml(f"<a href='{_e(resume_href)}'>{_e(resume_label)}</a>")),
        ("profiles_workbench_workspace_project", workspace.get("open_project", "")),
        ("profiles_workbench_workspace_goal", workspace.get("open_goal", "")),
        ("profiles_workbench_workspace_artifact", workspace.get("last_viewed_artifact", "")),
        ("profiles_workbench_provider_routing_active", "false"),
        ("profiles_workbench_provider_calls_taken", "0"),
        ("profiles_workbench_model_routing_enabled", "false"),
        ("profiles_workbench_write_on_get", "false"),
        ("profiles_workbench_network_actions_taken", "0"),
        ("profiles_workbench_external_effects_created", "false"),
    ]
    return "".join(
        [
            "<section class='panel profiles-operator-workbench' data-profiles-operator-workbench='true'><h2>Profiles Operator Workbench</h2>",
            "<p class='muted'>Review future planning, coding, review, docs, cheap-model, and frontier-model lanes without activating providers.</p>",
            "<div class='profiles-workbench-grid' data-profiles-workbench-actions='true'>",
            "<article class='profiles-workbench-card profiles-workbench-primary'><h3>Now</h3>",
            f"<p>{_e(primary_summary)}</p><a class='profiles-workbench-action' data-profiles-workbench-primary='true' href='{_e(target_href)}'>{_e(next_action)}</a></article>",
            "<article class='profiles-workbench-card'><h3>Lanes</h3>",
            f"<p>{len(future_lanes)} inactive future lane{'s' if len(future_lanes) != 1 else ''}.</p><a class='profiles-workbench-link' href='#profiles-future'>Review lanes</a></article>",
            "<article class='profiles-workbench-card'><h3>Storage</h3>",
            f"<p>{len(storage_profiles)} storage profile{'s' if len(storage_profiles) != 1 else ''}; {len(configured_profiles)} configured.</p><a class='profiles-workbench-link' href='#profiles-storage'>Review storage</a></article>",
            "<article class='profiles-workbench-card'><h3>Resume</h3>",
            f"<p>{_e(resume_summary)}</p><a class='profiles-workbench-link' href='{_e(resume_href)}'>{_e(resume_label)}</a></article>",
            "</div>",
            "<details class='profiles-workbench-evidence' data-profiles-workbench-evidence='true'><summary>Profiles workbench evidence</summary>",
            _kv(rows),
            _ul(
                [
                    f"profiles_workbench_now: <a href='{_e(target_href)}'>{_e(next_action)}</a>",
                    f"profiles_workbench_lanes: <a href='#profiles-future'>Review lanes</a>",
                    f"profiles_workbench_storage: <a href='#profiles-storage'>Review storage</a>",
                    f"profiles_workbench_resume: <a href='{_e(resume_href)}'>{_e(resume_label)}</a>",
                    "profiles_workbench_safety: read-only future provider-routing guidance; providers remain inactive",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _profiles_command_bar(
    *,
    configured_profiles: list[str],
    storage_profiles: list[Any],
    future_lanes: list[str],
    profile_path_exists: bool,
) -> str:
    enabled_profiles = [profile for profile in storage_profiles if profile.enabled]
    disabled_profiles = [profile for profile in storage_profiles if not profile.enabled]
    adapter_configured = [
        profile for profile in storage_profiles if profile.adapter_config_json
    ]
    write_allowed = [
        profile
        for profile in storage_profiles
        if str(profile.permissions_json.get("write", "deny")) not in {"deny", "false", "0"}
    ]
    use_for_values = {
        str(item)
        for profile in storage_profiles
        for item in profile.use_for_json
        if item
    }
    first_target = "Planning"
    next_action = "Review future profile lanes"
    target_href = "#profiles-future"
    target_label = "Future Profile Lanes"
    reason = "future_profile_lanes_prepared"
    if storage_profiles:
        first_target = storage_profiles[0].name
        next_action = "Review storage profile"
        target_href = "#profiles-storage"
        target_label = "Storage Profiles"
        reason = "storage_profile_records_available"
    elif configured_profiles:
        first_target = configured_profiles[0]
        next_action = "Review configured profile"
        target_href = "#profiles-configured"
        target_label = "Configured Profiles"
        reason = "configured_profiles_file_available"
    return "".join(
        [
            "<section class='panel profiles-command-bar' data-profiles-command-bar='true'><h2>Profiles Command Bar</h2>",
            "<p class='muted'>One read-only summary of inactive provider-routing preparation and the next local profile review target.</p>",
            "<details class='profiles-command-evidence' data-profiles-command-evidence='true'><summary>Profiles command evidence</summary>",
            _kv(
                [
                    ("profiles_command_status", "available"),
                    ("profiles_command_profiles_file", "present" if profile_path_exists else "missing"),
                    ("profiles_command_configured_profiles", str(len(configured_profiles))),
                    ("profiles_command_storage_profiles", str(len(storage_profiles))),
                    ("profiles_command_enabled_profiles", str(len(enabled_profiles))),
                    ("profiles_command_disabled_profiles", str(len(disabled_profiles))),
                    ("profiles_command_future_lanes", str(len(future_lanes))),
                    ("profiles_command_adapter_configured", str(len(adapter_configured))),
                    ("profiles_command_write_allowed_profiles", str(len(write_allowed))),
                    ("profiles_command_use_for_labels", str(len(use_for_values))),
                    ("profiles_command_first_target", first_target),
                    ("profiles_command_next_action", next_action),
                    (
                        "profiles_command_target_surface",
                        SafeHtml(f"<a href='{_e(target_href)}'>{_e(target_label)}</a>"),
                    ),
                    ("profiles_command_reason", reason),
                    ("profiles_command_provider_routing_active", "false"),
                    ("profiles_command_provider_calls_taken", "0"),
                    ("profiles_command_model_routing_enabled", "false"),
                    ("profiles_command_write_on_get", "false"),
                    ("profiles_command_network_actions_taken", "0"),
                    ("profiles_command_external_effects_created", "false"),
                ]
            ),
            _ul(
                [
                    f"profiles_command_now: {_e(next_action)}",
                    f"profiles_command_click: <a href='{_e(target_href)}'>{_e(target_label)}</a>",
                    f"profiles_command_reason: {_e(reason)}",
                    "profiles_command_safety: read-only inactive provider-routing guidance",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _profile_config_line(name: str) -> str:
    return f"profile={_e(name)} source=.clanker/profiles.yml provider=inactive"


def _storage_profile_line(profile: Any) -> str:
    use_for = ",".join(str(item) for item in profile.use_for_json) or "none"
    write_permission = profile.permissions_json.get("write", "unknown")
    adapter_state = "configured" if profile.adapter_config_json else "not_configured"
    return (
        f"profile={_e(profile.name)} label={_e(profile.label)} "
        f"mode={_e(profile.mode)} cost={_e(profile.cost_tier)} "
        f"model={_e(profile.model)} enabled={str(profile.enabled).lower()} "
        f"write={_e(write_permission)} adapter={_e(adapter_state)} "
        f"use_for={_e(use_for)} provider=inactive"
    )


def _profile_names(lines: list[str]) -> list[str]:
    names = []
    for line in lines:
        stripped = line.strip()
        if stripped.startswith("- name:"):
            names.append(stripped.removeprefix("- name:").strip())
    return names


_FIRST_RUN_STEPS: tuple[tuple[str, str, str], ...] = (
    ("create_project", "Project", "Register ClankerOS project"),
    ("create_first_goal", "Goal", "Create first goal"),
    ("create_first_delegation", "Delegation", "Create scout delegation"),
    ("generate_context_pack", "Context", "Generate context pack"),
    ("run_first_delegation", "Run", "Run first delegation"),
)


def _first_run_step_href(progress: dict[str, Any], step: str) -> str:
    goal_id = str(progress.get("goal_id") or "")
    if step == "create_project":
        return "#first-run-create-project"
    if step == "create_first_goal":
        return "#first-run-create-goal"
    if goal_id:
        return f"/goals/{quote(goal_id)}"
    return "#first-run-guide"


def _first_run_progress_strip(progress: dict[str, Any]) -> str:
    statuses = {
        step: _first_run_step_status(progress, step)
        for step, _label, _action in _FIRST_RUN_STEPS
    }
    done_count = sum(1 for status in statuses.values() if status == "done")
    current_count = sum(1 for status in statuses.values() if status == "current")
    waiting_count = len(_FIRST_RUN_STEPS) - done_count - current_count
    current_step = str(progress["current_step"])
    cards: list[str] = []
    lines: list[str] = []
    for index, (step, label, action) in enumerate(_FIRST_RUN_STEPS, start=1):
        status = statuses[step]
        href = _first_run_step_href(progress, step)
        card_classes = ["first-run-progress-card", f"first-run-progress-{status}"]
        if step == current_step:
            card_classes.append("first-run-progress-current")
        link_label = action if step == current_step else ("Open" if status == "done" else "Waiting")
        lines.append(f"first_run_progress_step: {step} status={status} action={action}")
        cards.append(
            "".join(
                [
                    (
                        f"<article class='{' '.join(card_classes)}' "
                        f"data-first-run-progress-card='true' data-first-run-step='{_e(step)}' "
                        f"data-first-run-step-status='{_e(status)}'>"
                    ),
                    f"<p class='first-run-progress-index'>{index}</p>",
                    f"<h3>{_e(label)}</h3>",
                    f"<p>{_e(action)}</p>",
                    f"<p class='first-run-progress-status'>{_e(status.replace('_', ' '))}</p>",
                    (
                        f"<a class='first-run-progress-action' href='{_e(href)}'>"
                        f"{_e(link_label)}</a>"
                    ),
                    "</article>",
                ]
            )
        )

    return "".join(
        [
            "<section class='panel first-run-progress-strip' data-first-run-progress-strip='true'><h3>First Run Progress</h3>",
            "<p class='muted'>The shortest browser path from an empty checkout to the first completed delegation.</p>",
            "<div class='first-run-progress-bar-row'>",
            f"<progress max='{len(_FIRST_RUN_STEPS)}' value='{done_count}' data-first-run-progress-bar='true'></progress>",
            f"<span>{done_count}/{len(_FIRST_RUN_STEPS)} complete</span>",
            "</div>",
            "<div class='first-run-progress-grid' data-first-run-progress-grid='true'>",
            "".join(cards),
            "</div>",
            "<details class='first-run-progress-evidence' data-first-run-progress-evidence='true'>",
            "<summary>First run progress evidence</summary>",
            _kv(
                [
                    ("first_run_progress_status", "complete" if progress["complete"] else "in_progress"),
                    ("first_run_progress_current_step", current_step),
                    ("first_run_progress_next_action", progress["next_action"]),
                    ("first_run_progress_next_reason", progress["next_reason"]),
                    ("first_run_progress_done_count", str(done_count)),
                    ("first_run_progress_current_count", str(current_count)),
                    ("first_run_progress_waiting_count", str(waiting_count)),
                    ("first_run_progress_total_steps", str(len(_FIRST_RUN_STEPS))),
                    ("first_run_progress_write_on_get", "false"),
                    ("first_run_progress_provider_calls_taken", "0"),
                    ("first_run_progress_network_actions_taken", "0"),
                    ("first_run_progress_external_effects_created", "false"),
                ]
            ),
            _ul(lines + ["first_run_progress_safety: read-only first-run state; confirmed forms remain below"]),
            "</details>",
            "</section>",
        ]
    )


def _first_run_command_bar(root: Path, storage: Storage, progress: dict[str, Any]) -> str:
    goal_id = str(progress.get("goal_id") or "")
    delegation_id = str(progress.get("delegation_id") or "")
    current_step = str(progress["current_step"])
    command_action_label = _first_run_command_action_label(progress)
    action_form = ""
    form_available = False
    inline_form_available = False
    confirmation_required = False
    form_surface: str | SafeHtml = "none"
    if current_step == "create_project":
        form_available = True
        confirmation_required = True
        form_surface = SafeHtml("<a href='#first-run-create-project'>Create Project</a>")
    elif current_step == "create_first_goal":
        form_available = True
        confirmation_required = True
        form_surface = SafeHtml("<a href='#first-run-create-goal'>Create First Goal</a>")
    elif goal_id:
        try:
            goal_state = _goal_state(root, storage, goal_id)
            next_action = _goal_next_action(root, goal_state)
            goal_form = _goal_next_action_form(goal_state, next_action)
        except Exception:
            goal_form = ""
        if goal_form:
            form_available = True
            inline_form_available = True
            confirmation_required = True
            form_surface = SafeHtml(
                f"<a href='#first-run-command-action'>{_e(command_action_label)}</a>"
            )
            action_form = "".join(
                [
                    "<details id='first-run-command-action' class='first-run-command-action' data-first-run-command-action='true' open>",
                    f"<summary>{_e(command_action_label)}</summary>",
                    "<p class='muted'>Run the current first-run step from this guide. Confirmation is still required before any local write or local execution.</p>",
                    goal_form,
                    "</details>",
                ]
            )
        else:
            form_surface = progress["next_surface"]

    goal_surface: str | SafeHtml = (
        SafeHtml(f"<a href='/goals/{quote(goal_id)}'>{_e(goal_id)}</a>") if goal_id else "none"
    )
    delegation_surface: str | SafeHtml = (
        SafeHtml(f"<a href='/delegations/{quote(delegation_id)}'>{_e(delegation_id)}</a>")
        if delegation_id
        else "none"
    )
    rows: list[tuple[str, str | SafeHtml]] = [
        ("first_run_command_status", "complete" if progress["complete"] else "available"),
        ("first_run_command_current_step", current_step),
        ("first_run_command_next_action", progress["next_action"]),
        ("first_run_command_reason", progress["next_reason"]),
        ("first_run_command_target_surface", progress["next_surface"]),
        ("first_run_command_form_surface", form_surface),
        ("first_run_command_action_form_available", str(form_available).lower()),
        (
            "first_run_command_inline_action_form_available",
            str(inline_form_available).lower(),
        ),
        ("first_run_command_confirmation_required", str(confirmation_required).lower()),
        ("first_run_command_project", progress["default_project"]),
        ("first_run_command_goal", goal_surface),
        ("first_run_command_delegation", delegation_surface),
        ("first_run_command_context_pack_ready", str(progress["context_pack_ready"]).lower()),
        (
            "first_run_command_delegation_completed",
            str(progress["delegation_completed"]).lower(),
        ),
        ("first_run_command_resume_surface", SafeHtml("<a href='/resume'>/resume</a>")),
        ("first_run_command_write_on_get", "false"),
        ("first_run_command_provider_calls_taken", "0"),
        ("first_run_command_network_actions_taken", "0"),
        ("first_run_command_external_effects_created", "false"),
    ]
    lines = [
        f"first_run_command_now: {_e(progress['next_action'])}",
        f"first_run_command_click: {progress['next_surface']}",
        f"first_run_command_form: {form_surface}",
        "first_run_command_safety: confirmed local action only; no provider, network, push, PR, or deploy effects",
    ]
    return "".join(
        [
            "<section class='panel first-run-command-bar' data-first-run-command-bar='true'><h3>First Run Command Bar</h3>",
            _kv(rows),
            _ul(lines),
            action_form,
            "</section>",
        ]
    )


