def _goal_ci_handoff(root: Path, state: dict[str, Any]) -> str:
    goal = state["goal"]
    storage = _storage(root)
    project = storage.get_registered_project(goal.project_id)
    project_root = Path(project.root_path) if project else root
    repo = _repo_state(project_root)
    full_commit = _git(project_root, ["rev-parse", "HEAD"]) or repo["commit"]
    repo_slug = _github_repo_slug(project_root)
    latest_record = _latest_ci_evidence_record(root, project_id=goal.project_id)

    source_kind = "none"
    latest_status = "missing"
    latest_scope = "none"
    latest_provider = "none"
    latest_commit = "none"
    latest_run_id = "none"
    latest_url: str | SafeHtml = "none"
    latest_evidence: str | SafeHtml = "none"
    latest_recorded_by = "none"
    branch_matches_current = "missing"
    commit_matches_current = "missing"
    matches_current = False
    if latest_record is not None:
        source_kind, record = latest_record
        result = record.result_json if isinstance(record.result_json, dict) else {}
        latest_status = str(record.status)
        latest_scope = str(result.get("evidence_scope", "unknown"))
        latest_provider = str(record.provider)
        latest_commit = str(record.commit_sha)
        latest_run_id = str(record.external_run_id)
        latest_url = SafeHtml(
            f"<a href='{_e(record.external_url)}'>{_e(record.external_url)}</a>"
        )
        latest_evidence = SafeHtml(
            _artifact_link(_repo_relative_artifact_path(root, record.evidence_path))
        )
        latest_recorded_by = str(record.recorded_by)
        branch_matches = record.branch_name == repo["branch"]
        commit_matches = _commit_refs_match(record.commit_sha, full_commit, repo["commit"])
        matches_current = branch_matches and commit_matches
        branch_matches_current = str(branch_matches).lower()
        commit_matches_current = str(commit_matches).lower()

    if latest_record is None:
        handoff_status = "missing"
        next_action = "Record Goal CI proof"
        target_href = "#record-goal-ci-proof"
        target_label = "Record Goal CI Proof From GitHub JSON"
        reason = "no project-scoped local CI proof record yet"
    elif not matches_current:
        handoff_status = "stale"
        next_action = "Record current Goal CI proof"
        target_href = "#record-goal-ci-proof"
        target_label = "Record Goal CI Proof From GitHub JSON"
        reason = "latest local proof does not match the current branch and commit"
    elif latest_status == "success" and latest_scope == "workflow_run":
        handoff_status = "current_success"
        next_action = "Review recorded Goal CI proof"
        target_href = "#goal-verification-evidence"
        target_label = "Goal Verification Evidence"
        reason = "current commit has operator-recorded full GitHub Actions proof"
    elif latest_status == "success" and (
        latest_scope == "job" or latest_scope.startswith("workflow_job:")
    ):
        handoff_status = "current_job_scope_only"
        next_action = "Record full-suite Goal CI proof"
        target_href = "#record-goal-ci-proof"
        target_label = "Record Goal CI Proof From GitHub JSON"
        reason = "latest proof is job-scoped early evidence only"
    else:
        handoff_status = "needs_attention"
        next_action = "Inspect recorded Goal CI proof"
        target_href = "#goal-verification-evidence"
        target_label = "Goal Verification Evidence"
        reason = "latest local proof is not a current full success record"

    branch_arg = shlex.quote(repo["branch"] if repo["branch"] != "unknown" else "<branch>")
    repo_arg = shlex.quote(repo_slug)
    gh_list_command = (
        f"gh run list --repo {repo_arg} --branch {branch_arg} --limit 5"
    )
    gh_view_command = (
        f"gh run view <run_id> --repo {repo_arg} "
        "--json status,conclusion,headSha,headBranch,databaseId,url,jobs"
    )
    proof_summary = latest_status
    if latest_scope != "none":
        proof_summary = f"{latest_status} / {latest_scope}"
    if latest_run_id != "none":
        proof_summary = f"{proof_summary} / {latest_run_id}"
    checkout_summary = (
        "matches current checkout"
        if matches_current
        else "needs current checkout proof"
    )
    full_suite_summary = (
        "workflow run proof recorded"
        if handoff_status == "current_success"
        else "full-suite proof still needs recording"
    )
    record_button_label = (
        "Review proof" if target_href == "#goal-verification-evidence" else "Record proof"
    )
    ci_cards = "".join(
        [
            "<div class='goal-ci-handoff-card' data-goal-ci-handoff-check='true'>",
            "<h3>Check GitHub</h3>",
            f"<strong>{_e(handoff_status)}</strong>",
            f"<p>{_e(reason)}</p>",
            f"<code class='goal-ci-command'>{_e(gh_list_command)}</code>",
            "<a class='goal-ci-handoff-link' href='/verification'>Open verification</a>",
            "</div>",
            "<div class='goal-ci-handoff-card goal-ci-handoff-primary' data-goal-ci-handoff-record='true' data-goal-ci-handoff-primary='true'>",
            "<h3>Record Proof</h3>",
            f"<strong>{_e(next_action)}</strong>",
            f"<p>{_e(target_label)}</p>",
            f"<a class='goal-ci-handoff-action' href='{_e(target_href)}'>{_e(record_button_label)}</a>",
            "</div>",
            "<div class='goal-ci-handoff-card' data-goal-ci-handoff-proof='true'>",
            "<h3>Current Proof</h3>",
            f"<strong>{_e(proof_summary)}</strong>",
            f"<p>{_e(checkout_summary)}</p>",
            "<a class='goal-ci-handoff-link' href='#goal-verification-evidence'>Review evidence</a>",
            "</div>",
            "<div class='goal-ci-handoff-card' data-goal-ci-handoff-full='true'>",
            "<h3>Full Suite</h3>",
            f"<strong>{_e(full_suite_summary)}</strong>",
            "<p>Fast smoke is early proof; full workflow success is the product proof.</p>",
            f"<code class='goal-ci-command'>{_e(gh_view_command)}</code>",
            "</div>",
            "<div class='goal-ci-handoff-card' data-goal-ci-handoff-finish='true'>",
            "<h3>Finish Today</h3>",
            "<strong>Save the resume point</strong>",
            "<p>When proof is recorded, finish the session with the Goal state preserved.</p>",
            "<a class='goal-ci-handoff-link' href='#goal-finish-today'>Finish Today</a>",
            "</div>",
        ]
    )
    return "".join(
        [
            "<section id='goal-ci-handoff' class='panel goal-ci-handoff' data-goal-ci-handoff='true'><h2>Goal CI Handoff</h2>",
            "<p class='muted'>Use GitHub Actions for the longer verification loop, then paste the result into this Goal's local evidence ledger.</p>",
            "<div class='goal-ci-handoff-grid' data-goal-ci-handoff-actions='true'>",
            ci_cards,
            "</div>",
            "<details class='goal-ci-handoff-evidence' data-goal-ci-handoff-evidence='true'><summary>Goal CI handoff evidence</summary>",
            _kv(
                [
                    ("goal_ci_handoff_status", handoff_status),
                    ("goal_ci_handoff_goal", goal.id),
                    ("goal_ci_handoff_project", goal.project_id),
                    ("goal_ci_handoff_branch", repo["branch"]),
                    ("goal_ci_handoff_current_commit", full_commit),
                    ("goal_ci_handoff_latest_source", source_kind),
                    ("goal_ci_handoff_latest_status", latest_status),
                    ("goal_ci_handoff_latest_scope", latest_scope),
                    ("goal_ci_handoff_latest_provider", latest_provider),
                    ("goal_ci_handoff_latest_commit", latest_commit),
                    ("goal_ci_handoff_latest_run_id", latest_run_id),
                    ("goal_ci_handoff_latest_url", latest_url),
                    ("goal_ci_handoff_latest_evidence", latest_evidence),
                    ("goal_ci_handoff_latest_recorded_by", latest_recorded_by),
                    ("goal_ci_handoff_branch_matches_current", branch_matches_current),
                    ("goal_ci_handoff_commit_matches_current", commit_matches_current),
                    ("goal_ci_handoff_matches_current_checkout", str(matches_current).lower()),
                    ("goal_ci_handoff_next_action", next_action),
                    (
                        "goal_ci_handoff_target_surface",
                        SafeHtml(f"<a href='{_e(target_href)}'>{_e(target_label)}</a>"),
                    ),
                    (
                        "goal_ci_handoff_record_surface",
                        SafeHtml(
                            "<a href='#record-goal-ci-proof'>"
                            "Record Goal CI Proof From GitHub JSON</a>"
                        ),
                    ),
                    (
                        "goal_ci_handoff_global_record_surface",
                        SafeHtml(
                            "<a href='/ci-evidence#record-ci-snapshot-json'>"
                            "/ci-evidence#record-ci-snapshot-json</a>"
                        ),
                    ),
                    ("goal_ci_handoff_reason", reason),
                    ("goal_ci_handoff_source", "project_scoped_ci_evidence_records"),
                    ("goal_ci_handoff_github_status_fetch", "none"),
                    ("goal_ci_handoff_app_github_polling", "false"),
                    ("goal_ci_handoff_write_on_get", "false"),
                    ("goal_ci_handoff_provider_calls_taken", "0"),
                    ("goal_ci_handoff_network_actions_taken", "0"),
                    ("goal_ci_handoff_external_effects_created", "false"),
                ]
            ),
            _ul(
                [
                    f"goal_ci_handoff_now: {_e(next_action)}",
                    f"goal_ci_handoff_click: <a href='{_e(target_href)}'>{_e(target_label)}</a>",
                    f"goal_ci_handoff_github_check: {_e(gh_list_command)}",
                    f"goal_ci_handoff_status_json: {_e(gh_view_command)}",
                    "goal_ci_handoff_boundary: fast smoke is early proof; full-suite success is the product proof",
                    "goal_ci_handoff_safety: read-only local GitHub Actions handoff",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _goal_workflow_gate_summary(
    root: Path,
    state: dict[str, Any],
    next_action: GoalNextAction,
) -> tuple[list[tuple[str, str]], dict[str, int], str]:
    gate_lines = _goal_remaining_work_gate_lines(root, state, next_action)
    gates: list[tuple[str, str]] = []
    for line in gate_lines:
        if not line.startswith("remaining_work_gate: "):
            continue
        parts = line.removeprefix("remaining_work_gate: ").split()
        if not parts:
            continue
        name = parts[0]
        status = "unknown"
        for part in parts[1:]:
            if part.startswith("status="):
                status = part.removeprefix("status=")
                break
        gates.append((name, status))
    counts: dict[str, int] = {}
    for _, status in gates:
        counts[status] = counts.get(status, 0) + 1
    current_gate = next(
        (name for name, status in gates if status == "pending"),
        next((name for name, status in gates if status == "waiting"), "complete"),
    )
    return gates, counts, current_gate


def _goal_command_bar(
    root: Path,
    state: dict[str, Any],
    phase: str,
    next_action: GoalNextAction,
) -> str:
    goal = state["goal"]
    open_incidents = sum(1 for row in state["incidents"] if row["status"] == "open")
    open_recommendations = sum(
        1 for row in state["recommendations"] if row["status"] == "open"
    )
    open_tasks = sum(
        1 for task in state["tasks"] if task.status not in {"completed", "cancelled"}
    )
    pending_approvals = (
        _count_status(state["worktree_approvals"], "pending_operator_approval")
        + _count_status(state["commit_approvals"], "pending_operator_approval")
        + _count_status(state["publications"], "pending_operator_approval")
    )
    waiting_items = open_incidents + open_recommendations + pending_approvals
    latest_ci = _latest_ci_evidence_record(root, project_id=goal.project_id)
    ci_status = "missing"
    ci_source = "none"
    if latest_ci is not None:
        ci_source, ci_record = latest_ci
        ci_status = str(ci_record.status)
    attention = _goal_operator_attention(phase, next_action)
    progress = _goal_progress_label(state)
    form_available = bool(_goal_next_action_form(state, next_action))
    primary_href = _goal_primary_action_href(
        state,
        next_action,
        form_available=form_available,
    )
    primary_label = _goal_action_cta_label(next_action, form_available)
    command_cards = "".join(
        [
            "<div class='goal-command-card goal-command-card-primary'>",
            "<span class='goal-command-label'>Now</span>",
            f"<strong>{_e(next_action.action)}</strong>",
            f"<a class='goal-command-action' data-goal-command-primary='true' href='{_e(primary_href)}'>{_e(primary_label)}</a>",
            "</div>",
            "<div class='goal-command-card'>",
            "<span class='goal-command-label'>Phase</span>",
            f"<strong>{_e(phase)}</strong>",
            "<a class='goal-command-link' data-goal-command-phase='true' href='#goal-current-phase'>Current phase</a>",
            "</div>",
            "<div class='goal-command-card'>",
            "<span class='goal-command-label'>Progress</span>",
            f"<strong>{_e(progress)}</strong>",
            "<a class='goal-command-link' data-goal-command-progress='true' href='#goal-progress-command-bar'>Progress</a>",
            "</div>",
            "<div class='goal-command-card'>",
            "<span class='goal-command-label'>Proof</span>",
            f"<strong>{_e(ci_status)}</strong>",
            "<a class='goal-command-link' data-goal-command-proof='true' href='#goal-ci-handoff'>CI handoff</a>",
            "</div>",
            "<div class='goal-command-card'>",
            "<span class='goal-command-label'>Resume</span>",
            "<strong>/resume</strong>",
            "<a class='goal-command-link' data-goal-command-resume='true' href='/resume'>Resume workspace</a>",
            "</div>",
        ]
    )
    return "".join(
        [
            "<section id='goal-command-bar' class='panel goal-command-bar' data-goal-command-bar='true'><h2>Goal Command Bar</h2>",
            "<p class='muted'>The shortest useful readback for this goal: state, click, waiting work, proof, and safety boundary.</p>",
            "<div class='goal-command-strip' data-goal-command-strip='true'>",
            command_cards,
            "</div>",
            "<details class='goal-command-evidence' data-goal-command-evidence='true'><summary>Goal command evidence</summary>",
            _kv(
                [
                    ("goal_command_bar_mode", "goal"),
                    ("goal_command_bar_goal", goal.id),
                    ("goal_command_bar_phase", phase),
                    ("goal_command_bar_attention", attention),
                    ("goal_command_bar_primary_action", next_action.action),
                    (
                        "goal_command_bar_primary_surface",
                        SafeHtml(
                            f"<a href='{_e(primary_href)}'>{_e(primary_label)}</a>"
                        ),
                    ),
                    ("goal_command_bar_reason", next_action.reason),
                    ("goal_command_bar_progress", progress),
                    ("goal_command_bar_open_tasks", str(open_tasks)),
                    ("goal_command_bar_waiting_items", str(waiting_items)),
                    ("goal_command_bar_pending_approvals", str(pending_approvals)),
                    ("goal_command_bar_open_incidents", str(open_incidents)),
                    ("goal_command_bar_open_recommendations", str(open_recommendations)),
                    ("goal_command_bar_resume_surface", SafeHtml("<a href='/resume'>/resume</a>")),
                    ("goal_command_bar_ci_status", ci_status),
                    ("goal_command_bar_ci_source", ci_source),
                    (
                        "goal_command_bar_ci_surface",
                        SafeHtml("<a href='/verification'>/verification</a>"),
                    ),
                    ("goal_command_bar_write_on_get", "false"),
                    ("goal_command_bar_network_actions_taken", "0"),
                    ("goal_command_bar_external_effects_created", "false"),
                ]
            ),
            _ul(
                [
                    f"goal_command_now: {_e(attention)}",
                    f"goal_command_click: <a href='{_e(primary_href)}'>{_e(primary_label)}</a>",
                    f"goal_command_progress: {_e(progress)}",
                    (
                        "goal_command_waiting: "
                        f"approvals={pending_approvals} "
                        f"incidents={open_incidents} "
                        f"recommendations={open_recommendations}"
                    ),
                    "goal_command_resume: <a href='/resume'>/resume</a>",
                    (
                        "goal_command_ci: "
                        f"status={_e(ci_status)} source={_e(ci_source)} "
                        "surface=<a href='/verification'>/verification</a>"
                    ),
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _goal_daily_loop(
    root: Path,
    state: dict[str, Any],
    phase: str,
    next_action: GoalNextAction,
) -> str:
    goal = state["goal"]
    workspace = _load_workspace_state(root)
    saved_goal = str(workspace.get("open_goal") or "").strip()
    saved_project = str(workspace.get("open_project") or "").strip()
    saved_artifact = str(workspace.get("last_viewed_artifact") or "").strip()
    latest_artifact = _goal_latest_artifact_path(root, state)
    workspace_matches_goal = saved_goal == goal.id
    workspace_matches_project = saved_project == goal.project_id
    artifact_matches_latest = (
        bool(latest_artifact)
        and saved_artifact == latest_artifact
    )
    resume_ready = (
        workspace_matches_goal
        and workspace_matches_project
        and (artifact_matches_latest or not latest_artifact)
    )
    open_incidents = sum(1 for row in state["incidents"] if row["status"] == "open")
    open_recommendation = next(
        (row for row in state["recommendations"] if row["status"] == "open"),
        None,
    )
    open_recommendations = sum(
        1 for row in state["recommendations"] if row["status"] == "open"
    )
    pending_approvals = (
        _count_status(state["worktree_approvals"], "pending_operator_approval")
        + _count_status(state["commit_approvals"], "pending_operator_approval")
        + _count_status(state["publications"], "pending_operator_approval")
    )
    waiting_items = open_incidents + open_recommendations + pending_approvals
    form_available = bool(_goal_next_action_form(state, next_action))
    if open_incidents:
        unblock_href = "/incidents"
        unblock_surface = SafeHtml("<a href='/incidents'>/incidents</a>")
        unblock_action = "Inspect incident"
        unblock_reason = "open_incidents"
    elif pending_approvals:
        unblock_href = "/approvals"
        unblock_surface = SafeHtml("<a href='/approvals'>/approvals</a>")
        unblock_action = "Review approval"
        unblock_reason = "pending_approvals"
    elif open_recommendations:
        target = _goal_recommendation_target(goal, open_recommendation)
        unblock_href = target.href
        unblock_surface = SafeHtml(
            f"<a href='{_e(target.href)}'>{_e(target.label)}</a>"
        )
        unblock_action = target.action
        unblock_reason = target.reason
    else:
        unblock_href = "#goal-remaining-work"
        unblock_surface = SafeHtml("<a href='#goal-remaining-work'>Remaining Work</a>")
        unblock_action = "Inspect remaining work"
        unblock_reason = "no_blockers"
    finish_status = "ready" if resume_ready else "needs_workspace_save"
    latest_artifact_value: str | SafeHtml = (
        SafeHtml(_artifact_link(latest_artifact)) if latest_artifact else "none"
    )
    saved_artifact_value: str | SafeHtml = (
        SafeHtml(_artifact_link(saved_artifact)) if saved_artifact else "none"
    )
    finish_resume_anchor = (
        "goal-action-dock-form" if form_available else "goal-next-action"
    )
    finish_resume_surface = f"/goals/{quote(goal.id)}#{finish_resume_anchor}"
    finish_resume_reason = (
        "current_action_form_available"
        if form_available
        else "next_action_card"
    )
    finish_form = _input_form(
        "save-workspace",
        {
            "open_project": goal.project_id,
            "open_goal": goal.id,
            "return_to": f"/goals/{goal.id}",
        },
        {
            "filters": f"goal:{goal.id}",
            "expanded_panels": "daily-loop,next-action,timeline,evidence,artifacts,notes",
            "last_viewed_artifact": latest_artifact,
            "resume_surface": finish_resume_surface,
            "updated_by": "goal-daily-loop",
        },
    )
    pause_form = _goal_pause_form(state)
    pause_available = "true" if pause_form else "false"
    continue_href = _goal_primary_action_href(
        state,
        next_action,
        form_available=form_available,
    )
    continue_label = _goal_action_cta_label(
        next_action,
        form_available,
        fallback="Open next surface",
    )
    start_status = "ready" if workspace_matches_goal else "needs_saved_goal"
    pause_label = "Pause Goal" if pause_form else "Pause unavailable"
    daily_loop_cards = "".join(
        [
            "<div class='goal-daily-loop-card goal-daily-loop-primary'>",
            "<h3>Continue</h3>",
            f"<p>{_e(next_action.action)}</p>",
            f"<a class='goal-daily-loop-action' data-goal-daily-loop-primary='true' href='{_e(continue_href)}'>{_e(continue_label)}</a>",
            "</div>",
            "<div class='goal-daily-loop-card'>",
            "<h3>Start</h3>",
            f"<p>{_e(start_status.replace('_', ' '))}</p>",
            "<a class='goal-daily-loop-link' data-goal-daily-loop-start='true' href='/resume'>Open resume</a>",
            "</div>",
            "<div class='goal-daily-loop-card'>",
            "<h3>Unblock</h3>",
            f"<p>{_e(str(waiting_items))} waiting item(s)</p>",
            f"<a class='goal-daily-loop-link' data-goal-daily-loop-unblock='true' href='{_e(unblock_href)}'>{_e(unblock_action)}</a>",
            "</div>",
            "<div class='goal-daily-loop-card'>",
            "<h3>Pause</h3>",
            f"<p>{'Available' if pause_form else 'Not available'}</p>",
            f"<a class='goal-daily-loop-link' data-goal-daily-loop-pause='true' data-open-details='true' href='#goal-pause'>{_e(pause_label)}</a>",
            "</div>",
            "<div class='goal-daily-loop-card'>",
            "<h3>Finish Today</h3>",
            f"<p>{_e(finish_status.replace('_', ' '))}</p>",
            "<a class='goal-daily-loop-link' data-goal-daily-loop-finish='true' data-open-details='true' href='#goal-finish-today'>Save resume point</a>",
            "</div>",
        ]
    )
    return "".join(
        [
            "<section id='goal-daily-loop' class='panel goal-daily-loop' data-goal-daily-loop='true'><h2>Goal Daily Loop</h2>",
            "<p class='muted'>Start, continue, unblock, and finish this goal from local browser state with a confirmed local resume save.</p>",
            "<div class='goal-daily-loop-grid' data-goal-daily-loop-actions='true'>",
            daily_loop_cards,
            "</div>",
            "<details class='goal-daily-loop-evidence' data-goal-daily-loop-evidence='true'><summary>Goal daily loop evidence</summary>",
            _kv(
                [
                    ("goal_daily_loop_status", "available"),
                    ("goal_daily_loop_goal", goal.id),
                    ("goal_daily_loop_project", goal.project_id),
                    ("goal_daily_loop_phase", phase),
                    ("goal_daily_loop_start_surface", SafeHtml("<a href='/resume'>/resume</a>")),
                    ("goal_daily_loop_next_action", next_action.action),
                    (
                        "goal_daily_loop_next_surface",
                        SafeHtml(f"<a href='{_e(continue_href)}'>{_e(continue_label)}</a>"),
                    ),
                    ("goal_daily_loop_next_form_available", str(form_available).lower()),
                    ("goal_daily_loop_waiting_items", str(waiting_items)),
                    ("goal_daily_loop_pending_approvals", str(pending_approvals)),
                    ("goal_daily_loop_open_incidents", str(open_incidents)),
                    ("goal_daily_loop_open_recommendations", str(open_recommendations)),
                    ("goal_daily_loop_unblock_action", unblock_action),
                    ("goal_daily_loop_unblock_surface", unblock_surface),
                    ("goal_daily_loop_unblock_reason", unblock_reason),
                    ("goal_daily_loop_finish_status", finish_status),
                    ("goal_daily_loop_finish_action", "save-workspace"),
                    ("goal_daily_loop_finish_form_available", "true"),
                    ("goal_daily_loop_finish_confirmation_required", "true"),
                    ("goal_daily_loop_pause_action", "pause-goal"),
                    ("goal_daily_loop_pause_form_available", pause_available),
                    ("goal_daily_loop_pause_confirmation_required", pause_available),
                    (
                        "goal_daily_loop_pause_surface",
                        SafeHtml("<a href='#goal-pause'>Pause Goal</a>")
                        if pause_form
                        else "not_available",
                    ),
                    (
                        "goal_daily_loop_finish_surface",
                        SafeHtml("<a href='#goal-finish-today'>Finish Today</a>"),
                    ),
                    (
                        "goal_daily_loop_finish_return_to",
                        SafeHtml(f"<a href='/goals/{quote(goal.id)}'>/goals/{_e(goal.id)}</a>"),
                    ),
                    (
                        "goal_daily_loop_finish_resume_surface",
                        SafeHtml(
                            f"<a href='{_e(finish_resume_surface)}'>{_e(finish_resume_surface)}</a>"
                        ),
                    ),
                    ("goal_daily_loop_finish_resume_reason", finish_resume_reason),
                    ("goal_daily_loop_saved_goal_matches_current", str(workspace_matches_goal).lower()),
                    ("goal_daily_loop_saved_project_matches_current", str(workspace_matches_project).lower()),
                    ("goal_daily_loop_saved_artifact_matches_latest", str(artifact_matches_latest).lower()),
                    ("goal_daily_loop_latest_artifact", latest_artifact_value),
                    ("goal_daily_loop_saved_artifact", saved_artifact_value),
                    ("goal_daily_loop_source", "goal_state_and_workspace"),
                    ("goal_daily_loop_write_on_get", "false"),
                    ("goal_daily_loop_network_actions_taken", "0"),
                    ("goal_daily_loop_external_effects_created", "false"),
                ]
            ),
            _ul(
                [
                    f"goal_daily_loop_step: start status={'ready' if workspace_matches_goal else 'needs_saved_goal'} surface=<a href='/resume'>/resume</a>",
                    f"goal_daily_loop_step: continue action={_e(next_action.action)} surface=<a href='{_e(continue_href)}'>{_e(continue_label)}</a>",
                    f"goal_daily_loop_step: unblock action={_e(unblock_action)} surface={unblock_surface} waiting={waiting_items}",
                    f"goal_daily_loop_step: pause available={pause_available} surface=<a href='#goal-pause'>Pause Goal</a>",
                    f"goal_daily_loop_step: finish status={_e(finish_status)} surface=<a href='#goal-finish-today'>Finish Today</a>",
                    f"goal_daily_loop_resume_surface: <a href='{_e(finish_resume_surface)}'>{_e(finish_resume_surface)}</a>",
                    "goal_daily_loop_safety: confirmed local pause or workspace save only",
                ]
            ),
            "</details>",
            (
                "<details id='goal-pause' class='goal-pause goal-pause-details' data-goal-pause-details='true'><summary>Pause Goal form</summary>"
                "<section><h3>Pause Goal</h3>"
                "<p class='muted'>Pause this Goal locally when you want to shelve it for later. It remains visible in paused lanes and can be resumed from the Goal page.</p>"
                f"{pause_form}"
                "</section></details>"
                if pause_form
                else "<details id='goal-pause' class='goal-pause goal-pause-details' data-goal-pause-details='true'><summary>Pause Goal form</summary><section><h3>Pause Goal</h3><p class='muted'>pause_goal_form_status: unavailable_for_current_goal_state</p></section></details>"
            ),
            "<details id='goal-finish-today' class='goal-finish-details' data-goal-finish-details='true'><summary>Finish Today save form</summary>",
            "<section><h3>Finish Today</h3>",
            "<p class='muted'>Save this goal, current filters, expanded panels, and latest artifact as tomorrow's resume point. This writes only `.clanker/app/workspace.json` after confirmation.</p>",
            finish_form,
            "</section></details>",
            "</section>",
        ]
    )


def _goal_return_brief(
    root: Path,
    state: dict[str, Any],
    phase: str,
    next_action: GoalNextAction,
) -> str:
    goal = state["goal"]
    workspace = _load_workspace_state(root)
    saved_project = str(workspace.get("open_project") or "").strip()
    saved_goal = str(workspace.get("open_goal") or "").strip()
    saved_artifact = str(workspace.get("last_viewed_artifact") or "").strip()
    readiness = _workspace_resume_readiness(
        root,
        open_project=saved_project,
        open_goal=saved_goal,
        filters=str(workspace.get("filters") or "").strip(),
        expanded=str(workspace.get("expanded_panels") or "").strip(),
        last_artifact=saved_artifact,
    )
    latest_item = _goal_latest_timeline_item(root, state)
    latest_message = latest_item.get("message", "none") if latest_item else "none"
    latest_surface = latest_item.get("href", "#goal-timeline") if latest_item else "#goal-timeline"
    latest_surface_value = SafeHtml(
        f"<a href='{_e(latest_surface)}'>{_e(latest_surface)}</a>"
    )
    latest_artifact = _goal_latest_artifact_path(root, state)
    latest_artifact_value: str | SafeHtml = (
        SafeHtml(_artifact_link(latest_artifact)) if latest_artifact else "none"
    )
    gates, counts, current_gate = _goal_workflow_gate_summary(root, state, next_action)
    pending_approvals = (
        _count_status(state["worktree_approvals"], "pending_operator_approval")
        + _count_status(state["commit_approvals"], "pending_operator_approval")
        + _count_status(state["publications"], "pending_operator_approval")
    )
    open_incidents = sum(1 for row in state["incidents"] if row["status"] == "open")
    open_recommendation = next(
        (row for row in state["recommendations"] if row["status"] == "open"),
        None,
    )
    open_recommendations = sum(
        1 for row in state["recommendations"] if row["status"] == "open"
    )
    if open_incidents:
        blocker_status = "open_incidents"
        blocker_href = "/incidents"
        blocker_action = "Inspect incidents"
        blocker_surface = SafeHtml("<a href='/incidents'>/incidents</a>")
    elif pending_approvals:
        blocker_status = "pending_approvals"
        blocker_href = "/approvals"
        blocker_action = "Review approvals"
        blocker_surface = SafeHtml("<a href='/approvals'>/approvals</a>")
    elif open_recommendations:
        target = _goal_recommendation_target(goal, open_recommendation)
        blocker_status = target.reason
        blocker_href = target.href
        blocker_action = target.action
        blocker_surface = SafeHtml(
            f"<a href='{_e(target.href)}'>{_e(target.label)}</a>"
        )
    else:
        blocker_status = "none"
        blocker_href = "#goal-remaining-work"
        blocker_action = "Review remaining work"
        blocker_surface = SafeHtml("<a href='#goal-remaining-work'>Goal Remaining Work</a>")
    ci_state = _ci_evidence_command_state(root)
    action_form_available = bool(_goal_next_action_form(state, next_action))
    primary_href = _goal_primary_action_href(
        state,
        next_action,
        form_available=action_form_available,
    )
    primary_label = _goal_action_cta_label(
        next_action,
        action_form_available,
        fallback="Open next surface",
    )
    workspace_matches_goal = saved_goal == goal.id
    workspace_matches_project = saved_project == goal.project_id
    done = counts.get("done", 0)
    total = len(gates)
    latest_label = "Open latest activity" if latest_item else "Open timeline"
    return_cards = "".join(
        [
            "<div class='goal-return-card goal-return-primary'>",
            "<h3>Continue</h3>",
            f"<p>{_e(next_action.action)}</p>",
            f"<a class='goal-return-action' data-goal-return-primary='true' href='{_e(primary_href)}'>{_e(primary_label)}</a>",
            "</div>",
            "<div class='goal-return-card'>",
            "<h3>Latest</h3>",
            f"<p>{_e(latest_message)}</p>",
            f"<a class='goal-return-link' data-goal-return-latest='true' href='{_e(latest_surface)}'>{_e(latest_label)}</a>",
            "</div>",
            "<div class='goal-return-card'>",
            "<h3>Blocker</h3>",
            f"<p>{_e(blocker_status.replace('_', ' '))}</p>",
            f"<a class='goal-return-link' data-goal-return-blocker='true' href='{_e(blocker_href)}'>{_e(blocker_action)}</a>",
            "</div>",
            "<div class='goal-return-card'>",
            "<h3>Finish</h3>",
            f"<p>{_e('ready' if readiness['ready'] else 'needs workspace save')}</p>",
            "<a class='goal-return-link' data-goal-return-finish='true' data-open-details='true' href='#goal-finish-today'>Save resume point</a>",
            "</div>",
            "<div class='goal-return-card'>",
            "<h3>Resume</h3>",
            f"<p>{_e(str(readiness['status']).replace('_', ' '))}</p>",
            "<a class='goal-return-link' data-goal-return-resume='true' href='/resume'>Open resume</a>",
            "</div>",
        ]
    )
    return "".join(
        [
            "<section id='goal-return-brief' class='panel goal-return-brief' data-goal-return-brief='true'><h2>Goal Return Brief</h2>",
            "<p class='muted'>A top-of-page resume brief for the current Goal: where to continue, what changed last, what proof exists, and what blocks the next move.</p>",
            "<div class='goal-return-grid' data-goal-return-actions='true'>",
            return_cards,
            "</div>",
            "<details class='goal-return-evidence' data-goal-return-evidence='true'><summary>Goal return evidence</summary>",
            _kv(
                [
                    ("goal_return_status", "ready" if readiness["ready"] else "needs_workspace_save"),
                    ("goal_return_goal", goal.id),
                    ("goal_return_project", goal.project_id),
                    ("goal_return_phase", phase),
                    ("goal_return_current_gate", current_gate),
                    ("goal_return_gate_progress", f"{done}/{total} gates done"),
                    ("goal_return_next_action", next_action.action),
                    (
                        "goal_return_next_surface",
                        SafeHtml(f"<a href='{_e(primary_href)}'>{_e(primary_label)}</a>"),
                    ),
                    ("goal_return_action_form_available", str(action_form_available).lower()),
                    ("goal_return_resume_ready", str(readiness["ready"]).lower()),
                    ("goal_return_workspace_status", str(readiness["status"])),
                    ("goal_return_saved_goal_matches_current", str(workspace_matches_goal).lower()),
                    ("goal_return_saved_project_matches_current", str(workspace_matches_project).lower()),
                    ("goal_return_saved_artifact", SafeHtml(_artifact_link(saved_artifact)) if saved_artifact else "none"),
                    ("goal_return_latest_activity_message", latest_message),
                    ("goal_return_latest_activity_surface", latest_surface_value),
                    ("goal_return_latest_artifact", latest_artifact_value),
                    ("goal_return_ci_status", ci_state["latest_status"]),
                    ("goal_return_ci_source", ci_state["latest_source"]),
                    ("goal_return_ci_current_proof", ci_state["current_proof"]),
                    ("goal_return_ci_surface", SafeHtml("<a href='/verification'>/verification</a>")),
                    ("goal_return_blocker_status", blocker_status),
                    ("goal_return_blocker_surface", blocker_surface),
                    ("goal_return_finish_surface", SafeHtml("<a href='#goal-finish-today'>Finish Today</a>")),
                    ("goal_return_resume_surface", SafeHtml("<a href='/resume'>/resume</a>")),
                    ("goal_return_source", "goal_workspace_timeline_ci_and_gate_state"),
                    ("goal_return_write_on_get", "false"),
                    ("goal_return_provider_calls_taken", "0"),
                    ("goal_return_network_actions_taken", "0"),
                    ("goal_return_external_effects_created", "false"),
                ]
            ),
            _ul(
                [
                    f"goal_return_now: {_e(next_action.action)}",
                    f"goal_return_continue: <a href='{_e(primary_href)}'>{_e(primary_label)}</a>",
                    f"goal_return_latest: {_e(latest_message)}",
                    f"goal_return_artifact: {_artifact_link(latest_artifact) if latest_artifact else 'none'}",
                    f"goal_return_unblock: {_e(blocker_status)} -> {blocker_surface}",
                    "goal_return_finish: <a href='#goal-finish-today'>Finish Today</a>",
                    "goal_return_safety: read-only return-to-work brief",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _goal_session_digest(
    root: Path,
    state: dict[str, Any],
    phase: str,
    next_action: GoalNextAction,
) -> str:
    goal = state["goal"]
    workspace = _load_workspace_state(root)
    saved_goal = str(workspace.get("open_goal") or "").strip()
    saved_project = str(workspace.get("open_project") or "").strip()
    workspace_updated = str(workspace.get("updated_at") or "").strip()
    last_action = str(workspace.get("last_action") or "").strip()
    last_action_result = str(workspace.get("last_action_result") or "").strip()
    last_action_at = str(workspace.get("last_action_updated_at") or "").strip()
    latest = _goal_latest_timeline_item(root, state)
    latest_message = latest.get("message", "No goal activity yet") if latest else "No goal activity yet"
    latest_at = latest.get("at", "") if latest else ""
    latest_at_label = _format_time(latest_at) if latest_at else "none"
    latest_href = latest.get("href", "#goal-timeline-command-bar") if latest else "#goal-timeline-command-bar"
    latest_kind = _timeline_item_family(latest) if latest else "none"
    latest_artifact = _goal_latest_artifact_path(root, state)
    latest_artifact_href = _artifact_href(root, latest_artifact) if latest_artifact else "#goal-artifact-command-bar"
    latest_artifact_label = "Open latest artifact" if latest_artifact else "Open artifacts"
    workspace_goal_matches = saved_goal == goal.id
    workspace_project_matches = saved_project == goal.project_id
    workspace_saved = bool(workspace_updated and workspace_updated != "never")
    latest_after_save = bool(
        workspace_goal_matches
        and workspace_saved
        and latest_at
        and latest_at > workspace_updated
    )
    if not workspace_saved:
        save_status = "not_saved"
        save_href = "#goal-finish-today"
        save_label = "Save this session"
    elif not workspace_goal_matches:
        save_status = "saved_other_goal"
        save_href = "#goal-finish-today"
        save_label = "Save this goal"
    elif latest_after_save:
        save_status = "changed_since_save"
        save_href = "#goal-finish-today"
        save_label = "Refresh saved point"
    else:
        save_status = "saved_current_goal"
        save_href = "/resume"
        save_label = "Open resume"
    pending_approvals = (
        _count_status(state["worktree_approvals"], "pending_operator_approval")
        + _count_status(state["commit_approvals"], "pending_operator_approval")
        + _count_status(state["publications"], "pending_operator_approval")
    )
    open_incidents = sum(1 for row in state["incidents"] if row["status"] == "open")
    open_recommendation = next(
        (row for row in state["recommendations"] if row["status"] == "open"),
        None,
    )
    open_recommendations = sum(
        1 for row in state["recommendations"] if row["status"] == "open"
    )
    waiting_items = pending_approvals + open_incidents + open_recommendations
    if open_incidents:
        waiting_status = "open_incidents"
        waiting_href = "/incidents"
        waiting_label = "Inspect incidents"
    elif pending_approvals:
        waiting_status = "pending_approvals"
        waiting_href = "/approvals"
        waiting_label = "Review approvals"
    elif open_recommendations:
        target = _goal_recommendation_target(goal, open_recommendation)
        waiting_status = target.reason
        waiting_href = target.href
        waiting_label = target.action
    else:
        waiting_status = "clear"
        waiting_href = "#goal-remaining-work-command-bar"
        waiting_label = "Check remaining work"
    gates, gate_counts, current_gate = _goal_workflow_gate_summary(root, state, next_action)
    form_available = bool(_goal_next_action_form(state, next_action))
    primary_href = _goal_primary_action_href(
        state,
        next_action,
        form_available=form_available,
    )
    primary_label = _goal_action_cta_label(
        next_action,
        form_available,
        fallback="Open next surface",
    )
    progress = _goal_progress_label(state)
    last_action_status = "none"
    if last_action:
        last_action_status = last_action
        if last_action_result:
            last_action_status = f"{last_action}: {last_action_result}"
    session_cards = "".join(
        [
            "<article class='goal-session-card goal-session-primary' data-goal-session-primary='true'>",
            "<h3>Continue</h3>",
            f"<p>{_e(next_action.action)} - {_e(progress)}</p>",
            f"<a class='goal-session-action' href='{_e(primary_href)}'>{_e(primary_label)}</a>",
            "</article>",
            "<article class='goal-session-card' data-goal-session-since-save='true'>",
            "<h3>Since Save</h3>",
            f"<p>{_e(save_status.replace('_', ' '))} - latest {_e(latest_at_label)}</p>",
            f"<a class='goal-session-link' data-open-details='true' href='{_e(save_href)}'>{_e(save_label)}</a>",
            "</article>",
            "<article class='goal-session-card' data-goal-session-artifact='true'>",
            "<h3>Latest Artifact</h3>",
            f"<p>{_e(latest_artifact or latest_message)}</p>",
            f"<a class='goal-session-link' href='{_e(latest_artifact_href)}'>{_e(latest_artifact_label)}</a>",
            "</article>",
            "<article class='goal-session-card' data-goal-session-waiting='true'>",
            "<h3>Waiting</h3>",
            f"<p>{waiting_items} item(s) - {_e(waiting_status.replace('_', ' '))}</p>",
            f"<a class='goal-session-link' href='{_e(waiting_href)}'>{_e(waiting_label)}</a>",
            "</article>",
            "<article class='goal-session-card' data-goal-session-finish='true'>",
            "<h3>Finish Today</h3>",
            f"<p>{gate_counts.get('done', 0)}/{len(gates)} gates - {_e(current_gate.replace('_', ' '))}</p>",
            "<a class='goal-session-link' data-open-details='true' href='#goal-finish-today'>Save resume point</a>",
            "</article>",
        ]
    )
    return "".join(
        [
            "<section id='goal-session-digest' class='panel goal-session-digest' data-goal-session-digest='true'><h2>Goal Session Digest</h2>",
            "<p class='muted'>A short return-to-work digest from the current Goal, saved workspace state, latest local activity, latest artifact, and waiting queues.</p>",
            "<div class='goal-session-grid' data-goal-session-actions='true'>",
            session_cards,
            "</div>",
            "<details class='goal-session-evidence' data-goal-session-evidence='true'><summary>Goal session digest evidence</summary>",
            _kv(
                [
                    ("goal_session_digest_status", save_status),
                    ("goal_session_digest_goal", goal.id),
                    ("goal_session_digest_project", goal.project_id),
                    ("goal_session_digest_phase", phase),
                    ("goal_session_digest_current_gate", current_gate),
                    ("goal_session_digest_gate_progress", f"{gate_counts.get('done', 0)}/{len(gates)} gates done"),
                    ("goal_session_digest_next_action", next_action.action),
                    (
                        "goal_session_digest_next_surface",
                        SafeHtml(f"<a href='{_e(next_action.href)}'>{_e(next_action.href)}</a>"),
                    ),
                    ("goal_session_digest_action_form_available", str(form_available).lower()),
                    ("goal_session_digest_workspace_updated_at", workspace_updated or "never"),
                    ("goal_session_digest_workspace_goal_matches_current", str(workspace_goal_matches).lower()),
                    ("goal_session_digest_workspace_project_matches_current", str(workspace_project_matches).lower()),
                    ("goal_session_digest_latest_after_save", str(latest_after_save).lower()),
                    ("goal_session_digest_latest_kind", latest_kind),
                    ("goal_session_digest_latest_at", latest_at_label),
                    ("goal_session_digest_latest_message", latest_message),
                    ("goal_session_digest_latest_surface", SafeHtml(f"<a href='{_e(latest_href)}'>{_e(latest_href)}</a>")),
                    ("goal_session_digest_latest_artifact", SafeHtml(_artifact_link(latest_artifact)) if latest_artifact else "none"),
                    ("goal_session_digest_waiting_items", str(waiting_items)),
                    ("goal_session_digest_pending_approvals", str(pending_approvals)),
                    ("goal_session_digest_open_incidents", str(open_incidents)),
                    ("goal_session_digest_open_recommendations", str(open_recommendations)),
                    ("goal_session_digest_waiting_surface", SafeHtml(f"<a href='{_e(waiting_href)}'>{_e(waiting_label)}</a>")),
                    ("goal_session_digest_last_action", last_action_status),
                    ("goal_session_digest_last_action_at", last_action_at or "none"),
                    ("goal_session_digest_card_count", "5"),
                    ("goal_session_digest_source", "goal_state_workspace_timeline_artifact_and_waiting_queues"),
                    ("goal_session_digest_write_on_get", "false"),
                    ("goal_session_digest_provider_calls_taken", "0"),
                    ("goal_session_digest_network_actions_taken", "0"),
                    ("goal_session_digest_external_effects_created", "false"),
                ]
            ),
            _ul(
                [
                    f"goal_session_digest_continue: <a href='{_e(primary_href)}'>{_e(primary_label)}</a>",
                    f"goal_session_digest_since_save: {_e(save_status)} latest_after_save={str(latest_after_save).lower()}",
                    f"goal_session_digest_latest: {_e(latest_kind)} {_e(latest_at_label)} -> <a href='{_e(latest_href)}'>{_e(latest_href)}</a>",
                    f"goal_session_digest_artifact: {_artifact_link(latest_artifact) if latest_artifact else 'none'}",
                    f"goal_session_digest_waiting: approvals={pending_approvals} incidents={open_incidents} recommendations={open_recommendations} -> <a href='{_e(waiting_href)}'>{_e(waiting_label)}</a>",
                    "goal_session_digest_finish: <a href='#goal-finish-today'>Finish Today</a>",
                    "goal_session_digest_safety: read-only local session digest; confirmed forms own writes",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _goal_activity_pulse(
    root: Path,
    state: dict[str, Any],
    phase: str,
    next_action: GoalNextAction,
) -> str:
    goal = state["goal"]
    items = _goal_timeline_items(root, state)
    recent = list(reversed(items[-3:]))
    family_order = ["artifact", "approval", "delegation", "run", "task", "operator_note", "event"]
    family_counts = {family: 0 for family in family_order}
    for item in items:
        family = _timeline_item_family(item)
        if family not in family_counts:
            family = "event"
        family_counts[family] += 1

    latest = items[-1] if items else {}
    latest_kind = _timeline_item_family(latest) if latest else "none"
    latest_at = _format_time(latest.get("at") or "") if latest else "none"
    latest_message = latest.get("message") or "No goal activity yet"
    latest_href = latest.get("href") or "#goal-timeline-command-bar"
    artifact_items = [
        item
        for item in items
        if _timeline_item_family(item) == "artifact"
        or str(item.get("href") or "").startswith("/artifacts?path=")
    ]
    latest_artifact = artifact_items[-1] if artifact_items else {}
    latest_artifact_at = _format_time(latest_artifact.get("at") or "") if latest_artifact else "none"
    latest_artifact_label = latest_artifact.get("message") or "No artifact recorded yet"
    latest_artifact_href = latest_artifact.get("href") or "#goal-artifact-command-bar"
    action_form_available = bool(_goal_next_action_form(state, next_action))
    primary_href = _goal_primary_action_href(
        state,
        next_action,
        form_available=action_form_available,
    )
    primary_label = _goal_action_cta_label(next_action, action_form_available)

    if recent:
        recent_rows = "".join(
            [
                (
                    "<li data-goal-activity-pulse-event='true' "
                    f"data-goal-activity-pulse-kind='{_e(_timeline_item_family(item))}'>"
                    f"<time>{_e(_format_time(item.get('at') or ''))}</time> "
                    f"<strong>{_e(_timeline_item_family(item))}</strong> "
                    f"<a href='{_e(item.get('href') or '#goal-timeline-command-bar')}'>"
                    f"{_e(item.get('message') or 'Goal activity')}</a></li>"
                )
                for item in recent
            ]
        )
    else:
        recent_rows = (
            "<li data-goal-activity-pulse-event='true' "
            "data-goal-activity-pulse-kind='empty'>No recent activity yet.</li>"
        )
    recent_lines = [
        (
            f"goal_activity_pulse_recent: {_e(_format_time(item.get('at') or ''))} "
            f"kind={_e(_timeline_item_family(item))} "
            f"surface=<a href='{_e(item.get('href') or '#goal-timeline-command-bar')}'>"
            f"{_e(item.get('message') or 'Goal activity')}</a>"
        )
        for item in recent
    ]
    if not recent_lines:
        recent_lines = ["goal_activity_pulse_recent: none"]

    latest_surface = SafeHtml(f"<a href='{_e(latest_href)}'>{_e(latest_message)}</a>")
    artifact_surface = SafeHtml(
        f"<a href='{_e(latest_artifact_href)}'>{_e(latest_artifact_label)}</a>"
    )
    next_surface = SafeHtml(f"<a href='{_e(primary_href)}'>{_e(primary_label)}</a>")
    mix_label = (
        f"{family_counts['artifact']} artifacts · {family_counts['run']} runs · "
        f"{family_counts['approval']} approvals"
    )
    cards = "".join(
        [
            "<article class='goal-activity-pulse-card goal-activity-pulse-primary' data-goal-activity-pulse-latest='true'>",
            "<h3>Latest</h3>",
            f"<p>{_e(latest_kind)} · {_e(latest_at)}</p>",
            f"<a class='goal-activity-pulse-action' data-goal-activity-pulse-primary='true' href='{_e(latest_href)}'>Open latest</a>",
            "</article>",
            "<article class='goal-activity-pulse-card goal-activity-pulse-recent' data-goal-activity-pulse-recent='true'>",
            "<h3>Recent Three</h3>",
            f"<ol class='goal-activity-pulse-list'>{recent_rows}</ol>",
            "</article>",
            "<article class='goal-activity-pulse-card' data-goal-activity-pulse-mix='true'>",
            "<h3>Mix</h3>",
            f"<p>{_e(mix_label)}</p>",
            "<a class='goal-activity-pulse-link' href='#goal-timeline-filter'>Filter timeline</a>",
            "</article>",
            "<article class='goal-activity-pulse-card' data-goal-activity-pulse-artifact='true'>",
            "<h3>Artifact</h3>",
            f"<p>{_e(latest_artifact_at)} · {_e(latest_artifact_label)}</p>",
            f"<a class='goal-activity-pulse-link' href='{_e(latest_artifact_href)}'>Open artifact</a>",
            "</article>",
            "<article class='goal-activity-pulse-card' data-goal-activity-pulse-next='true'>",
            "<h3>Next</h3>",
            f"<p>{_e(next_action.action)} · {_e(phase)}</p>",
            f"<a class='goal-activity-pulse-link' href='{_e(primary_href)}'>{_e(primary_label)}</a>",
            "</article>",
        ]
    )
    return "".join(
        [
            "<section id='goal-activity-pulse' class='panel goal-activity-pulse' data-goal-activity-pulse='true'><h2>Goal Activity Pulse</h2>",
            "<p class='muted'>The newest Goal movement, surfaced before the full timeline so returning operators can see what changed without hunting.</p>",
            "<div class='goal-activity-pulse-grid' data-goal-activity-pulse-actions='true'>",
            cards,
            "</div>",
            "<details class='goal-activity-pulse-evidence' data-goal-activity-pulse-evidence='true'><summary>Goal activity pulse evidence</summary>",
            _kv(
                [
                    ("goal_activity_pulse_status", "available" if items else "empty"),
                    ("goal_activity_pulse_goal", goal.id),
                    ("goal_activity_pulse_project", goal.project_id),
                    ("goal_activity_pulse_phase", phase),
                    ("goal_activity_pulse_items", str(len(items))),
                    ("goal_activity_pulse_recent_count", str(len(recent))),
                    ("goal_activity_pulse_latest_kind", latest_kind),
                    ("goal_activity_pulse_latest_at", latest_at),
                    ("goal_activity_pulse_latest_message", latest_message),
                    ("goal_activity_pulse_latest_surface", latest_surface),
                    ("goal_activity_pulse_artifact_events", str(family_counts["artifact"])),
                    ("goal_activity_pulse_approval_events", str(family_counts["approval"])),
                    ("goal_activity_pulse_delegation_events", str(family_counts["delegation"])),
                    ("goal_activity_pulse_run_events", str(family_counts["run"])),
                    ("goal_activity_pulse_task_events", str(family_counts["task"])),
                    ("goal_activity_pulse_operator_note_events", str(family_counts["operator_note"])),
                    ("goal_activity_pulse_event_events", str(family_counts["event"])),
                    ("goal_activity_pulse_latest_artifact_at", latest_artifact_at),
                    ("goal_activity_pulse_latest_artifact", artifact_surface),
                    ("goal_activity_pulse_next_action", next_action.action),
                    ("goal_activity_pulse_next_surface", next_surface),
                    ("goal_activity_pulse_action_form_available", str(action_form_available).lower()),
                    ("goal_activity_pulse_source", "goal_timeline_items_and_goal_next_action"),
                    ("goal_activity_pulse_write_on_get", "false"),
                    ("goal_activity_pulse_provider_calls_taken", "0"),
                    ("goal_activity_pulse_network_actions_taken", "0"),
                    ("goal_activity_pulse_external_effects_created", "false"),
                ]
            ),
            _ul(
                [
                    f"goal_activity_pulse_latest: {_e(latest_kind)} {_e(latest_message)}",
                    *recent_lines,
                    f"goal_activity_pulse_mix: {_e(mix_label)}",
                    f"goal_activity_pulse_artifact: {artifact_surface}",
                    f"goal_activity_pulse_next: {_e(next_action.action)} {next_surface}",
                    "goal_activity_pulse_safety: read-only local timeline pulse; confirmed forms own writes",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _goal_continuation_rail(
    root: Path,
    state: dict[str, Any],
    phase: str,
    next_action: GoalNextAction,
) -> str:
    goal = state["goal"]
    gates, _, current_gate = _goal_workflow_gate_summary(root, state, next_action)
    total = len(gates)
    current_index = next(
        (index for index, (name, _) in enumerate(gates) if name == current_gate),
        0,
    )
    upcoming = gates[current_index : current_index + 5]
    current_position = current_index + 1 if gates else 0
    action_form_available = bool(_goal_next_action_form(state, next_action))
    step_rows: list[str] = []
    step_lines: list[str] = []
    step_values: list[tuple[str, str | SafeHtml]] = []
    for offset, (name, status) in enumerate(upcoming, start=1):
        is_current = name == current_gate
        marker = "current" if is_current else status
        action, surface = _goal_continuation_gate_action(
            goal.id,
            name,
            is_current=is_current,
            next_action=next_action,
            action_form_available=action_form_available,
        )
        label = name.replace("_", " ")
        step_rows.append(
            "<li "
            f"data-continuation-gate='{_e(name)}' "
            f"data-continuation-status='{_e(status)}' "
            f"data-continuation-marker='{_e(marker)}'>"
            f"<span class='workflow-map-index'>{offset}</span> "
            f"<strong>{_e(label)}</strong> "
            f"status={_e(status)} marker={_e(marker)} "
            f"action={_e(action)} surface={surface}</li>"
        )
        step_lines.append(
            f"goal_continuation_step: {offset} gate={_e(name)} "
            f"status={_e(status)} marker={_e(marker)} "
            f"action={_e(action)} surface={surface}"
        )
        step_values.append((action, surface))
    next_gate = upcoming[1][0] if len(upcoming) > 1 else "complete"
    next_action_label = step_values[1][0] if len(step_values) > 1 else "none"
    next_surface = step_values[1][1] if len(step_values) > 1 else "none"
    now_action = step_values[0][0] if step_values else next_action.action
    now_surface = (
        step_values[0][1]
        if step_values
        else _goal_continuation_link(next_action.href, next_action.href)
    )
    then_gate = upcoming[2][0] if len(upcoming) > 2 else "complete"
    then_action = step_values[2][0] if len(step_values) > 2 else "none"
    then_surface = step_values[2][1] if len(step_values) > 2 else "none"
    primary_href = _goal_primary_action_href(
        state,
        next_action,
        form_available=action_form_available,
    )
    primary_label = _goal_action_cta_label(
        next_action,
        action_form_available,
        fallback="Open current surface",
    )
    next_href, next_label = _goal_continuation_surface_href_label(next_surface)
    then_href, then_label = _goal_continuation_surface_href_label(then_surface)
    publish_href = "#goal-workflow-map"
    publish_label = "Review boundary"
    manual_boundary = (
        "manual_publish_outside_clankeros"
        if any(name == "manual_publish" for name, _ in gates)
        else "none"
    )
    if manual_boundary == "none":
        publish_label = "Review workflow"
    continuation_cards = "".join(
        [
            "<div class='goal-continuation-card goal-continuation-primary'>",
            "<h3>Now</h3>",
            f"<p>{_e(now_action)}</p>",
            f"<a class='goal-continuation-action' data-goal-continuation-primary='true' href='{_e(primary_href)}'>{_e(primary_label)}</a>",
            "</div>",
            "<div class='goal-continuation-card'>",
            "<h3>Next Gate</h3>",
            f"<p>{_e(next_gate.replace('_', ' '))}: {_e(next_action_label)}</p>",
            f"<a class='goal-continuation-link' data-goal-continuation-next='true' href='{_e(next_href)}'>{_e(next_label)}</a>",
            "</div>",
            "<div class='goal-continuation-card'>",
            "<h3>Then</h3>",
            f"<p>{_e(then_gate.replace('_', ' '))}: {_e(then_action)}</p>",
            f"<a class='goal-continuation-link' data-goal-continuation-then='true' href='{_e(then_href)}'>{_e(then_label)}</a>",
            "</div>",
            "<div class='goal-continuation-card'>",
            "<h3>Publish Boundary</h3>",
            f"<p>{_e(manual_boundary.replace('_', ' '))}</p>",
            f"<a class='goal-continuation-link' data-goal-continuation-publish='true' href='{_e(publish_href)}'>{_e(publish_label)}</a>",
            "</div>",
            "<div class='goal-continuation-card'>",
            "<h3>Finish Today</h3>",
            f"<p>{_e(current_position)}/{_e(total)} gates</p>",
            "<a class='goal-continuation-link' data-goal-continuation-finish='true' data-open-details='true' href='#goal-finish-today'>Save resume point</a>",
            "</div>",
        ]
    )
    return "".join(
        [
            "<section id='goal-continuation-rail' class='panel goal-continuation-rail' data-goal-continuation-rail='true'><h2>Goal Continuation Rail</h2>",
            "<p class='muted'>A compact operator path from the current click through the next local gates and the final manual boundary.</p>",
            "<div class='goal-continuation-grid' data-goal-continuation-actions='true'>",
            continuation_cards,
            "</div>",
            "<details class='goal-continuation-evidence' data-goal-continuation-evidence='true'><summary>Goal continuation evidence</summary>",
            _kv(
                [
                    ("goal_continuation_status", "available" if gates else "empty"),
                    ("goal_continuation_goal", goal.id),
                    ("goal_continuation_project", goal.project_id),
                    ("goal_continuation_phase", phase),
                    ("goal_continuation_current_gate", current_gate),
                    ("goal_continuation_current_position", f"{current_position}/{total}"),
                    ("goal_continuation_step_count", str(len(upcoming))),
                    ("goal_continuation_now_action", now_action),
                    ("goal_continuation_now_surface", now_surface),
                    ("goal_continuation_next_gate", next_gate),
                    ("goal_continuation_next_action", next_action_label),
                    ("goal_continuation_next_surface", next_surface),
                    ("goal_continuation_manual_boundary", manual_boundary),
                    ("goal_continuation_source", "goal_workflow_gates_and_next_action"),
                    ("goal_continuation_write_on_get", "false"),
                    ("goal_continuation_provider_calls_taken", "0"),
                    ("goal_continuation_network_actions_taken", "0"),
                    ("goal_continuation_external_effects_created", "false"),
                ]
            ),
            "<ol class='workflow-map-rail goal-continuation-steps'>",
            "".join(step_rows),
            "</ol>",
            _ul(
                step_lines
                + [
                    "goal_continuation_safety: local browser guidance only; publication remains manual"
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _goal_continuation_gate_action(
    goal_id: str,
    gate: str,
    *,
    is_current: bool,
    next_action: GoalNextAction,
    action_form_available: bool,
) -> tuple[str, SafeHtml | str]:
    if is_current:
        if action_form_available:
            return next_action.action, _goal_continuation_link(
                "#goal-action-dock-form",
                next_action.action,
            )
        return next_action.action, _goal_continuation_link(
            next_action.href,
            next_action.href,
        )
    action, href, label = _GOAL_CONTINUATION_GATE_ACTIONS.get(
        gate,
        ("Inspect gate", f"/goals/{quote(goal_id)}", "Goal page"),
    )
    if href == "outside_clankeros":
        return action, "outside_clankeros"
    if href == "#goal-next-action" and label == "Goal action form":
        label = action
    return action, _goal_continuation_link(href, label)


def _goal_continuation_link(href: str, label: str) -> SafeHtml:
    return SafeHtml(f"<a href='{_e(href)}'>{_e(label)}</a>")


def _goal_continuation_surface_href_label(surface: str | SafeHtml) -> tuple[str, str]:
    text = str(surface)
    if "outside_clankeros" in text:
        return "#goal-workflow-map", "Review manual boundary"
    href_match = re.search(r"href='([^']+)'", text)
    label_match = re.search(r">([^<]+)</a>", text)
    href = href_match.group(1) if href_match else "#goal-workflow-map"
    label = label_match.group(1) if label_match else href
    return href, label


_GOAL_CONTINUATION_GATE_ACTIONS: dict[str, tuple[str, str, str]] = {
    "scout_delegation": ("Create scout delegation", "#goal-next-action", "Goal action form"),
    "context_pack": ("Generate context pack", "#goal-next-action", "Goal action form"),
    "implementation_handoff": ("Run delegation", "#goal-next-action", "Goal action form"),
    "coder_prep": ("Run coder prep", "#goal-next-action", "Goal action form"),
    "worktree_plan": ("Create worktree plan", "#goal-next-action", "Goal action form"),
    "worktree_approval": ("Request worktree approval", "#goal-next-action", "Goal action form"),
    "worktree_run": ("Run approved worktree", "#goal-next-action", "Goal action form"),
    "review": ("Open review", "#goal-next-action", "Goal action form"),
    "commit_request": ("Create commit request", "#goal-next-action", "Goal action form"),
    "commit_approval": ("Approve commit request", "/approvals", "/approvals"),
    "local_commit": ("Commit approved worktree", "#goal-next-action", "Goal action form"),
    "publication_request": ("Create publication request", "#goal-next-action", "Goal action form"),
    "publication_approval": ("Approve publication request", "/approvals", "/approvals"),
    "publication_handoff": ("Create publication handoff", "#goal-next-action", "Goal action form"),
    "manual_publish": ("Manual publish outside ClankerOS", "outside_clankeros", "outside_clankeros"),
}


def _goal_rows(storage: Storage, *, limit: int) -> list[sqlite3.Row]:
    return _table_rows(
        storage.db_path,
        """
        select * from goals
        order by updated_at desc, created_at desc, id desc
        limit ?
        """,
        (limit,),
    )


def _goal_bucket(row: sqlite3.Row) -> str:
    status = str(row["status"]).lower()
    if status in {"completed", "done", "closed"}:
        return "completed"
    if status in {"paused", "blocked", "waiting", "waiting_approval"}:
        return "paused"
    return "active"


def _goal_index_line(
    root: Path,
    storage: Storage,
    row: sqlite3.Row,
    *,
    extra_attrs: str = "",
) -> str:
    state = _goal_state(root, storage, str(row["id"]))
    next_action = _goal_next_action(root, state)
    phase = _goal_current_phase(state)
    progress = _goal_progress_label(state)
    remaining = _goal_remaining_work_summary(state)
    bucket = _goal_bucket(row)
    goal_id = str(row["id"])
    project_id = str(row["project_id"])
    status = str(row["status"])
    title = str(row["title"] or row["description"] or row["id"])
    open_tasks = len(
        [
            task
            for task in state.get("tasks", [])
            if task.status not in {"completed", "cancelled"}
        ]
    )
    open_incidents = len(
        [
            incident
            for incident in state.get("incidents", [])
            if incident["status"] == "open"
        ]
    )
    open_recommendations = len(
        [
            recommendation
            for recommendation in state.get("recommendations", [])
            if recommendation["status"] == "open"
        ]
    )
    pending_approvals = (
        _count_status(state.get("worktree_approvals", []), "pending_operator_approval")
        + _count_status(state.get("commit_approvals", []), "pending_operator_approval")
        + _count_status(state.get("publications", []), "pending_operator_approval")
    )
    waiting_items = pending_approvals + open_incidents + open_recommendations
    completed_tasks = len(
        [task for task in state.get("tasks", []) if task.status == "completed"]
    )
    total_tasks = len(state.get("tasks", []))
    progress_ratio = int((completed_tasks / total_tasks) * 10000) if total_tasks else 0
    updated_at = str(row["updated_at"] or row["created_at"] or "")
    form_available = (
        bool(_goal_next_action_form(state, next_action)) if state.get("goal") else False
    )
    next_href = _goal_board_action_href(goal_id, next_action.href, form_available)
    next_label = "Use action form" if form_available else "Open next"
    searchable = " ".join(
        [
            goal_id,
            title,
            str(row["description"] or ""),
            project_id,
            status,
            bucket,
            phase,
            next_action.action,
            progress,
            remaining,
        ]
    ).lower()
    return "".join(
        [
            "<article class='goal-index-row goal-index-card' data-goal-card='true' data-goal-board-row='true' ",
            f"{extra_attrs} " if extra_attrs else "",
            f"data-goal-board-bucket='{_e(bucket)}' ",
            f"data-goal-board-updated='{_e(updated_at)}' ",
            f"data-goal-board-waiting='{waiting_items}' ",
            f"data-goal-board-open-work='{open_tasks}' ",
            f"data-goal-board-progress-done='{completed_tasks}' ",
            f"data-goal-board-progress-total='{total_tasks}' ",
            f"data-goal-board-progress-ratio='{progress_ratio}' ",
            f"data-goal-board-title='{_e(title.lower())}' ",
            f"data-goal-board-phase='{_e(phase.lower())}' ",
            f"data-goal-board-search='{_e(searchable)}'>",
            "<div class='goal-index-main'>",
            f"<span class='goal-index-kicker'>{_e(bucket.title())} Goal</span>",
            f"<h3><a data-goal-card-open='true' href='/goals/{quote(goal_id)}'>{_e(title)}</a></h3>",
            f"<p class='goal-index-summary'>{_e(project_id)} / {_e(phase)} / {_e(progress)}</p>",
            "<div class='goal-index-actions'>",
            f"<a class='goal-index-action' data-goal-card-next='true' href='{_e(next_href)}'>{_e(next_label)}</a>",
            f"<a class='goal-index-link' data-goal-card-project='true' href='/projects/{quote(project_id)}'>Project</a>",
            "</div>",
            "</div>",
            "<dl class='goal-index-metrics'>",
            f"<dt>Next</dt><dd>{_e(next_action.action)}</dd>",
            f"<dt>Waiting</dt><dd>{waiting_items} item(s)</dd>",
            f"<dt>Open Work</dt><dd>{open_tasks} task(s)</dd>",
            "</dl>",
            "<p class='goal-index-legacy'>",
            f"project={_e(project_id)} status={_e(status)} "
            f"phase={_e(phase)} "
            f"next_action={_e(next_action.action)} "
            f"progress={_e(progress)} "
            f"remaining_work={_e(remaining)}",
            "</p>",
            "</article>",
        ]
    )


def _goal_remaining_work_summary(state: dict[str, Any]) -> str:
    open_tasks = len([task for task in state["tasks"] if task.status != "completed"])
    open_incidents = len([row for row in state["incidents"] if row["status"] == "open"])
    open_recommendations = len(
        [row for row in state["recommendations"] if row["status"] == "open"]
    )
    return (
        f"open_tasks:{open_tasks} "
        f"open_incidents:{open_incidents} "
        f"open_recommendations:{open_recommendations}"
    )


def _goal_state(root: Path, storage: Storage, goal_id: str) -> dict[str, Any]:
    try:
        goal = storage.get_goal(goal_id)
    except KeyError:
        return {"goal": None}
    tasks = storage.list_tasks(goal_id)
    task_ids = {task.id for task in tasks}
    delegations = storage.list_subagent_delegations(goal_id)
    delegation_ids = {delegation.id for delegation in delegations}
    worktree_approvals = [
        item
        for item in list_coder_worktree_approvals(root, limit=200)
        if item.delegation_id in delegation_ids
    ]
    worktree_runs = [
        item
        for item in list_coder_worktree_runs(root, limit=200)
        if item.delegation_id in delegation_ids
    ]
    commit_approvals = [
        item
        for item in list_coder_worktree_commit_approvals(root, limit=200)
        if item.delegation_id in delegation_ids
    ]
    publications = [
        item
        for item in list_coder_publications(root, limit=200)
        if item.delegation_id in delegation_ids
    ]
    incidents = _table_rows(
        storage.db_path,
        "select * from incidents where goal_id = ? order by created_at desc, id desc",
        (goal_id,),
    )
    recommendations = _table_rows(
        storage.db_path,
        "select * from task_recommendations where goal_id = ? order by created_at desc, id desc",
        (goal_id,),
    )
    run_rows = _table_rows(
        storage.db_path,
        "select * from runs where goal_id = ? order by started_at desc, id desc",
        (goal_id,),
    )
    event_rows = _table_rows(
        storage.db_path,
        "select * from events where goal_id = ? order by created_at asc, id asc",
        (goal_id,),
    )
    steering_reviews = storage.list_recent_steering_reviews(limit=20, goal_id=goal_id)
    prep_packets = [
        item
        for item in list_coder_prep_packets(root)
        if item.get("source", {}).get("delegation_id") in delegation_ids
    ]
    worktree_plans = [
        item
        for item in list_coder_worktree_plan_packets(root)
        if item.get("source", {}).get("delegation_id") in delegation_ids
    ]
    risks = [task.risk_level for task in tasks]
    skill_tags = sorted({tag for task in tasks for tag in task.skill_tags})
    plans = storage.list_plans(goal_id)
    latest_plan = plans[-1] if plans else None
    plan_steps = storage.list_plan_steps(latest_plan.id) if latest_plan else []
    sprint_contract = storage.get_latest_sprint_contract(goal_id)
    return {
        "root": root,
        "goal": goal,
        "plans": plans,
        "latest_plan": latest_plan,
        "plan_steps": plan_steps,
        "sprint_contract": sprint_contract,
        "tasks": tasks,
        "task_ids": task_ids,
        "delegations": delegations,
        "delegation_ids": delegation_ids,
        "runs": run_rows,
        "events": event_rows,
        "worktree_approvals": worktree_approvals,
        "worktree_runs": worktree_runs,
        "commit_approvals": commit_approvals,
        "publications": publications,
        "incidents": incidents,
        "recommendations": recommendations,
        "steering_reviews": steering_reviews,
        "prep_packets": prep_packets,
        "worktree_plans": worktree_plans,
        "risk_level": _highest_risk(risks),
        "skill_tags": skill_tags,
    }


def _goal_current_phase(state: dict[str, Any]) -> str:
    goal = state.get("goal")
    if goal is None:
        return "Missing"
    if goal.status == "completed":
        return "Completed"
    if goal.status == "paused":
        return "Paused"
    if any(str(row["status"]) == "open" for row in state["incidents"]):
        return "Blocked"
    if any(task.status in {"failed", "blocked"} for task in state["tasks"]):
        return "Blocked"
    if _count_status(state["publications"], "ready_for_operator"):
        return "Ready to publish"
    if _count_status(state["publications"], "approved"):
        return "Ready to publish"
    if _count_status(state["publications"], "pending_operator_approval"):
        return "Waiting for approval"
    if _count_status(state["commit_approvals"], "committed"):
        return "Ready to publish"
    if _count_status(state["commit_approvals"], "approved"):
        return "Ready to commit"
    if _count_status(state["commit_approvals"], "pending_operator_approval"):
        return "Waiting for approval"
    completed_runs = [run for run in state["worktree_runs"] if run.status == "completed"]
    if completed_runs:
        reviewed = [
            run
            for run in completed_runs
            if _run_review_gate_state(state["root"], run).get("commit_request_form_available")
        ]
        return "Ready to commit" if reviewed else "Needs review"
    if any(run.status == "running" for run in state["worktree_runs"]):
        return "Running"
    if _count_status(state["worktree_approvals"], "pending_operator_approval"):
        return "Waiting for approval"
    if _count_status(state["worktree_approvals"], "approved"):
        return "Ready to run"
    if state["worktree_plans"]:
        return "Waiting for approval"
    if state["prep_packets"]:
        return "Planning worktree"
    if any(_goal_delegation_has_handoff(state, delegation) for delegation in state["delegations"]):
        return "Coder prep"
    if any(delegation.status == "completed" for delegation in state["delegations"]):
        return "Implementation handoff"
    if any(delegation.status in {"pending", "running"} for delegation in state["delegations"]):
        return "Running"
    if state["tasks"]:
        return "Ready for delegation"
    return "Goal accepted"


def _goal_phase_banner(
    root: Path,
    state: dict[str, Any],
    phase: str,
    next_action: GoalNextAction,
) -> str:
    latest_item = _goal_latest_timeline_item(root, state)
    latest_activity = latest_item.get("message") if latest_item else "none"
    phase_reason = _goal_phase_reason(root, state, phase)
    attention = _goal_operator_attention(phase, next_action)
    next_surface = SafeHtml(f"<a href='{_e(next_action.href)}'>{_e(next_action.href)}</a>")
    return "".join(
        [
            "<section id='goal-current-phase' class='banner goal-phase-banner' aria-live='polite' data-goal-phase-banner='true'><h2>Current Phase</h2>",
            f"<p class='phase-callout'><strong>{_e(phase)}</strong></p>",
            "<div class='goal-phase-grid' data-goal-phase-grid='true'>",
            "<article class='goal-phase-card goal-phase-card-primary' data-goal-phase-next='true'><h3>Next</h3>",
            f"<strong>{_e(next_action.action)}</strong></article>",
            "<article class='goal-phase-card' data-goal-phase-attention='true'><h3>Attention</h3>",
            f"<strong>{_e(attention)}</strong></article>",
            "<article class='goal-phase-card' data-goal-phase-latest='true'><h3>Latest</h3>",
            f"<p>{_e(_compact_label(latest_activity or 'none', 96))}</p></article>",
            "</div>",
            "<details class='goal-phase-evidence' data-goal-phase-evidence='true'><summary>Current phase evidence</summary>",
            _kv(
                [
                    ("current_phase_banner", phase),
                    ("current_phase_is_large_banner", "true"),
                    ("phase_reason", phase_reason),
                    ("operator_attention", attention),
                    ("next_recommended_action", next_action.action),
                    ("next_action_surface", next_surface),
                    ("latest_activity", latest_activity or "none"),
                    ("operator_always_knows_what_is_happening", "true"),
                    ("phase_banner_write_on_get", "false"),
                    ("phase_banner_external_effects_created", "false"),
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _goal_latest_timeline_item(root: Path, state: dict[str, Any]) -> dict[str, str] | None:
    items = _goal_timeline_items(root, state)
    return items[-1] if items else None


def _goal_phase_reason(root: Path, state: dict[str, Any], phase: str) -> str:
    if phase == "Completed":
        return "goal is marked completed"
    if phase == "Paused":
        return "goal status is paused and can be resumed locally"
    if phase == "Blocked":
        open_incident = next((row for row in state["incidents"] if row["status"] == "open"), None)
        if open_incident is not None:
            return f"open incident requires inspection: {open_incident['summary']}"
        blocked_tasks = [
            task
            for task in state["tasks"]
            if task.status in {"failed", "blocked"}
        ]
        if blocked_tasks:
            return f"{len(blocked_tasks)} task(s) are failed or blocked"
        return "blocked state detected"
    if phase == "Ready to publish":
        if _count_status(state["publications"], "ready_for_operator"):
            return "publication handoff is ready for manual push/PR outside ClankerOS"
        if _count_status(state["publications"], "approved"):
            return "publication is approved and needs a local handoff artifact"
        if _count_status(state["commit_approvals"], "committed"):
            return "local commit exists and publication request can be created"
        return "publication gate is available"
    if phase == "Ready to commit":
        if _count_status(state["commit_approvals"], "approved"):
            return "commit approval is granted; local worktree commit can be recorded"
        reviewed = [
            run
            for run in state["worktree_runs"]
            if run.status == "completed"
            and _run_review_gate_state(root, run).get("commit_request_form_available")
        ]
        if reviewed:
            return "reviewed worktree run is ready for commit request"
        return "commit gate is available"
    if phase == "Needs review":
        return "completed worktree run needs a review artifact before commit request"
    if phase == "Waiting for approval":
        if _count_status(state["publications"], "pending_operator_approval"):
            return "publication approval is pending operator decision"
        if _count_status(state["commit_approvals"], "pending_operator_approval"):
            return "commit approval is pending operator decision"
        if _count_status(state["worktree_approvals"], "pending_operator_approval"):
            return "worktree approval is pending operator decision"
        if state["worktree_plans"]:
            return "worktree plan exists and needs an approval request"
        return "operator approval is required before continuing"
    if phase == "Running":
        if any(run.status == "running" for run in state["worktree_runs"]):
            return "approved worktree execution is running"
        if any(delegation.status in {"pending", "running"} for delegation in state["delegations"]):
            return "delegation is pending or running; browser execution remains unexposed"
        return "local workflow step is running"
    if phase == "Ready to run":
        return "worktree execution approval is granted; run the bounded local action or use the CLI fallback"
    if phase == "Planning worktree":
        return "coder prep exists and a bounded worktree plan is the next artifact"
    if phase == "Coder prep":
        return "implementation handoff is available and coder prep is next"
    if phase == "Implementation handoff":
        return "delegation result is complete and implementation handoff/coder prep is next"
    if phase == "Ready for delegation":
        return "goal has planned tasks and needs a scout delegation"
    if phase == "Goal accepted":
        return "goal exists and needs planning or task setup"
    return "phase read from local goal state"


def _goal_operator_attention(phase: str, next_action: GoalNextAction) -> str:
    if phase == "Blocked":
        return f"Resolve: {next_action.action}"
    if phase == "Running":
        return f"Watch: {next_action.action}"
    if phase == "Completed":
        return "Done: inspect evidence before closing"
    if phase in {
        "Waiting for approval",
        "Needs review",
        "Ready to commit",
        "Ready to publish",
        "Ready to run",
        "Planning worktree",
        "Coder prep",
        "Implementation handoff",
        "Ready for delegation",
        "Paused",
        "Goal accepted",
    }:
        return f"Act: {next_action.action}"
    return f"Next: {next_action.action}"


def _goal_next_action(root: Path, state: dict[str, Any]) -> GoalNextAction:
    goal = state.get("goal")
    if goal is None:
        return GoalNextAction("select_existing_goal", "/goals", "goal_not_found")
    if goal.status == "completed":
        return GoalNextAction("Review completed goal evidence", f"/goals/{quote(goal.id)}", "goal_status_completed")
    if goal.status == "paused":
        return GoalNextAction("Resume paused goal", f"/goals/{quote(goal.id)}", "goal_status_paused")
    open_incident = next((row for row in state["incidents"] if row["status"] == "open"), None)
    if open_incident is not None:
        return GoalNextAction("Inspect incident", "/incidents", str(open_incident["summary"]))
    recommendation = next((row for row in state["recommendations"] if row["status"] == "open"), None)
    if recommendation is not None:
        target = _goal_recommendation_target(goal, recommendation)
        return GoalNextAction(target.action, target.href, str(recommendation["reason"]))
    for status, action, href in [
        ("ready_for_operator", "Manual publish outside ClankerOS", None),
        ("approved", "Create publication handoff", None),
        ("pending_operator_approval", "Approve publication", "/approvals"),
    ]:
        publication = next((item for item in state["publications"] if item.status == status), None)
        if publication is not None:
            if href == "/approvals":
                href = f"/approvals?run_id={quote(publication.run_id)}"
            return GoalNextAction(
                action,
                href or f"/runs/{quote(publication.run_id)}",
                f"publication={publication.id}",
            )
    committed = next((item for item in state["commit_approvals"] if item.status == "committed"), None)
    if committed is not None:
        return GoalNextAction("Create publication request", f"/runs/{quote(committed.run_id)}", f"commit={committed.commit_sha or 'recorded'}")
    approved_commit = next((item for item in state["commit_approvals"] if item.status == "approved"), None)
    if approved_commit is not None:
        return GoalNextAction("Commit approved worktree", f"/runs/{quote(approved_commit.run_id)}", f"approval={approved_commit.id}")
    pending_commit = next((item for item in state["commit_approvals"] if item.status == "pending_operator_approval"), None)
    if pending_commit is not None:
        return GoalNextAction("Approve commit", f"/approvals?run_id={quote(pending_commit.run_id)}", f"approval={pending_commit.id}")
    completed_run = next((item for item in state["worktree_runs"] if item.status == "completed"), None)
    if completed_run is not None:
        gate = _run_review_gate_state(root, completed_run)
        if gate["commit_request_form_available"]:
            return GoalNextAction("Create commit request", f"/runs/{quote(completed_run.id)}", f"reviewed_run={completed_run.id}")
        return GoalNextAction("Open review", f"/runs/{quote(completed_run.id)}", str(gate["blocked_reason"]))
    pending_worktree = next((item for item in state["worktree_approvals"] if item.status == "pending_operator_approval"), None)
    if pending_worktree is not None:
        return GoalNextAction("Approve worktree", f"/approvals?goal_id={quote(goal.id)}", f"approval={pending_worktree.id}")
    approved_worktree = next((item for item in state["worktree_approvals"] if item.status == "approved"), None)
    if approved_worktree is not None:
        return GoalNextAction("Run approved worktree", f"/goals/{quote(goal.id)}", f"approval={approved_worktree.id}")
    if state["worktree_plans"]:
        delegation_id = str(state["worktree_plans"][0].get("source", {}).get("delegation_id") or "")
        return GoalNextAction("Request worktree approval", f"/delegations/{quote(delegation_id)}", "coder_worktree_plan_available")
    if state["prep_packets"]:
        delegation_id = str(state["prep_packets"][0].get("source", {}).get("delegation_id") or "")
        return GoalNextAction("Create worktree plan", f"/delegations/{quote(delegation_id)}", "coder_prep_available")
    completed_delegation = next((item for item in state["delegations"] if item.status == "completed"), None)
    if completed_delegation is not None:
        return GoalNextAction("Run coder prep", f"/delegations/{quote(completed_delegation.id)}", "implementation_handoff_or_result_available")
    if state["delegations"]:
        delegation = state["delegations"][0]
        metadata = load_delegation_result_metadata(delegation)
        if not _delegation_has_context_pack(root, delegation, metadata):
            return GoalNextAction("Generate context pack", f"/goals/{quote(goal.id)}", f"delegation={delegation.id} context_pack_missing")
        return GoalNextAction("Run delegation", f"/goals/{quote(goal.id)}", f"delegation={delegation.id} context_pack_ready_confirmed_browser_action")
    return GoalNextAction("Create scout delegation", f"/goals/{quote(goal.id)}", "goal_has_no_delegation_yet")


def _goal_next_action_form(state: dict[str, Any], next_action: GoalNextAction) -> str:
    if next_action.action == "Create scout delegation":
        return _goal_scout_delegation_form(state)
    if next_action.action == "Resume paused goal":
        return _goal_resume_form(state)
    if next_action.action == "Generate context pack":
        return _goal_context_pack_form(state)
    if next_action.action == "Run delegation":
        return _goal_run_delegation_handoff(state)
    if next_action.action == "Run coder prep":
        return _goal_coder_prep_form(state)
    if next_action.action == "Create worktree plan":
        return _goal_worktree_plan_form(state)
    if next_action.action == "Request worktree approval":
        return _goal_worktree_approval_form(state)
    if next_action.action == "Approve worktree":
        return _goal_approve_worktree_form(state)
    if next_action.action == "Run approved worktree":
        return _goal_run_worktree_handoff(state["root"], state)
    if next_action.action == "Create commit request":
        return _goal_commit_request_form(state["root"], state)
    if next_action.action == "Open review":
        return _goal_review_run_form(state["root"], state)
    if next_action.action == "Approve commit":
        return _goal_approve_commit_form(state)
    if next_action.action == "Commit approved worktree":
        return _goal_commit_worktree_form(state)
    if next_action.action == "Create publication request":
        return _goal_publication_request_form(state)
    if next_action.action == "Approve publication":
        return _goal_approve_publication_form(state)
    if next_action.action == "Create publication handoff":
        return _goal_publication_handoff_form(state)
    if next_action.action == "Manual publish outside ClankerOS":
        return _goal_manual_publish_panel(state["root"], state)
    return ""


def _goal_next_action_card(state: dict[str, Any], next_action: GoalNextAction) -> str:
    form = _goal_next_action_form(state, next_action)
    root = state["root"]
    goal = state["goal"]
    phase = _goal_current_phase(state)
    gates, counts, current_gate = _goal_workflow_gate_summary(root, state, next_action)
    total_gates = len(gates)
    done_gates = counts.get("done", 0)
    form_available = bool(form)
    primary_href = "#goal-next-action-form" if form_available else next_action.href
    primary_label = next_action.action
    primary_surface = SafeHtml(
        f"<a href='{_e(primary_href)}'>{_e(primary_label)}</a>"
    )
    source_surface = SafeHtml(
        f"<a href='{_e(next_action.href)}'>{_e(next_action.href)}</a>"
    )
    form_html = (
        f"<div id='goal-next-action-form' data-goal-next-action-form='true'>{form}</div>"
        if form
        else ""
    )
    details_html = (
        "<details class='goal-next-action-details' data-goal-next-action-details='true'>"
        "<summary>Action Evidence</summary>"
        + _kv(
            [
                ("next_action_focus_status", "available"),
                ("next_action_focus_goal", goal.id),
                ("next_action_focus_project", goal.project_id),
                ("next_action_focus_phase", phase),
                ("next_action_focus_current_gate", current_gate),
                (
                    "next_action_focus_gate_progress",
                    f"{done_gates}/{total_gates} gates done",
                ),
                ("next_action_focus_primary_surface", primary_surface),
                ("next_action_focus_source_surface", source_surface),
                ("next_action_focus_form_available", str(form_available).lower()),
                (
                    "next_action_focus_confirmation_required",
                    str(form_available).lower(),
                ),
                ("next_action_focus_write_on_get", "false"),
                ("next_action_focus_provider_calls_taken", "0"),
                ("next_action_focus_network_actions_taken", "0"),
                ("next_action_focus_external_effects_created", "false"),
                ("recommended_action", next_action.action),
                ("reason", next_action.reason),
                ("open_surface", SafeHtml(f"<a href='{_e(next_action.href)}'>{_e(next_action.href)}</a>")),
                ("next_action_form_available", "true" if form else "false"),
                ("external_effects_created", "false"),
            ]
        )
        + _ul(
            [
                f"next_action_focus_now: {_e(next_action.action)}",
                f"next_action_focus_click: <a href='{_e(primary_href)}'>{_e(primary_label)}</a>",
                f"next_action_focus_source: <a href='{_e(next_action.href)}'>{_e(next_action.href)}</a>",
                f"next_action_focus_gate: {_e(current_gate)}",
                "next_action_focus_safety: confirmed local action only",
            ]
        )
        + "</details>"
    )
    return (
        "<section id='goal-next-action' class='goal-next-action'><h2>Next Action</h2>"
        "<div class='goal-next-action-focus' data-goal-next-action-focus='true'>"
        "<div class='goal-next-action-focus-grid'>"
        "<div class='goal-next-action-focus-card goal-next-action-focus-primary'>"
        "<span class='goal-next-action-focus-label'>Now</span>"
        f"<h3>{_e(next_action.action)}</h3>"
        f"<p>{_e(_goal_operator_attention(phase, next_action))}</p>"
        f"<a class='goal-next-action-focus-button' data-goal-next-action-focus-primary='true' href='{_e(primary_href)}'>{_e(primary_label)}</a>"
        "</div>"
        "<div class='goal-next-action-focus-card'>"
        "<span class='goal-next-action-focus-label'>Gate</span>"
        f"<p>{_e(current_gate.replace('_', ' '))}</p>"
        f"<strong>{_e(str(done_gates))}/{_e(str(total_gates))} done</strong>"
        "</div>"
        "<div class='goal-next-action-focus-card'>"
        "<span class='goal-next-action-focus-label'>Target</span>"
        f"<p><a href='{_e(next_action.href)}'>{_e(next_action.href)}</a></p>"
        "</div>"
        "<div class='goal-next-action-focus-card'>"
        "<span class='goal-next-action-focus-label'>Boundary</span>"
        "<p>Confirmed local action only</p>"
        "<strong>No external effects</strong>"
        "</div>"
        "</div>"
        "</div>"
        + form_html
        + details_html
        + "</section>"
    )


def _goal_next_recommendation_section(
    state: dict[str, Any],
    next_action: GoalNextAction,
) -> str:
    recommendation = next(
        (row for row in state["recommendations"] if row["status"] == "open"),
        None,
    )
    if recommendation is not None:
        evidence_path = str(recommendation["evidence_path"] or "")
        recovery_commands = _goal_recovery_command_cards(recommendation)
        target = _goal_recommendation_target(state["goal"], recommendation)
        rows: list[tuple[str, str | SafeHtml]] = [
            ("next_recommendation_status", "open_task_recommendation"),
            ("next_recommendation_source", "task_recommendations"),
            ("next_recommendation_id", str(recommendation["id"])),
            ("next_recommendation_type", str(recommendation["recommendation_type"])),
            ("next_recommendation_task_id", str(recommendation["task_id"])),
            ("next_recommendation_action", target.action),
            ("next_recommendation_reason", str(recommendation["reason"])),
            (
                "next_recommendation_surface",
                SafeHtml(f"<a href='{_e(target.href)}'>{_e(target.label)}</a>"),
            ),
            (
                "next_recommendation_triage_surface",
                SafeHtml("<a href='/incidents#incident-recommendations'>Incident recommendations</a>"),
            ),
            (
                "next_recommendation_evidence",
                SafeHtml(_artifact_link(evidence_path)) if evidence_path else "missing",
            ),
            ("next_recommendation_write_on_get", "false"),
            ("next_recommendation_external_effects_created", "false"),
        ]
    else:
        recovery_commands = ""
        rows = [
            ("next_recommendation_status", "derived_from_goal_state"),
            ("next_recommendation_source", "current_phase_and_goal_records"),
            ("next_recommendation_action", next_action.action),
            ("next_recommendation_reason", next_action.reason),
            (
                "next_recommendation_surface",
                SafeHtml(f"<a href='{_e(next_action.href)}'>{_e(next_action.href)}</a>"),
            ),
            ("next_recommendation_form_surface", "Next Action card"),
            ("next_recommendation_write_on_get", "false"),
            ("next_recommendation_external_effects_created", "false"),
        ]
    return (
        "<section id='goal-next-recommendation'><h2>Next Recommendation</h2>"
        "<p class='muted'>Explains why this goal is pointing at the current action.</p>"
        + _kv(rows)
        + recovery_commands
        + "</section>"
    )


def _goal_recovery_command_cards(recommendation: Any) -> str:
    commands = _recommended_commands(recommendation)
    if not commands:
        return ""
    recommendation_id = str(_recommendation_value(recommendation, "id", "unknown"))
    task_id = str(_recommendation_value(recommendation, "task_id", "unknown"))
    evidence_path = str(_recommendation_value(recommendation, "evidence_path", "") or "")
    evidence_surface: str | SafeHtml = (
        SafeHtml(_artifact_link(evidence_path)) if evidence_path else "missing"
    )
    cards = []
    for index, command in enumerate(commands, start=1):
        cards.append(
            "<article class='goal-recovery-command-card' data-goal-recovery-command-card='true'>"
            f"<span class='goal-recovery-command-label'>Command {index}</span>"
            f"<code>{_e(command)}</code>"
            f"<button type='button' data-copy-text='{_e(command)}' "
            f"data-copy-label='goal recovery command {index}'>Copy</button>"
            "</article>"
        )
    return "".join(
        [
            "<section id='goal-recovery-commands' class='goal-recovery-commands' data-goal-recovery-commands='true'>",
            "<h3>Goal Recovery Commands</h3>",
            "<p class='muted'>Copy-only local commands from the open task recommendation. Nothing runs from this page.</p>",
            "<div class='goal-recovery-command-list' data-goal-recovery-command-list='true'>",
            "".join(cards),
            "</div>",
            "<p class='muted' data-clipboard-status='true' aria-live='polite'></p>",
            "<details class='goal-recovery-command-evidence' data-goal-recovery-commands-evidence='true'><summary>Goal recovery command evidence</summary>",
            _kv(
                [
                    ("goal_recovery_commands_status", "available"),
                    (
                        "goal_recovery_commands_source",
                        "task_recommendations.recommended_commands",
                    ),
                    ("goal_recovery_commands_recommendation_id", recommendation_id),
                    ("goal_recovery_commands_task_id", task_id),
                    ("goal_recovery_commands_count", str(len(commands))),
                    ("goal_recovery_commands_evidence", evidence_surface),
                    ("goal_recovery_commands_copy_only", "true"),
                    ("goal_recovery_commands_execute_on_get", "false"),
                    ("goal_recovery_commands_retry_on_get", "false"),
                    ("goal_recovery_commands_replan_on_get", "false"),
                    ("goal_recovery_commands_write_on_get", "false"),
                    ("goal_recovery_commands_provider_calls_taken", "0"),
                    ("goal_recovery_commands_network_actions_taken", "0"),
                    ("goal_recovery_commands_external_effects_created", "false"),
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _recommended_commands(recommendation: Any) -> list[str]:
    raw = _recommendation_value(recommendation, "recommended_commands", [])
    if isinstance(raw, (list, tuple)):
        return [str(command).strip() for command in raw if str(command).strip()]
    if not isinstance(raw, str):
        return []
    text = raw.strip()
    if not text:
        return []
    try:
        decoded = json.loads(text)
    except json.JSONDecodeError:
        decoded = None
    if isinstance(decoded, list):
        return [str(command).strip() for command in decoded if str(command).strip()]
    return [line.strip() for line in text.splitlines() if line.strip()]


def _recommendation_value(
    recommendation: Any,
    key: str,
    default: object = "",
) -> object:
    if isinstance(recommendation, sqlite3.Row):
        return recommendation[key] if key in recommendation.keys() else default
    if isinstance(recommendation, dict):
        return recommendation.get(key, default)
    return getattr(recommendation, key, default)


