def _goal_timeline_items(root: Path, state: dict[str, Any]) -> list[dict[str, str]]:
    goal = state["goal"]
    items: list[dict[str, str]] = [
        {
            "at": goal.created_at,
            "message": f"Goal created for project {goal.project_id}.",
            "href": f"/goals/{quote(goal.id)}",
        }
    ]
    for task in state["tasks"]:
        items.append(
            {
                "at": task.created_at,
                "message": f"Task created: {task.task_type}.",
                "href": f"/goals/{quote(goal.id)}",
                "kind": "task",
            }
        )
        if task.updated_at != task.created_at:
            items.append(
                {
                    "at": task.updated_at,
                    "message": f"Task {task.id} status is {task.status}.",
                    "href": f"/goals/{quote(goal.id)}",
                    "kind": "task",
                }
            )
    operator_notes = _goal_operator_notes_path(goal)
    if (root / operator_notes).exists():
        items.append(
            {
                "at": _artifact_time(root, operator_notes.as_posix()) or goal.updated_at,
                "message": "Operator note saved.",
                "href": _artifact_href(root, operator_notes),
                "kind": "operator_note",
            }
        )
    for delegation in state["delegations"]:
        delegation_href = f"/delegations/{quote(delegation.id)}"
        items.append({"at": delegation.created_at, "message": f"Scout delegated: {delegation.title}.", "href": delegation_href})
        if delegation.started_at:
            items.append({"at": delegation.started_at, "message": f"Delegation {delegation.id} started.", "href": delegation_href})
        if delegation.completed_at:
            items.append({"at": delegation.completed_at, "message": f"Execution completed: delegation {delegation.id}.", "href": delegation_href})
        metadata = load_delegation_result_metadata(delegation)
        for label, key in [
            ("Context pack built", "context_pack_md"),
            ("Implementation handoff created", "implementation_handoff_md"),
        ]:
            at = _artifact_time(root, str(metadata.get(key) or ""))
            if at:
                artifact = str(metadata.get(key) or "")
                items.append(
                    {
                        "at": at,
                        "message": f"{label} for {delegation.id}.",
                        "href": _artifact_href(root, artifact),
                    }
                )
    for packet in state["prep_packets"]:
        at = _artifact_time(root, str(packet.get("_path") or ""))
        href = _artifact_href(root, packet.get("_path")) if packet.get("_path") else f"/goals/{quote(goal.id)}"
        items.append({"at": at or goal.updated_at, "message": "Coder prep finished.", "href": href})
    for packet in state["worktree_plans"]:
        at = _artifact_time(root, str(packet.get("_path") or ""))
        href = _artifact_href(root, packet.get("_path")) if packet.get("_path") else f"/goals/{quote(goal.id)}"
        items.append({"at": at or goal.updated_at, "message": "Worktree planned.", "href": href})
    for approval in state["worktree_approvals"]:
        items.append({"at": approval.requested_at, "message": f"Approval requested: worktree execution {approval.id}.", "href": "/approvals"})
        if approval.decided_at:
            items.append(
                {
                    "at": approval.decided_at,
                    "message": _approval_decision_timeline_message(
                        "worktree execution",
                        approval.status,
                        approval.id,
                    ),
                    "href": "/approvals",
                }
            )
    for run in state["worktree_runs"]:
        run_href = f"/runs/{quote(run.id)}"
        items.append({"at": run.started_at, "message": f"Approved worktree execution started: {run.id}.", "href": run_href})
        items.append({"at": run.completed_at, "message": f"Execution {run.status}: {run.id}.", "href": run_href})
        review_state = _run_review_gate_state(root, run)
        if review_state["exists"]:
            review_path = str(review_state["review_path"])
            review_message = (
                f"Review passed for {run.id}."
                if review_state["status"] == "reviewed"
                else f"Review artifact recorded for {run.id}: status={review_state['status']}."
            )
            items.append(
                {
                    "at": _artifact_time(root, review_path) or run.completed_at,
                    "message": review_message,
                    "href": _artifact_href(root, review_path),
                }
            )
    for approval in state["commit_approvals"]:
        run_href = f"/runs/{quote(approval.run_id)}"
        items.append({"at": approval.requested_at, "message": f"Commit approval requested: {approval.id}.", "href": run_href})
        if approval.decided_at:
            items.append(
                {
                    "at": approval.decided_at,
                    "message": _gate_decision_timeline_message(
                        "Commit",
                        approval.status,
                        approval.id,
                    ),
                    "href": "/approvals",
                }
            )
        if approval.commit_artifact_path:
            at = _artifact_time(root, approval.commit_artifact_path)
            if at:
                items.append({"at": at, "message": f"Local commit artifact recorded for {approval.run_id}.", "href": _artifact_href(root, approval.commit_artifact_path)})
    for publication in state["publications"]:
        run_href = f"/runs/{quote(publication.run_id)}"
        items.append({"at": publication.requested_at, "message": f"Publication approval requested: {publication.id}.", "href": run_href})
        if publication.decided_at:
            items.append(
                {
                    "at": publication.decided_at,
                    "message": _gate_decision_timeline_message(
                        "Publication",
                        publication.status,
                        publication.id,
                    ),
                    "href": "/approvals",
                }
            )
        if publication.handoff_at:
            href = _artifact_href(root, publication.handoff_artifact_path) if publication.handoff_artifact_path else run_href
            items.append({"at": publication.handoff_at, "message": f"Publication handoff ready: {publication.id}.", "href": href})
    for row in state["events"]:
        items.append({"at": row["created_at"], "message": str(row["message"]), "href": f"/goals/{quote(goal.id)}"})
    artifact_hrefs = {
        item.get("href", "")
        for item in items
        if item.get("href", "").startswith("/artifacts?path=")
    }
    for record in _goal_artifact_records(root, state):
        href = _artifact_href(root, record["path"])
        if href in artifact_hrefs:
            continue
        artifact_hrefs.add(href)
        items.append(
            {
                "at": _artifact_time(root, record["path"]) or goal.updated_at,
                "message": f"Artifact recorded: {record['label']}.",
                "href": href,
                "kind": "artifact",
            }
        )
    return sorted(items, key=lambda item: item.get("at") or "")


def _approval_decision_timeline_message(kind: str, status: str, item_id: str) -> str:
    if status == "approved":
        return f"Approval granted: {kind} {item_id}."
    if status == "rejected":
        return f"Approval rejected: {kind} {item_id}."
    return f"Approval decision recorded: {kind} {item_id} status={status}."


def _gate_decision_timeline_message(gate: str, status: str, item_id: str) -> str:
    if status == "approved":
        return f"{gate} approved: {item_id}."
    if status == "rejected":
        return f"{gate} rejected: {item_id}."
    return f"{gate} decision recorded: {item_id} status={status}."


def _timeline_line(item: dict[str, str]) -> str:
    kind = _timeline_item_family(item)
    target = _timeline_target_label(item)
    timestamp = f"<time>{_e(_format_time(item.get('at') or ''))}</time>"
    message = _e(item.get("message") or "")
    href = item.get("href") or ""
    prefix = (
        "<span class='timeline-event' data-timeline-event='true' "
        f"data-timeline-kind='{_e(kind)}'>"
        f"{timestamp} <span class='timeline-kind'>{_e(kind)}</span> "
    )
    suffix = f" <span class='timeline-target'>{_e(target)}</span></span>"
    if href:
        return f"{prefix}<a class='timeline-link' href='{_e(href)}'>{message}</a>{suffix}"
    return f"{prefix}<span class='timeline-message'>{message}</span>{suffix}"


def _timeline_target_label(item: dict[str, str]) -> str:
    href = str(item.get("href") or "")
    if href.startswith("/artifacts?path="):
        return "artifact"
    if href.startswith("/delegations/"):
        return "delegation"
    if href.startswith("/runs/"):
        return "run"
    if href.startswith("/approvals"):
        return "approval"
    if href.startswith("/goals/"):
        return "goal"
    return "local"


def _format_time(value: str) -> str:
    if not value:
        return "unknown"
    normalized = value.replace("Z", "+00:00")
    try:
        parsed = datetime.fromisoformat(normalized)
        return parsed.strftime("%H:%M")
    except ValueError:
        return value.split("T")[-1][:5] if "T" in value else value[:16]


def _artifact_time(root: Path, path: str) -> str | None:
    if not path or path == "none":
        return None
    candidate = root / path
    if not candidate.exists():
        return None
    return datetime.fromtimestamp(candidate.stat().st_mtime, timezone.utc).isoformat(timespec="seconds")


def _goal_delegation_lines(state: dict[str, Any]) -> list[str]:
    return [
        f"<a href='/delegations/{quote(delegation.id)}'>{_e(delegation.id)}</a>: status={_e(delegation.status)} profile={_e(delegation.assigned_profile)} title={_e(delegation.title)}"
        for delegation in state["delegations"]
    ]


def _goal_delegation_section(root: Path, state: dict[str, Any]) -> str:
    lines = _goal_delegation_lines(state)
    return _goal_delegation_command_bar(root, state, lines) + _collapsible_list_section(
        "Delegations",
        lines,
        anchor_id="goal-delegations",
        details_class="goal-delegation-list",
        data_attr="goal-delegation-list",
        summary=f"Detailed delegation rows ({len(lines)})",
    )


def _goal_delegation_command_bar(
    root: Path,
    state: dict[str, Any],
    delegation_lines: list[str],
) -> str:
    goal = state["goal"]
    delegations = list(state["delegations"])
    pending_delegations = [item for item in delegations if item.status == "pending"]
    running_delegations = [item for item in delegations if item.status == "running"]
    completed_delegations = [item for item in delegations if item.status == "completed"]
    failed_or_blocked_delegations = [
        item for item in delegations if item.status in {"failed", "blocked"}
    ]
    summary_by_delegation: dict[str, dict[str, Any]] = {}
    context_pack_ready = 0
    implementation_handoff_ready = 0
    for delegation in delegations:
        metadata = load_delegation_result_metadata(delegation)
        if _delegation_has_context_pack(root, delegation, metadata):
            context_pack_ready += 1
        summary = summarize_implementation_handoff(root, delegation)
        summary_by_delegation[delegation.id] = summary
        if str(summary["status"]) == "readable":
            implementation_handoff_ready += 1

    selected_delegation = delegations[0] if delegations else None
    latest_delegation_id = "none"
    latest_delegation_status = "none"
    latest_delegation_profile = "none"
    latest_delegation_surface: str | SafeHtml = "none"
    latest_workflow_surface: str | SafeHtml = "none"
    latest_context_pack_status = "none"
    latest_handoff_status = "none"
    next_action = "Create scout delegation"
    target_href = "#goal-next-action"
    target_label = "Next Action"
    target_form_available = False
    reason = "goal has no delegation yet"
    current_action = _goal_next_action(root, state)
    current_form_available = bool(_goal_next_action_form(state, current_action))
    current_href = _goal_primary_action_href(
        state,
        current_action,
        form_available=current_form_available,
    )
    current_label = _goal_action_cta_label(current_action, current_form_available)

    if selected_delegation is not None:
        latest_delegation_id = selected_delegation.id
        latest_delegation_status = selected_delegation.status
        latest_delegation_profile = selected_delegation.assigned_profile
        latest_delegation_surface = SafeHtml(
            f"<a href='/delegations/{quote(selected_delegation.id)}'>"
            f"/delegations/{_e(selected_delegation.id)}</a>"
        )
        latest_workflow_surface = SafeHtml(
            f"<a href='/workflow?delegation_id={quote(selected_delegation.id)}'>"
            f"/workflow?delegation_id={_e(selected_delegation.id)}</a>"
        )
        metadata = load_delegation_result_metadata(selected_delegation)
        latest_context_pack_status = (
            "available"
            if _delegation_has_context_pack(root, selected_delegation, metadata)
            else "missing"
        )
        summary = summary_by_delegation[selected_delegation.id]
        latest_handoff_status = (
            "available" if str(summary["status"]) == "readable" else str(summary["status"])
        )
        delegation_prep = [
            item
            for item in state["prep_packets"]
            if item.get("source", {}).get("delegation_id") == selected_delegation.id
        ]
        delegation_plans = [
            item
            for item in state["worktree_plans"]
            if item.get("source", {}).get("delegation_id") == selected_delegation.id
        ]
        worktree_approvals = list_coder_worktree_approvals(
            root,
            delegation_id=selected_delegation.id,
            limit=50,
        )
        worktree_runs = list_coder_worktree_runs(
            root,
            delegation_id=selected_delegation.id,
            limit=50,
        )
        commit_approvals = list_coder_worktree_commit_approvals(
            root,
            delegation_id=selected_delegation.id,
            limit=50,
        )
        publications = list_coder_publications(
            root,
            delegation_id=selected_delegation.id,
            limit=50,
        )
        token = _delegation_next_action(
            root,
            summary=summary,
            prep_count=len(delegation_prep),
            plan_count=len(delegation_plans),
            worktree_approvals=worktree_approvals,
            worktree_runs=worktree_runs,
            commit_approvals=commit_approvals,
            publications=publications,
        )
        selected_run = worktree_runs[0] if worktree_runs else None
        selected_commit_run_id = next(
            (item.run_id for item in commit_approvals if getattr(item, "run_id", "")),
            "",
        )
        selected_publication_run_id = next(
            (item.run_id for item in publications if getattr(item, "run_id", "")),
            "",
        )
        run_id = (
            selected_run.id
            if selected_run is not None
            else selected_commit_run_id or selected_publication_run_id
        )
        if token == "generate_context_pack":
            next_action = "Generate context pack"
            target_href = "#goal-next-action"
            reason = "selected delegation is missing a context pack"
        elif token == "run_delegation_or_review_implementation_handoff":
            next_action = "Run delegation"
            target_href = "#goal-next-action"
            reason = "implementation handoff is missing or unreadable"
        elif token == "prepare_coder_from_handoff":
            next_action = "Run coder prep"
            target_href = f"/delegations/{quote(selected_delegation.id)}"
            target_label = f"/delegations/{selected_delegation.id}"
            reason = "implementation handoff is ready for bounded coder prep"
        elif token == "prepare_coder_worktree_plan":
            next_action = "Create worktree plan"
            target_href = f"/delegations/{quote(selected_delegation.id)}"
            target_label = f"/delegations/{selected_delegation.id}"
            reason = "coder prep packet is ready for worktree planning"
        elif token == "decide_pending_worktree_approval":
            next_action = "Approve worktree"
            target_href = "/approvals"
            target_label = "/approvals"
            reason = "worktree approval is waiting for an operator decision"
        elif token == "run_approved_worktree_from_cli":
            next_action = "Run approved worktree"
            target_href = "#goal-next-action"
            reason = "worktree execution is approved and needs confirmed local execution"
        elif token == "request_commit_for_reviewed_run":
            next_action = "Create commit request"
            target_href = f"/runs/{quote(run_id)}" if run_id else f"/delegations/{quote(selected_delegation.id)}"
            target_label = f"/runs/{run_id}" if run_id else f"/delegations/{selected_delegation.id}"
            reason = "reviewed coder run is ready for a local commit request"
        elif token == "approve_or_reject_commit_request":
            next_action = "Approve commit"
            target_href = "/approvals"
            target_label = "/approvals"
            reason = "commit approval is waiting for an operator decision"
        elif token == "commit_approved_worktree":
            next_action = "Commit approved worktree"
            target_href = f"/runs/{quote(run_id)}" if run_id else f"/delegations/{quote(selected_delegation.id)}"
            target_label = f"/runs/{run_id}" if run_id else f"/delegations/{selected_delegation.id}"
            reason = "commit approval is granted for the selected delegation"
        elif token == "request_publication_handoff":
            next_action = "Create publication request"
            target_href = f"/runs/{quote(run_id)}" if run_id else f"/delegations/{quote(selected_delegation.id)}"
            target_label = f"/runs/{run_id}" if run_id else f"/delegations/{selected_delegation.id}"
            reason = "local commit is recorded and publication can be requested"
        elif token == "approve_or_reject_publication_request":
            next_action = "Approve publication"
            target_href = "/approvals"
            target_label = "/approvals"
            reason = "publication approval is waiting for an operator decision"
        elif token == "prepare_publication_handoff":
            next_action = "Create publication handoff"
            target_href = f"/runs/{quote(run_id)}" if run_id else f"/delegations/{quote(selected_delegation.id)}"
            target_label = f"/runs/{run_id}" if run_id else f"/delegations/{selected_delegation.id}"
            reason = "publication approval is granted for the selected delegation"
        elif token == "manual_operator_push_pr_outside_clankeros":
            next_action = "Use publication handoff"
            target_href = f"/runs/{quote(run_id)}" if run_id else f"/delegations/{quote(selected_delegation.id)}"
            target_label = f"/runs/{run_id}" if run_id else f"/delegations/{selected_delegation.id}"
            reason = "publication handoff is ready for manual push or PR outside ClankerOS"
        else:
            next_action = "Review delegation workflow"
            target_href = f"/workflow?delegation_id={quote(selected_delegation.id)}"
            target_label = f"/workflow?delegation_id={selected_delegation.id}"
            reason = "selected delegation has workflow state to inspect"
    delegation_current_actions = {
        "Create scout delegation",
        "Generate context pack",
        "Run delegation",
        "Run coder prep",
        "Create worktree plan",
        "Request worktree approval",
        "Run approved worktree",
        "Open review",
        "Create commit request",
        "Approve commit",
        "Commit approved worktree",
        "Create publication request",
        "Approve publication",
        "Create publication handoff",
    }
    if current_form_available and current_action.action in delegation_current_actions:
        if next_action != current_action.action:
            reason = f"current_goal_action={current_action.reason}"
        next_action = current_label
        target_href = current_href
        target_label = current_label
        target_form_available = current_form_available

    if next_action == "Create commit request":
        status = "ready_for_commit_request"
    elif not delegations:
        status = "empty"
    elif failed_or_blocked_delegations:
        status = "attention_required"
    elif running_delegations:
        status = "running"
    elif implementation_handoff_ready:
        status = "handoff_available"
    elif context_pack_ready:
        status = "context_pack_ready"
    else:
        status = "delegations_available"

    target = SafeHtml(f"<a href='{_e(target_href)}'>{_e(target_label)}</a>")
    latest_delegation_href = (
        f"/delegations/{quote(latest_delegation_id)}"
        if latest_delegation_id != "none"
        else (current_href if current_action.action == next_action else "#goal-next-action")
    )
    workflow_href = (
        f"/workflow?delegation_id={quote(latest_delegation_id)}"
        if latest_delegation_id != "none"
        else "/workflow"
    )
    latest_delegation_label = (
        "Open delegation"
        if latest_delegation_id != "none"
        else (current_label if current_action.action == next_action else "Next Action")
    )
    delegation_cards = "".join(
        [
            "<div class='goal-delegation-card goal-delegation-primary' data-goal-delegation-now='true'>",
            "<h3>Now</h3>",
            f"<strong>{_e(next_action)}</strong>",
            f"<p>{_e(reason)}</p>",
            f"<a class='goal-delegation-action' data-goal-delegation-primary='true' href='{_e(target_href)}'>{_e(next_action)}</a>",
            "</div>",
            "<div class='goal-delegation-card' data-goal-delegation-latest='true'>",
            "<h3>Latest</h3>",
            f"<strong>{_e(latest_delegation_id)}</strong>",
            f"<p>{_e(latest_delegation_status)} via {_e(latest_delegation_profile)}.</p>",
            f"<a class='goal-delegation-link' href='{_e(latest_delegation_href)}'>{_e(latest_delegation_label)}</a>",
            "</div>",
            "<div class='goal-delegation-card' data-goal-delegation-workflow='true'>",
            "<h3>Workflow</h3>",
            f"<strong>{len(delegations)} delegation(s)</strong>",
            f"<p>{len(running_delegations)} running; {len(failed_or_blocked_delegations)} blocked/failed.</p>",
            f"<a class='goal-delegation-link' href='{_e(workflow_href)}'>Workflow</a>",
            "</div>",
            "<div class='goal-delegation-card' data-goal-delegation-handoff='true'>",
            "<h3>Handoff</h3>",
            f"<strong>{context_pack_ready} context / {implementation_handoff_ready} handoff</strong>",
            f"<p>{len(state['prep_packets'])} prep packet(s); {len(state['worktree_plans'])} worktree plan(s).</p>",
            "<a class='goal-delegation-link' href='#goal-artifact-command-bar'>Artifacts</a>",
            "</div>",
            "<div class='goal-delegation-card' data-goal-delegation-safety='true'>",
            "<h3>Safety</h3>",
            "<strong>read-only posture</strong>",
            "<p>No delegation execution, providers, network actions, or writes on GET.</p>",
            "<a class='goal-delegation-link' href='#goal-delegations'>Detailed rows</a>",
            "</div>",
        ]
    )
    return "".join(
        [
            "<section id='goal-delegation-command-bar' class='panel goal-delegation-command-bar' data-goal-delegation-command-bar='true'><h3>Goal Delegation Command Bar</h3>",
            "<p class='muted'>Goal-scoped delegation posture before the detailed scout, context-pack, and handoff rows.</p>",
            "<div class='goal-delegation-grid' data-goal-delegation-actions='true'>",
            delegation_cards,
            "</div>",
            "<details class='goal-delegation-command-evidence' data-goal-delegation-evidence='true'><summary>Goal delegation command evidence</summary>",
            _kv(
                [
                    ("goal_delegation_command_goal", goal.id),
                    ("goal_delegation_command_project", goal.project_id),
                    ("goal_delegation_command_status", status),
                    ("goal_delegation_command_items", str(len(delegation_lines))),
                    ("goal_delegation_command_total_delegations", str(len(delegations))),
                    ("goal_delegation_command_pending_delegations", str(len(pending_delegations))),
                    ("goal_delegation_command_running_delegations", str(len(running_delegations))),
                    ("goal_delegation_command_completed_delegations", str(len(completed_delegations))),
                    (
                        "goal_delegation_command_failed_or_blocked_delegations",
                        str(len(failed_or_blocked_delegations)),
                    ),
                    ("goal_delegation_command_context_packs_ready", str(context_pack_ready)),
                    (
                        "goal_delegation_command_implementation_handoffs_ready",
                        str(implementation_handoff_ready),
                    ),
                    ("goal_delegation_command_coder_prep_packets", str(len(state["prep_packets"]))),
                    ("goal_delegation_command_worktree_plans", str(len(state["worktree_plans"]))),
                    ("goal_delegation_command_latest_delegation", latest_delegation_id),
                    ("goal_delegation_command_latest_status", latest_delegation_status),
                    ("goal_delegation_command_latest_profile", latest_delegation_profile),
                    ("goal_delegation_command_latest_surface", latest_delegation_surface),
                    ("goal_delegation_command_workflow_surface", latest_workflow_surface),
                    ("goal_delegation_command_latest_context_pack_status", latest_context_pack_status),
                    ("goal_delegation_command_latest_handoff_status", latest_handoff_status),
                    ("goal_delegation_command_next_action", next_action),
                    ("goal_delegation_command_target_surface", target),
                    (
                        "goal_delegation_command_action_form_available",
                        str(target_form_available).lower(),
                    ),
                    ("goal_delegation_command_reason", reason),
                    (
                        "goal_delegation_command_source",
                        "goal_delegations_context_and_handoff_state",
                    ),
                    ("goal_delegation_command_write_on_get", "false"),
                    ("goal_delegation_command_provider_calls_taken", "0"),
                    ("goal_delegation_command_network_actions_taken", "0"),
                    ("goal_delegation_command_external_effects_created", "false"),
                ]
            ),
            _ul(
                [
                    f"goal_delegation_now: {_e(next_action)}",
                    f"goal_delegation_click: {target}",
                    (
                        "goal_delegation_latest: "
                        f"{_e(latest_delegation_id)} status={_e(latest_delegation_status)} "
                        f"context={_e(latest_context_pack_status)} handoff={_e(latest_handoff_status)}"
                    ),
                    "goal_delegation_safety: read-only local delegation posture",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _goal_run_lines(root: Path, state: dict[str, Any]) -> list[str]:
    lines = [
        f"<a href='/runs/{quote(str(row['id']))}'>{_e(row['id'])}</a>: status={_e(row['status'])} project={_e(row['project_id'])}"
        for row in state["runs"]
    ]
    lines.extend(_coder_run_line(root, run) for run in state["worktree_runs"])
    return lines


def _goal_run_section(root: Path, state: dict[str, Any]) -> str:
    lines = _goal_run_lines(root, state)
    return _goal_run_command_bar(root, state, lines) + _collapsible_list_section(
        "Runs",
        lines,
        anchor_id="goal-runs",
        details_class="goal-run-list",
        data_attr="goal-run-list",
        summary=f"Detailed run rows ({len(lines)})",
    )


def _goal_run_command_bar(
    root: Path,
    state: dict[str, Any],
    run_lines: list[str],
) -> str:
    goal = state["goal"]
    task_runs = list(state["runs"])
    worktree_runs = list(state["worktree_runs"])
    completed_worktree_runs = [
        run for run in worktree_runs if run.status == "completed"
    ]
    running_worktree_runs = [
        run for run in worktree_runs if run.status == "running"
    ]
    failed_worktree_runs = [
        run for run in worktree_runs if run.status == "failed"
    ]
    review_states = [
        _run_review_gate_state(root, run)
        for run in worktree_runs
    ]
    reviewed_runs = [
        run
        for run, review in zip(worktree_runs, review_states, strict=False)
        if review["commit_request_form_available"]
    ]
    review_blocked_runs = [
        run
        for run, review in zip(worktree_runs, review_states, strict=False)
        if run.status == "completed" and not review["commit_request_form_available"]
    ]
    changed_files_count = sum(len(run.changed_files) for run in worktree_runs)
    outside_allowed_files = sum(len(run.outside_allowed_files) for run in worktree_runs)
    verification_failed_runs = [
        run
        for run in worktree_runs
        if run.verification_exit_code is not None and run.verification_exit_code != 0
    ]
    selected_run = worktree_runs[0] if worktree_runs else None
    selected_task_run = task_runs[0] if task_runs and selected_run is None else None

    latest_run_id = "none"
    latest_run_status = "none"
    latest_run_surface: str | SafeHtml = "none"
    latest_review_status = "none"
    latest_changed_files_count = "0"
    latest_diff_summary = "none"
    latest_diff_surface: str | SafeHtml = "none"
    next_action = "Create run through the next Goal action"
    target_href = "#goal-next-action"
    target_label = "Next Action"
    target_form_available = False
    reason = "no local run records are attached to this goal"
    current_action = _goal_next_action(root, state)
    current_form_available = bool(_goal_next_action_form(state, current_action))
    current_href = _goal_primary_action_href(
        state,
        current_action,
        form_available=current_form_available,
    )
    current_label = _goal_action_cta_label(current_action, current_form_available)

    if selected_run is not None:
        latest_run_id = selected_run.id
        latest_run_status = selected_run.status
        latest_run_surface = SafeHtml(
            f"<a href='/runs/{quote(selected_run.id)}'>/runs/{_e(selected_run.id)}</a>"
        )
        review_gate = _run_review_gate_state(root, selected_run)
        latest_review_status = str(review_gate["status"])
        change_summary = coder_worktree_change_summary(root, selected_run)
        latest_changed_files_count = change_summary["changed_files_count"]
        latest_diff_summary = change_summary["diff_summary"]
        latest_diff_surface = _artifact_link(
            str(Path(selected_run.evidence_path) / "diff.patch")
        )
        commit_approvals = [
            item
            for item in state["commit_approvals"]
            if item.run_id == selected_run.id
        ]
        publications = [
            item
            for item in state["publications"]
            if item.run_id == selected_run.id
        ]
        next_action, raw_target_href, target_label, reason = _run_command_next_action(
            selected_run,
            review_gate=review_gate,
            commit_approvals=commit_approvals,
            publications=publications,
        )
        target_href = (
            f"/runs/{quote(selected_run.id)}{raw_target_href}"
            if raw_target_href.startswith("#")
            else raw_target_href
        )
    elif selected_task_run is not None:
        latest_run_id = str(selected_task_run["id"])
        latest_run_status = str(selected_task_run["status"])
        latest_run_surface = SafeHtml(
            f"<a href='/runs/{quote(latest_run_id)}'>/runs/{_e(latest_run_id)}</a>"
        )
        next_action = "Review task run evidence"
        target_href = f"/runs/{quote(latest_run_id)}"
        target_label = f"/runs/{latest_run_id}"
        reason = "task run evidence is available for this goal"
    run_current_actions = {
        "Run delegation",
        "Run approved worktree",
        "Open review",
        "Create commit request",
        "Approve commit",
        "Commit approved worktree",
        "Create publication request",
        "Approve publication",
        "Create publication handoff",
    }
    if current_form_available and current_action.action in run_current_actions:
        if next_action != current_action.action:
            reason = f"current_goal_action={current_action.reason}"
        next_action = current_label
        target_href = current_href
        target_label = current_label
        target_form_available = current_form_available

    if selected_run is not None and next_action == "Create commit request":
        status = "ready_for_commit_request"
    elif (
        selected_run is not None
        and selected_run.status == "completed"
        and latest_review_status != "reviewed"
    ):
        status = "needs_review"
    elif selected_run is not None:
        status = "worktree_runs_available"
    elif task_runs:
        status = "task_runs_available"
    elif run_lines:
        status = "history_available"
    else:
        status = "empty"

    target = SafeHtml(f"<a href='{_e(target_href)}'>{_e(target_label)}</a>")
    latest_run_href = (
        f"/runs/{quote(latest_run_id)}"
        if latest_run_id != "none"
        else "#goal-next-action"
    )
    latest_run_label = "Open run" if latest_run_id != "none" else "Next Action"
    latest_diff_href = (
        _artifact_href(root, str(Path(selected_run.evidence_path) / "diff.patch"))
        if selected_run is not None
        else "#goal-evidence-command-bar"
    )
    run_cards = "".join(
        [
            "<div class='goal-run-card goal-run-primary' data-goal-run-now='true'>",
            "<h3>Now</h3>",
            f"<strong>{_e(next_action)}</strong>",
            f"<p>{_e(reason)}</p>",
            f"<a class='goal-run-action' data-goal-run-primary='true' href='{_e(target_href)}'>{_e(next_action)}</a>",
            "</div>",
            "<div class='goal-run-card' data-goal-run-latest='true'>",
            "<h3>Latest Run</h3>",
            f"<strong>{_e(latest_run_id)}</strong>",
            f"<p>{_e(latest_run_status)}; review {_e(latest_review_status)}.</p>",
            f"<a class='goal-run-link' href='{_e(latest_run_href)}'>{_e(latest_run_label)}</a>",
            "</div>",
            "<div class='goal-run-card' data-goal-run-review='true'>",
            "<h3>Review</h3>",
            f"<strong>{len(reviewed_runs)} ready / {len(review_blocked_runs)} blocked</strong>",
            f"<p>{len(verification_failed_runs)} verification failure(s).</p>",
            f"<a class='goal-run-link' href='{_e(target_href)}'>Review target</a>",
            "</div>",
            "<div class='goal-run-card' data-goal-run-changes='true'>",
            "<h3>Changes</h3>",
            f"<strong>{changed_files_count} changed</strong>",
            f"<p>{outside_allowed_files} outside allowed files.</p>",
            f"<a class='goal-run-link' href='{_e(latest_diff_href)}'>Diff</a>",
            "</div>",
            "<div class='goal-run-card' data-goal-run-safety='true'>",
            "<h3>Safety</h3>",
            "<strong>read-only posture</strong>",
            "<p>No run execution, providers, network actions, or writes on GET.</p>",
            "<a class='goal-run-link' href='#goal-runs'>Detailed rows</a>",
            "</div>",
        ]
    )
    return "".join(
        [
            "<section id='goal-run-command-bar' class='panel goal-run-command-bar' data-goal-run-command-bar='true'><h3>Goal Run Command Bar</h3>",
            "<p class='muted'>Goal-scoped run posture before the detailed task and worktree run list.</p>",
            "<div class='goal-run-grid' data-goal-run-actions='true'>",
            run_cards,
            "</div>",
            "<details class='goal-run-command-evidence' data-goal-run-evidence='true'><summary>Goal run command evidence</summary>",
            _kv(
                [
                    ("goal_run_command_goal", goal.id),
                    ("goal_run_command_project", goal.project_id),
                    ("goal_run_command_status", status),
                    ("goal_run_command_items", str(len(run_lines))),
                    ("goal_run_command_task_runs", str(len(task_runs))),
                    ("goal_run_command_worktree_runs", str(len(worktree_runs))),
                    (
                        "goal_run_command_completed_worktree_runs",
                        str(len(completed_worktree_runs)),
                    ),
                    (
                        "goal_run_command_running_worktree_runs",
                        str(len(running_worktree_runs)),
                    ),
                    (
                        "goal_run_command_failed_worktree_runs",
                        str(len(failed_worktree_runs)),
                    ),
                    ("goal_run_command_reviewed_runs", str(len(reviewed_runs))),
                    (
                        "goal_run_command_review_blocked_runs",
                        str(len(review_blocked_runs)),
                    ),
                    (
                        "goal_run_command_verification_failed_runs",
                        str(len(verification_failed_runs)),
                    ),
                    ("goal_run_command_changed_files_count", str(changed_files_count)),
                    ("goal_run_command_outside_allowed_files", str(outside_allowed_files)),
                    ("goal_run_command_latest_run", latest_run_id),
                    ("goal_run_command_latest_status", latest_run_status),
                    ("goal_run_command_latest_surface", latest_run_surface),
                    ("goal_run_command_latest_review_status", latest_review_status),
                    (
                        "goal_run_command_latest_changed_files_count",
                        latest_changed_files_count,
                    ),
                    ("goal_run_command_latest_diff_summary", latest_diff_summary),
                    ("goal_run_command_latest_diff", SafeHtml(str(latest_diff_surface))),
                    ("goal_run_command_next_action", next_action),
                    ("goal_run_command_target_surface", target),
                    (
                        "goal_run_command_action_form_available",
                        str(target_form_available).lower(),
                    ),
                    ("goal_run_command_reason", reason),
                    ("goal_run_command_source", "goal_runs_and_coder_worktree_runs"),
                    ("goal_run_command_write_on_get", "false"),
                    ("goal_run_command_provider_calls_taken", "0"),
                    ("goal_run_command_network_actions_taken", "0"),
                    ("goal_run_command_external_effects_created", "false"),
                ]
            ),
            _ul(
                [
                    f"goal_run_now: {_e(next_action)}",
                    f"goal_run_click: <a href='{_e(target_href)}'>{_e(target_label)}</a>",
                    f"goal_run_latest: {_e(latest_run_id)} status={_e(latest_run_status)} review={_e(latest_review_status)}",
                    "goal_run_safety: read-only local run posture",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _goal_approval_lines(root: Path, state: dict[str, Any]) -> list[str]:
    return (
        [_approval_line(item) for item in state["worktree_approvals"]]
        + [_commit_line(item) for item in state["commit_approvals"]]
        + [_publication_line(root, item) for item in state["publications"]]
    )


def _goal_approval_section(root: Path, state: dict[str, Any]) -> str:
    lines = _goal_approval_lines(root, state)
    return _goal_approval_command_bar(state, lines) + _collapsible_list_section(
        "Approvals",
        lines,
        anchor_id="goal-approvals",
        details_class="goal-approval-list",
        data_attr="goal-approval-list",
        summary=f"Detailed approval rows ({len(lines)})",
    )


def _goal_approval_command_bar(
    state: dict[str, Any],
    approval_lines: list[str],
) -> str:
    goal = state["goal"]
    pending_worktree = _count_status(
        state["worktree_approvals"],
        "pending_operator_approval",
    )
    pending_commit = _count_status(
        state["commit_approvals"],
        "pending_operator_approval",
    )
    pending_publication = _count_status(
        state["publications"],
        "pending_operator_approval",
    )
    approved_worktree = _count_status(state["worktree_approvals"], "approved")
    approved_commit = _count_status(state["commit_approvals"], "approved")
    approved_publication = _count_status(state["publications"], "approved")
    committed_commit = _count_status(state["commit_approvals"], "committed")
    publication_ready = _count_status(state["publications"], "ready_for_operator")
    pending_total = pending_worktree + pending_commit + pending_publication
    approved_total = approved_worktree + approved_commit + approved_publication
    downstream_total = committed_commit + publication_ready

    next_action = "Continue Goal workflow"
    target_href = "#goal-next-action"
    target_label = "Next Action"
    target_form_available = False
    reason = "approval gates are not the active local blocker"
    current_action = _goal_next_action(state["root"], state)
    current_form_available = bool(_goal_next_action_form(state, current_action))
    current_href = _goal_primary_action_href(
        state,
        current_action,
        form_available=current_form_available,
    )
    current_label = _goal_action_cta_label(current_action, current_form_available)
    if pending_publication:
        next_action = "Approve publication"
        target_href = "/approvals"
        target_label = "/approvals"
        reason = "publication gate is waiting for an operator decision"
    elif pending_commit:
        next_action = "Approve commit"
        target_href = "/approvals"
        target_label = "/approvals"
        reason = "commit gate is waiting for an operator decision"
    elif pending_worktree:
        next_action = "Approve worktree"
        target_href = "/approvals"
        target_label = "/approvals"
        reason = "worktree gate is waiting for an operator decision"
    elif publication_ready:
        next_action = "Use publication handoff"
        target_href = "#goal-completion-readiness"
        target_label = "Completion Readiness"
        reason = "publication handoff is ready for manual push/PR outside ClankerOS"
    elif approved_publication:
        publication = next(
            (item for item in state["publications"] if item.status == "approved"),
            None,
        )
        next_action = "Create publication handoff"
        target_href = (
            f"/runs/{quote(publication.run_id)}"
            if publication is not None
            else "#goal-next-action"
        )
        target_label = target_href if publication is not None else "Next Action"
        reason = "publication approval is granted and needs a local handoff artifact"
    elif committed_commit:
        commit = next(
            (item for item in state["commit_approvals"] if item.status == "committed"),
            None,
        )
        next_action = "Create publication request"
        target_href = (
            f"/runs/{quote(commit.run_id)}"
            if commit is not None
            else "#goal-next-action"
        )
        target_label = target_href if commit is not None else "Next Action"
        reason = "local worktree commit is recorded and publication can be requested"
    elif approved_commit:
        commit = next(
            (item for item in state["commit_approvals"] if item.status == "approved"),
            None,
        )
        next_action = "Commit approved worktree"
        target_href = (
            f"/runs/{quote(commit.run_id)}"
            if commit is not None
            else "#goal-next-action"
        )
        target_label = target_href if commit is not None else "Next Action"
        reason = "commit approval is granted and awaiting the local commit action"
    elif approved_worktree:
        next_action = "Run approved worktree"
        target_href = "#goal-next-action"
        target_label = "Next Action"
        reason = "worktree approval is granted and execution is the next bounded step"
    elif approval_lines:
        next_action = "Review approval history"
        target_href = "#goal-approvals"
        target_label = "Approvals"
        reason = "approval records exist but no active approval gate is waiting"
    if current_form_available and next_action == current_action.action:
        target_href = current_href
        target_label = current_label
        target_form_available = current_form_available

    if pending_total:
        status = "waiting_for_operator"
    elif approved_total or downstream_total:
        status = "approved_gate_available"
    elif approval_lines:
        status = "history_available"
    else:
        status = "empty"

    approval_cards = "".join(
        [
            "<div class='goal-approval-card goal-approval-primary' data-goal-approval-now='true'>",
            "<h3>Now</h3>",
            f"<strong>{_e(next_action)}</strong>",
            f"<p>{_e(reason)}</p>",
            f"<a class='goal-approval-action' data-goal-approval-primary='true' href='{_e(target_href)}'>{_e(next_action)}</a>",
            "</div>",
            "<div class='goal-approval-card' data-goal-approval-pending='true'>",
            "<h3>Pending</h3>",
            f"<strong>{pending_total} waiting</strong>",
            f"<p>{pending_worktree} worktree; {pending_commit} commit; {pending_publication} publication.</p>",
            "<a class='goal-approval-link' href='/approvals'>Approvals</a>",
            "</div>",
            "<div class='goal-approval-card' data-goal-approval-approved='true'>",
            "<h3>Approved</h3>",
            f"<strong>{approved_total} approved</strong>",
            f"<p>{approved_worktree} worktree; {approved_commit} commit; {approved_publication} publication.</p>",
            "<a class='goal-approval-link' href='#goal-approvals'>Detailed rows</a>",
            "</div>",
            "<div class='goal-approval-card' data-goal-approval-downstream='true'>",
            "<h3>Downstream</h3>",
            f"<strong>{downstream_total} ready</strong>",
            f"<p>{committed_commit} committed; {publication_ready} publication handoff-ready.</p>",
            "<a class='goal-approval-link' href='#goal-completion-readiness'>Completion readiness</a>",
            "</div>",
            "<div class='goal-approval-card' data-goal-approval-safety='true'>",
            "<h3>Safety</h3>",
            "<strong>confirmed forms only</strong>",
            "<p>This Goal surface reads local approval posture and does not decide approvals on GET.</p>",
            "<a class='goal-approval-link' href='#goal-approval-command-bar'>Proof</a>",
            "</div>",
        ]
    )
    return "".join(
        [
            "<section id='goal-approval-command-bar' class='panel goal-approval-command-bar' data-goal-approval-command-bar='true'><h3>Goal Approval Command Bar</h3>",
            "<p class='muted'>Goal-scoped approval posture before the detailed worktree, commit, and publication approval records.</p>",
            "<div class='goal-approval-grid' data-goal-approval-actions='true'>",
            approval_cards,
            "</div>",
            "<details class='goal-approval-command-evidence' data-goal-approval-evidence='true'><summary>Goal approval command evidence</summary>",
            _kv(
                [
                    ("goal_approval_command_goal", goal.id),
                    ("goal_approval_command_project", goal.project_id),
                    ("goal_approval_command_status", status),
                    ("goal_approval_command_items", str(len(approval_lines))),
                    ("goal_approval_command_pending_total", str(pending_total)),
                    ("goal_approval_command_approved_total", str(approved_total)),
                    ("goal_approval_command_pending_worktree", str(pending_worktree)),
                    ("goal_approval_command_pending_commit", str(pending_commit)),
                    ("goal_approval_command_pending_publication", str(pending_publication)),
                    ("goal_approval_command_approved_worktree", str(approved_worktree)),
                    ("goal_approval_command_approved_commit", str(approved_commit)),
                    ("goal_approval_command_approved_publication", str(approved_publication)),
                    ("goal_approval_command_committed_commits", str(committed_commit)),
                    ("goal_approval_command_ready_publications", str(publication_ready)),
                    ("goal_approval_command_next_action", next_action),
                    (
                        "goal_approval_command_target_surface",
                        SafeHtml(f"<a href='{_e(target_href)}'>{_e(target_label)}</a>"),
                    ),
                    (
                        "goal_approval_command_action_form_available",
                        str(target_form_available).lower(),
                    ),
                    ("goal_approval_command_reason", reason),
                    ("goal_approval_command_source", "goal_local_approval_records"),
                    ("goal_approval_command_write_on_get", "false"),
                    ("goal_approval_command_provider_calls_taken", "0"),
                    ("goal_approval_command_network_actions_taken", "0"),
                    ("goal_approval_command_external_effects_created", "false"),
                ]
            ),
            _ul(
                [
                    f"goal_approval_now: {_e(next_action)}",
                    f"goal_approval_click: <a href='{_e(target_href)}'>{_e(target_label)}</a>",
                    f"goal_approval_reason: {_e(reason)}",
                    "goal_approval_safety: read-only local approval posture",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _goal_incident_section(root: Path, state: dict[str, Any]) -> str:
    lines = _goal_incident_lines(root, state)
    return _goal_incident_command_bar(root, state, lines) + _collapsible_list_section(
        "Goal Incidents",
        lines,
        anchor_id="goal-incidents",
        details_class="goal-incident-list",
        data_attr="goal-incident-list",
        summary=f"Detailed incident rows ({len(lines)})",
    )


def _goal_incident_command_bar(
    root: Path,
    state: dict[str, Any],
    incident_lines: list[str],
) -> str:
    goal = state["goal"]
    incidents = state["incidents"]
    open_incidents = [row for row in incidents if row["status"] == "open"]
    resolved_incidents = [row for row in incidents if row["status"] == "resolved"]
    open_recommendations = [
        row for row in state["recommendations"] if row["status"] == "open"
    ]
    current_action = _goal_next_action(root, state)
    current_form_available = bool(_goal_next_action_form(state, current_action))
    current_href = _goal_primary_action_href(
        state,
        current_action,
        form_available=current_form_available,
    )
    current_label = _goal_action_cta_label(current_action, current_form_available)
    target_form_available = False
    first_incident = (
        open_incidents[0]
        if open_incidents
        else (resolved_incidents[0] if resolved_incidents else None)
    )
    first_evidence: str | SafeHtml = "none"
    first_id = "none"
    first_status = "none"
    first_severity = "none"
    first_run = "none"
    first_task = "none"
    first_summary = "none"
    if first_incident is not None:
        first_id = str(first_incident["id"])
        first_status = str(first_incident["status"])
        first_severity = str(first_incident["severity"])
        first_run = str(first_incident["run_id"] or "none")
        first_task = str(first_incident["task_id"] or "none")
        first_summary = str(first_incident["summary"])
        evidence_path = str(first_incident["evidence_path"] or "none")
        first_evidence = SafeHtml(
            _artifact_link(_repo_relative_artifact_path(root, evidence_path))
        )
    if open_incidents:
        status = "open_incidents"
        next_action = "Inspect incident"
        target_href = "/incidents#incident-open"
        target_label = "Open Incidents"
        target_surface = SafeHtml("<a href='/incidents#incident-open'>Open Incidents</a>")
        reason = "open_goal_incident"
    elif open_recommendations:
        target = _goal_recommendation_target(goal, open_recommendations[0])
        status = "recommendations_open"
        next_action = target.action
        target_href = target.href
        target_label = target.label
        target_surface = SafeHtml(
            f"<a href='{_e(target.href)}'>{_e(target.label)}</a>"
        )
        reason = target.reason
    elif resolved_incidents:
        status = "resolved_history"
        next_action = "Review resolved incidents"
        target_href = "/incidents#incident-resolved"
        target_label = "Resolved Incidents"
        target_surface = SafeHtml(
            "<a href='/incidents#incident-resolved'>Resolved Incidents</a>"
        )
        reason = "resolved_goal_incidents"
    else:
        status = "clear"
        next_action = current_label
        target_href = current_href
        target_label = current_label
        target_surface = SafeHtml(
            f"<a href='{_e(target_href)}'>{_e(target_label)}</a>"
        )
        target_form_available = current_form_available
        reason = f"no_goal_incidents; current_action={current_action.reason}"
    incident_cards = "".join(
        [
            "<div class='goal-incident-card goal-incident-primary' data-goal-incident-now='true'>",
            "<h3>Now</h3>",
            f"<strong>{_e(next_action)}</strong>",
            f"<p>{_e(reason)}</p>",
            f"<a class='goal-incident-action' data-goal-incident-primary='true' href='{_e(target_href)}'>{_e(next_action)}</a>",
            "</div>",
            "<div class='goal-incident-card' data-goal-incident-open='true'>",
            "<h3>Open</h3>",
            f"<strong>{len(open_incidents)} incident(s)</strong>",
            f"<p>{len(open_recommendations)} recovery recommendation(s).</p>",
            "<a class='goal-incident-link' href='/incidents#incident-open'>Open incidents</a>",
            "</div>",
            "<div class='goal-incident-card' data-goal-incident-first='true'>",
            "<h3>First</h3>",
            f"<strong>{_e(first_id)}</strong>",
            f"<p>{_e(first_severity)}; {_e(first_summary)}</p>",
            f"<a class='goal-incident-link' href='{_e(target_href)}'>{_e(target_label)}</a>",
            "</div>",
            "<div class='goal-incident-card' data-goal-incident-recovery='true'>",
            "<h3>Recovery</h3>",
            f"<strong>{len(resolved_incidents)} resolved</strong>",
            f"<p>{len(incident_lines)} detailed incident row(s).</p>",
            "<a class='goal-incident-link' href='#goal-incidents'>Detailed rows</a>",
            "</div>",
            "<div class='goal-incident-card' data-goal-incident-safety='true'>",
            "<h3>Safety</h3>",
            "<strong>read-only triage</strong>",
            "<p>No resolution, retry, providers, network actions, or writes on GET.</p>",
            "<a class='goal-incident-link' href='#goal-remaining-work-command-bar'>Remaining work</a>",
            "</div>",
        ]
    )
    return "".join(
        [
            "<section id='goal-incident-command-bar' class='panel goal-incident-command-bar' data-goal-incident-command-bar='true'><h3>Goal Incident Command Bar</h3>",
            "<p class='muted'>Incident posture before the detailed goal incident list.</p>",
            "<div class='goal-incident-grid' data-goal-incident-actions='true'>",
            incident_cards,
            "</div>",
            "<details class='goal-incident-command-evidence' data-goal-incident-evidence='true'><summary>Goal incident command evidence</summary>",
            _kv(
                [
                    ("goal_incident_command_goal", goal.id),
                    ("goal_incident_command_project", goal.project_id),
                    ("goal_incident_command_status", status),
                    ("goal_incident_command_open_count", str(len(open_incidents))),
                    ("goal_incident_command_resolved_count", str(len(resolved_incidents))),
                    ("goal_incident_command_total_count", str(len(incidents))),
                    (
                        "goal_incident_command_open_recommendations",
                        str(len(open_recommendations)),
                    ),
                    ("goal_incident_command_first_id", first_id),
                    ("goal_incident_command_first_status", first_status),
                    ("goal_incident_command_first_severity", first_severity),
                    ("goal_incident_command_first_run", first_run),
                    ("goal_incident_command_first_task", first_task),
                    ("goal_incident_command_first_summary", first_summary),
                    ("goal_incident_command_first_evidence", first_evidence),
                    ("goal_incident_command_next_action", next_action),
                    ("goal_incident_command_target_surface", target_surface),
                    (
                        "goal_incident_command_action_form_available",
                        str(target_form_available).lower(),
                    ),
                    ("goal_incident_command_reason", reason),
                    ("goal_incident_command_source", "goal_incidents_and_recommendations"),
                    ("goal_incident_command_write_on_get", "false"),
                    ("goal_incident_command_provider_calls_taken", "0"),
                    ("goal_incident_command_network_actions_taken", "0"),
                    ("goal_incident_command_external_effects_created", "false"),
                ]
            ),
            _ul(
                [
                    f"goal_incident_now: {_e(status)} open={len(open_incidents)} resolved={len(resolved_incidents)}",
                    f"goal_incident_click: {target_surface}",
                    f"goal_incident_first: {_e(first_id)} severity={_e(first_severity)}",
                    "goal_incident_safety: read-only local incident posture",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _goal_incident_lines(root: Path, state: dict[str, Any]) -> list[str]:
    incidents = state["incidents"]
    open_incidents = [row for row in incidents if row["status"] == "open"]
    resolved_incidents = [row for row in incidents if row["status"] == "resolved"]
    lines = [
        "goal_incident_surface: <a href='/incidents'>/incidents</a>",
        f"goal_incident_open_count: {len(open_incidents)}",
        f"goal_incident_resolved_count: {len(resolved_incidents)}",
        f"goal_incident_total_count: {len(incidents)}",
        "goal_incidents_write_on_get: false",
        "goal_incidents_external_effects_created: false",
    ]
    if not incidents:
        lines.append("goal_incident_status: none")
        return lines
    for incident in incidents[:10]:
        evidence_path = str(incident["evidence_path"] or "none")
        lines.append(
            f"goal_incident: {_e(incident['id'])} status={_e(incident['status'])} "
            f"severity={_e(incident['severity'])} run={_e(incident['run_id'] or 'none')} "
            f"task={_e(incident['task_id'] or 'none')} summary={_e(incident['summary'])}"
        )
        lines.append(
            f"goal_incident_evidence: {_artifact_link(_repo_relative_artifact_path(root, evidence_path))}"
        )
    if len(incidents) > 10:
        lines.append(f"goal_incident_more_count: {len(incidents) - 10}")
    return lines


def _goal_evidence_lines(root: Path, state: dict[str, Any]) -> list[str]:
    lines: list[str] = []
    for row in state["runs"]:
        for key in ["activity_path", "summary_path", "events_path"]:
            if row[key]:
                lines.append(f"{_e(row['id'])} {key}: {_artifact_link(_repo_relative_artifact_path(root, row[key]))}")
    for incident in state["incidents"]:
        lines.append(f"incident {incident['id']}: {_artifact_link(str(incident['evidence_path'] or 'none'))}")
    for recommendation in state["recommendations"]:
        lines.append(f"recommendation {recommendation['id']}: {_artifact_link(str(recommendation['evidence_path']))}")
    for run in state["worktree_runs"]:
        lines.append(f"{_e(run.id)} evidence: {_artifact_link(run.evidence_path)}")
    return lines


def _goal_evidence_section(root: Path, state: dict[str, Any]) -> str:
    lines = _goal_evidence_lines(root, state)
    return (
        _goal_evidence_command_bar(root, state, lines)
        + _goal_evidence_digest(root, state, lines)
        + _collapsible_list_section(
            "Evidence",
            lines,
            anchor_id="goal-evidence",
            details_class="goal-evidence-list",
            data_attr="goal-evidence-list",
            summary=f"Detailed evidence list ({len(lines)})",
        )
    )


def _goal_evidence_command_bar(
    root: Path,
    state: dict[str, Any],
    evidence_lines: list[str],
) -> str:
    goal = state["goal"]
    artifact_records = _goal_artifact_records(root, state)
    artifact_counts = {kind: 0 for kind in ["markdown", "json", "patch", "text"]}
    for record in artifact_records:
        artifact_counts[record["kind"]] += 1

    run_evidence_items = sum(
        1
        for row in state["runs"]
        for key in ["activity_path", "summary_path", "events_path"]
        if row[key]
    )
    worktree_evidence_items = len(state["worktree_runs"])
    incident_evidence_items = len(state["incidents"])
    recommendation_evidence_items = len(state["recommendations"])
    latest_record = artifact_records[-1] if artifact_records else None
    if incident_evidence_items:
        next_action = "Review incident evidence"
        target_href = "#goal-incidents"
        target_label = "Goal Incidents"
        reason = "open or historical incident evidence is attached to this goal"
    elif recommendation_evidence_items:
        next_action = "Review recommendation evidence"
        target_href = "/incidents"
        target_label = "/incidents"
        reason = "task recommendations have local evidence attached"
    elif latest_record is not None:
        next_action = "Open latest Goal artifact"
        target_href = f"/artifacts?path={quote(latest_record['path'])}"
        target_label = latest_record["label"]
        reason = "goal artifacts are available in the bounded artifact viewer"
    elif evidence_lines:
        next_action = "Review evidence list"
        target_href = "#goal-evidence"
        target_label = "Evidence"
        reason = "run evidence records are available"
    else:
        next_action = "Create evidence through the next Goal action"
        target_href = "#goal-next-action"
        target_label = "Next Action"
        reason = "no local evidence records are attached yet"

    status = "available" if evidence_lines or artifact_records else "empty"
    latest_label = latest_record["label"] if latest_record is not None else "none"
    latest_href = (
        _artifact_href(root, latest_record["path"])
        if latest_record is not None
        else "#goal-artifact-explorer"
    )
    latest_button_label = (
        "Open latest artifact" if latest_record is not None else "Open artifact explorer"
    )
    latest_surface = (
        _artifact_link(latest_record["path"])
        if latest_record is not None
        else "none"
    )
    target = SafeHtml(f"<a href='{_e(target_href)}'>{_e(target_label)}</a>")
    attention_href = "#goal-incidents" if incident_evidence_items else "/incidents"
    attention_label = "Goal Incidents" if incident_evidence_items else "/incidents"
    attention_total = incident_evidence_items + recommendation_evidence_items
    evidence_cards = "".join(
        [
            "<div class='goal-evidence-card goal-evidence-primary' data-goal-evidence-now='true'>",
            "<h3>Now</h3>",
            f"<strong>{_e(next_action)}</strong>",
            f"<p>{_e(reason)}</p>",
            f"<a class='goal-evidence-action' data-goal-evidence-primary='true' href='{_e(target_href)}'>{_e(next_action)}</a>",
            "</div>",
            "<div class='goal-evidence-card' data-goal-evidence-latest='true'>",
            "<h3>Latest</h3>",
            f"<strong>{_e(latest_label)}</strong>",
            f"<p>{len(artifact_records)} bounded artifact record(s).</p>",
            f"<a class='goal-evidence-link' href='{_e(latest_href)}'>{_e(latest_button_label)}</a>",
            "</div>",
            "<div class='goal-evidence-card' data-goal-evidence-inventory='true'>",
            "<h3>Inventory</h3>",
            f"<strong>{len(evidence_lines)} evidence item(s)</strong>",
            (
                f"<p>{run_evidence_items} run, {worktree_evidence_items} worktree, "
                f"{len(artifact_records)} artifact.</p>"
            ),
            "<a class='goal-evidence-link' href='#goal-evidence'>Detailed list</a>",
            "</div>",
            "<div class='goal-evidence-card' data-goal-evidence-attention='true'>",
            "<h3>Attention</h3>",
            f"<strong>{attention_total} item(s)</strong>",
            (
                f"<p>{incident_evidence_items} incident, "
                f"{recommendation_evidence_items} recommendation.</p>"
            ),
            f"<a class='goal-evidence-link' href='{_e(attention_href)}'>{_e(attention_label)}</a>",
            "</div>",
            "<div class='goal-evidence-card' data-goal-evidence-safety='true'>",
            "<h3>Safety</h3>",
            "<strong>read-only local proof</strong>",
            "<p>No providers, network actions, writes on GET, or external effects.</p>",
            "<a class='goal-evidence-link' href='#goal-artifact-command-bar'>Artifacts</a>",
            "</div>",
        ]
    )
    return "".join(
        [
            "<section id='goal-evidence-command-bar' class='panel goal-evidence-command-bar' data-goal-evidence-command-bar='true'><h3>Goal Evidence Command Bar</h3>",
            "<p class='muted'>Goal-scoped evidence posture before the detailed evidence list and typed artifact explorer.</p>",
            "<div class='goal-evidence-grid' data-goal-evidence-actions='true'>",
            evidence_cards,
            "</div>",
            "<details class='goal-evidence-command-evidence' data-goal-evidence-evidence='true'><summary>Goal evidence command evidence</summary>",
            _kv(
                [
                    ("goal_evidence_command_goal", goal.id),
                    ("goal_evidence_command_project", goal.project_id),
                    ("goal_evidence_command_status", status),
                    ("goal_evidence_command_items", str(len(evidence_lines))),
                    ("goal_evidence_command_artifact_records", str(len(artifact_records))),
                    ("goal_evidence_command_run_evidence_items", str(run_evidence_items)),
                    ("goal_evidence_command_worktree_evidence_items", str(worktree_evidence_items)),
                    ("goal_evidence_command_incident_evidence_items", str(incident_evidence_items)),
                    ("goal_evidence_command_recommendation_evidence_items", str(recommendation_evidence_items)),
                    ("goal_evidence_command_markdown_artifacts", str(artifact_counts["markdown"])),
                    ("goal_evidence_command_json_artifacts", str(artifact_counts["json"])),
                    ("goal_evidence_command_patch_artifacts", str(artifact_counts["patch"])),
                    ("goal_evidence_command_text_artifacts", str(artifact_counts["text"])),
                    ("goal_evidence_command_latest_artifact", latest_label),
                    ("goal_evidence_command_latest_surface", SafeHtml(str(latest_surface))),
                    ("goal_evidence_command_next_action", next_action),
                    (
                        "goal_evidence_command_target_surface",
                        target,
                    ),
                    ("goal_evidence_command_reason", reason),
                    ("goal_evidence_command_source", "goal_evidence_lines_and_artifact_registry"),
                    ("goal_evidence_command_write_on_get", "false"),
                    ("goal_evidence_command_provider_calls_taken", "0"),
                    ("goal_evidence_command_network_actions_taken", "0"),
                    ("goal_evidence_command_external_effects_created", "false"),
                ]
            ),
            _ul(
                [
                    f"goal_evidence_now: {_e(next_action)}",
                    f"goal_evidence_click: <a href='{_e(target_href)}'>{_e(target_label)}</a>",
                    f"goal_evidence_reason: {_e(reason)}",
                    "goal_evidence_safety: read-only local evidence inventory",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _goal_evidence_digest(
    root: Path,
    state: dict[str, Any],
    evidence_lines: list[str],
) -> str:
    goal = state["goal"]
    artifact_records = _goal_artifact_records(root, state)
    artifact_counts = {kind: 0 for kind in ["markdown", "json", "patch", "text"]}
    available_artifacts = 0
    missing_artifacts = 0
    for record in artifact_records:
        artifact_counts[record["kind"]] += 1
        if record["status"] == "available":
            available_artifacts += 1
        else:
            missing_artifacts += 1

    run_evidence_items = sum(
        1
        for row in state["runs"]
        for key in ["activity_path", "summary_path", "events_path"]
        if row[key]
    )
    worktree_evidence_items = len(state["worktree_runs"])
    incident_evidence_items = len(state["incidents"])
    recommendation_evidence_items = len(state["recommendations"])

    latest_path = _goal_latest_artifact_path(root, state)
    latest_record = next(
        (record for record in artifact_records if record["path"] == latest_path),
        None,
    )
    if latest_record is None:
        latest_record = next(
            (record for record in reversed(artifact_records) if record["status"] == "available"),
            artifact_records[-1] if artifact_records else None,
        )
    latest_label = latest_record["label"] if latest_record is not None else "none"
    latest_kind = latest_record["kind"] if latest_record is not None else "none"
    latest_status = latest_record["status"] if latest_record is not None else "none"
    latest_href = (
        _artifact_href(root, latest_record["path"])
        if latest_record is not None
        else "#goal-artifact-explorer"
    )
    latest_surface = (
        _artifact_link(latest_record["path"])
        if latest_record is not None
        else "none"
    )

    project = _storage(root).get_registered_project(goal.project_id)
    project_root = Path(project.root_path) if project else root
    repo = _repo_state(project_root)
    full_commit = _git(project_root, ["rev-parse", "HEAD"]) or repo["commit"]
    latest_ci = _latest_ci_evidence_record(root, project_id=goal.project_id)
    ci_source = "none"
    ci_status = "missing"
    ci_scope = "none"
    ci_run_id = "none"
    ci_commit = "none"
    ci_matches_current = False
    ci_status_label = "No CI proof"
    ci_href = "#record-goal-ci-proof"
    ci_link_label = "Record CI proof"
    ci_record_surface: str | SafeHtml = "none"
    if latest_ci is not None:
        ci_source, ci_record = latest_ci
        result_json = ci_record.result_json if isinstance(ci_record.result_json, dict) else {}
        ci_status = str(ci_record.status)
        ci_scope = str(result_json.get("evidence_scope", "unknown"))
        ci_run_id = str(ci_record.external_run_id)
        ci_commit = str(ci_record.commit_sha)
        branch_matches = ci_record.branch_name == repo["branch"]
        commit_matches = _commit_refs_match(ci_record.commit_sha, full_commit, repo["commit"])
        ci_matches_current = branch_matches and commit_matches
        if ci_matches_current and ci_status == "success" and ci_scope == "workflow_run":
            ci_status_label = "Current workflow proof"
            ci_href = "#goal-verification-evidence"
            ci_link_label = "Review CI proof"
        elif ci_matches_current and ci_status == "success":
            ci_status_label = "Current partial proof"
            ci_href = "#record-goal-ci-proof"
            ci_link_label = "Record full proof"
        elif ci_matches_current:
            ci_status_label = "Current proof needs attention"
            ci_href = "#goal-verification-evidence"
            ci_link_label = "Inspect CI proof"
        else:
            ci_status_label = "Stale CI proof"
            ci_href = "#record-goal-ci-proof"
            ci_link_label = "Record current proof"
        ci_record_surface = SafeHtml(
            _artifact_link(_repo_relative_artifact_path(root, ci_record.evidence_path))
        )

    evidence_status = "available" if evidence_lines or artifact_records else "empty"
    artifact_mix = (
        f"{artifact_counts['markdown']} md / {artifact_counts['json']} json / "
        f"{artifact_counts['patch']} patch / {artifact_counts['text']} text"
    )
    proof_total = len(evidence_lines) + len(artifact_records)

    return "".join(
        [
            "<section id='goal-evidence-digest' class='panel goal-evidence-digest' data-goal-evidence-digest='true'><h3>Goal Evidence Digest</h3>",
            "<p class='muted'>Scan-first proof summary before the full evidence inventory.</p>",
            "<div class='goal-evidence-grid' data-goal-evidence-digest-actions='true'>",
            "<article class='goal-evidence-card goal-evidence-primary' data-goal-evidence-digest-proof='true'>",
            "<h3>Proof</h3>",
            f"<strong>{_e(evidence_status)}</strong>",
            f"<p>{proof_total} local proof item(s); {available_artifacts} available artifact(s).</p>",
            "<a class='goal-evidence-action' data-goal-evidence-digest-primary='true' href='#goal-evidence'>Evidence list</a>",
            "</article>",
            "<article class='goal-evidence-card' data-goal-evidence-digest-latest='true'>",
            "<h3>Latest</h3>",
            f"<strong>{_e(latest_label)}</strong>",
            f"<p>{_e(latest_kind)}; status={_e(latest_status)}.</p>",
            f"<a class='goal-evidence-link' href='{_e(latest_href)}'>Open latest</a>",
            "</article>",
            "<article class='goal-evidence-card' data-goal-evidence-digest-run='true'>",
            "<h3>Run Proof</h3>",
            f"<strong>{run_evidence_items + worktree_evidence_items} item(s)</strong>",
            f"<p>{run_evidence_items} run file(s); {worktree_evidence_items} coder run(s).</p>",
            "<a class='goal-evidence-link' href='#goal-runs'>Runs</a>",
            "</article>",
            "<article class='goal-evidence-card' data-goal-evidence-digest-types='true'>",
            "<h3>Artifact Mix</h3>",
            f"<strong>{len(artifact_records)} artifact(s)</strong>",
            f"<p>{_e(artifact_mix)}; missing={missing_artifacts}.</p>",
            "<a class='goal-evidence-link' href='#goal-artifact-explorer'>Artifact explorer</a>",
            "</article>",
            "<article class='goal-evidence-card' data-goal-evidence-digest-ci='true'>",
            "<h3>CI Proof</h3>",
            f"<strong>{_e(ci_status_label)}</strong>",
            f"<p>{_e(ci_status)}; scope={_e(ci_scope)}; matches current={str(ci_matches_current).lower()}.</p>",
            f"<a class='goal-evidence-link' href='{_e(ci_href)}'>{_e(ci_link_label)}</a>",
            "</article>",
            "<article class='goal-evidence-card' data-goal-evidence-digest-safety='true'>",
            "<h3>Safety</h3>",
            "<strong>read-only digest</strong>",
            "<p>No provider calls, network actions, writes on GET, or external effects.</p>",
            "<a class='goal-evidence-link' href='#goal-evidence-digest'>Evidence</a>",
            "</article>",
            "</div>",
            "<details class='goal-evidence-digest-evidence' data-goal-evidence-digest-evidence='true'><summary>Goal evidence digest evidence</summary>",
            _kv(
                [
                    ("goal_evidence_digest_goal", goal.id),
                    ("goal_evidence_digest_project", goal.project_id),
                    ("goal_evidence_digest_status", evidence_status),
                    ("goal_evidence_digest_evidence_items", str(len(evidence_lines))),
                    ("goal_evidence_digest_artifact_records", str(len(artifact_records))),
                    ("goal_evidence_digest_available_artifacts", str(available_artifacts)),
                    ("goal_evidence_digest_missing_artifacts", str(missing_artifacts)),
                    ("goal_evidence_digest_run_evidence_items", str(run_evidence_items)),
                    ("goal_evidence_digest_worktree_evidence_items", str(worktree_evidence_items)),
                    ("goal_evidence_digest_incident_evidence_items", str(incident_evidence_items)),
                    ("goal_evidence_digest_recommendation_evidence_items", str(recommendation_evidence_items)),
                    ("goal_evidence_digest_markdown_artifacts", str(artifact_counts["markdown"])),
                    ("goal_evidence_digest_json_artifacts", str(artifact_counts["json"])),
                    ("goal_evidence_digest_patch_artifacts", str(artifact_counts["patch"])),
                    ("goal_evidence_digest_text_artifacts", str(artifact_counts["text"])),
                    ("goal_evidence_digest_latest_artifact", latest_label),
                    ("goal_evidence_digest_latest_kind", latest_kind),
                    ("goal_evidence_digest_latest_status", latest_status),
                    ("goal_evidence_digest_latest_surface", SafeHtml(str(latest_surface))),
                    ("goal_evidence_digest_ci_status_label", ci_status_label),
                    ("goal_evidence_digest_ci_status", ci_status),
                    ("goal_evidence_digest_ci_source", ci_source),
                    ("goal_evidence_digest_ci_scope", ci_scope),
                    ("goal_evidence_digest_ci_run_id", ci_run_id),
                    ("goal_evidence_digest_ci_commit", ci_commit),
                    ("goal_evidence_digest_ci_matches_current_checkout", str(ci_matches_current).lower()),
                    ("goal_evidence_digest_ci_surface", ci_record_surface),
                    ("goal_evidence_digest_source", "goal_evidence_lines_artifact_records_and_project_ci_evidence"),
                    ("goal_evidence_digest_write_on_get", "false"),
                    ("goal_evidence_digest_github_status_fetch", "none"),
                    ("goal_evidence_digest_provider_calls_taken", "0"),
                    ("goal_evidence_digest_network_actions_taken", "0"),
                    ("goal_evidence_digest_external_effects_created", "false"),
                ]
            ),
            _ul(
                [
                    f"goal_evidence_digest_proof: {proof_total} local proof item(s)",
                    f"goal_evidence_digest_latest: {_e(latest_label)} kind={_e(latest_kind)} status={_e(latest_status)}",
                    f"goal_evidence_digest_artifacts: {_e(artifact_mix)}",
                    f"goal_evidence_digest_ci: {_e(ci_status_label)} status={_e(ci_status)} scope={_e(ci_scope)}",
                    "goal_evidence_digest_safety: read-only local proof digest",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _goal_artifact_lines(root: Path, state: dict[str, Any]) -> list[str]:
    return [
        f"{_e(record['label'])}: {_artifact_link(record['path'])}"
        for record in _goal_artifact_records(root, state)
    ]


def _goal_artifact_section(root: Path, state: dict[str, Any]) -> str:
    records = _goal_artifact_records(root, state)
    lines = [
        f"{_e(record['label'])}: {_artifact_link(record['path'])}"
        for record in records
    ]
    return _goal_artifact_command_bar(root, state, records, lines) + _collapsible_list_section(
        "Artifacts",
        lines,
        anchor_id="goal-artifacts",
        details_class="goal-artifact-list",
        data_attr="goal-artifact-list",
        summary=f"Detailed artifact list ({len(lines)})",
    ) + _goal_artifact_explorer(root, state, records=records)


def _goal_artifact_command_bar(
    root: Path,
    state: dict[str, Any],
    records: list[dict[str, str]],
    artifact_lines: list[str],
) -> str:
    goal = state["goal"]
    counts = {kind: 0 for kind in ["markdown", "json", "patch", "text"]}
    sources: dict[str, int] = {}
    available = 0
    missing = 0
    for record in records:
        counts[record["kind"]] = counts.get(record["kind"], 0) + 1
        sources[record["source"]] = sources.get(record["source"], 0) + 1
        if record["status"] == "available":
            available += 1
        else:
            missing += 1
    latest_path = _goal_latest_artifact_path(root, state)
    latest_record = next(
        (record for record in records if record["path"] == latest_path),
        None,
    )
    if latest_record is None:
        latest_record = next(
            (record for record in reversed(records) if record["status"] == "available"),
            records[-1] if records else None,
        )
    latest_label = latest_record["label"] if latest_record is not None else "none"
    latest_kind = latest_record["kind"] if latest_record is not None else "none"
    latest_source = latest_record["source"] if latest_record is not None else "none"
    latest_status = latest_record["status"] if latest_record is not None else "none"
    latest_surface = (
        _artifact_link(latest_record["path"])
        if latest_record is not None
        else "none"
    )
    source_summary = (
        ", ".join(f"{source}:{count}" for source, count in sorted(sources.items()))
        if sources
        else "none"
    )
    if latest_record is not None and latest_record["status"] == "available":
        next_action = "Open latest artifact"
        target_href = _artifact_href(root, latest_record["path"])
        target_label = latest_record["label"]
        reason = "latest available goal artifact is ready for bounded review"
    elif records:
        next_action = "Review artifact inventory"
        target_href = "#goal-artifact-explorer"
        target_label = "Goal Artifact Explorer"
        reason = "goal artifact records exist but no available latest artifact was found"
    else:
        next_action = "Create artifact through next Goal action"
        target_href = "#goal-next-action"
        target_label = "Next Action"
        reason = "goal has no bounded artifact records yet"
    status = "available" if available else "empty"
    if available and missing:
        status = "partial"
    target = SafeHtml(f"<a href='{_e(target_href)}'>{_e(target_label)}</a>")
    latest_href = (
        _artifact_href(root, latest_record["path"])
        if latest_record is not None
        else "#goal-artifact-explorer"
    )
    latest_button_label = (
        "Open latest artifact" if latest_record is not None else "Open explorer"
    )
    artifact_cards = "".join(
        [
            "<div class='goal-artifact-card goal-artifact-primary' data-goal-artifact-open='true'>",
            "<h3>Open</h3>",
            f"<strong>{_e(next_action)}</strong>",
            f"<p>{_e(reason)}</p>",
            f"<a class='goal-artifact-action' data-goal-artifact-primary='true' href='{_e(target_href)}'>{_e(next_action)}</a>",
            "</div>",
            "<div class='goal-artifact-card' data-goal-artifact-latest='true'>",
            "<h3>Latest</h3>",
            f"<strong>{_e(latest_label)}</strong>",
            f"<p>{_e(latest_kind)} from {_e(latest_source)}; {_e(latest_status)}.</p>",
            f"<a class='goal-artifact-link' href='{_e(latest_href)}'>{_e(latest_button_label)}</a>",
            "</div>",
            "<div class='goal-artifact-card' data-goal-artifact-types='true'>",
            "<h3>Types</h3>",
            (
                f"<strong>{counts['markdown']} md / {counts['json']} json</strong>"
            ),
            f"<p>{counts['patch']} patch, {counts['text']} text/log.</p>",
            "<a class='goal-artifact-link' href='#goal-artifact-explorer'>Explorer</a>",
            "</div>",
            "<div class='goal-artifact-card' data-goal-artifact-inventory='true'>",
            "<h3>Inventory</h3>",
            f"<strong>{available} available / {missing} missing</strong>",
            f"<p>{_e(source_summary)}</p>",
            "<a class='goal-artifact-link' href='#goal-artifacts'>Detailed list</a>",
            "</div>",
            "<div class='goal-artifact-card' data-goal-artifact-safety='true'>",
            "<h3>Safety</h3>",
            "<strong>bounded viewer only</strong>",
            "<p>No raw filesystem browsing, writes on GET, providers, or network actions.</p>",
            "<a class='goal-artifact-link' href='#goal-evidence-command-bar'>Evidence</a>",
            "</div>",
        ]
    )
    return "".join(
        [
            "<section id='goal-artifact-command-bar' class='panel goal-artifact-command-bar' data-goal-artifact-command-bar='true'><h3>Goal Artifact Command Bar</h3>",
            "<p class='muted'>Goal-scoped artifact posture before the detailed artifact list and typed explorer.</p>",
            "<div class='goal-artifact-grid' data-goal-artifact-actions='true'>",
            artifact_cards,
            "</div>",
            "<details class='goal-artifact-command-evidence' data-goal-artifact-evidence='true'><summary>Goal artifact command evidence</summary>",
            _kv(
                [
                    ("goal_artifact_command_goal", goal.id),
                    ("goal_artifact_command_project", goal.project_id),
                    ("goal_artifact_command_status", status),
                    ("goal_artifact_command_items", str(len(artifact_lines))),
                    ("goal_artifact_command_records", str(len(records))),
                    ("goal_artifact_command_available_records", str(available)),
                    ("goal_artifact_command_missing_records", str(missing)),
                    ("goal_artifact_command_markdown_artifacts", str(counts["markdown"])),
                    ("goal_artifact_command_json_artifacts", str(counts["json"])),
                    ("goal_artifact_command_patch_artifacts", str(counts["patch"])),
                    ("goal_artifact_command_text_artifacts", str(counts["text"])),
                    ("goal_artifact_command_sources", source_summary),
                    ("goal_artifact_command_latest_artifact", latest_label),
                    ("goal_artifact_command_latest_kind", latest_kind),
                    ("goal_artifact_command_latest_source", latest_source),
                    ("goal_artifact_command_latest_status", latest_status),
                    ("goal_artifact_command_latest_surface", SafeHtml(str(latest_surface))),
                    ("goal_artifact_command_next_action", next_action),
                    ("goal_artifact_command_target_surface", target),
                    ("goal_artifact_command_reason", reason),
                    ("goal_artifact_command_source", "goal_artifact_registry"),
                    ("goal_artifact_command_raw_filesystem_browsing", "false"),
                    ("goal_artifact_command_write_on_get", "false"),
                    ("goal_artifact_command_provider_calls_taken", "0"),
                    ("goal_artifact_command_network_actions_taken", "0"),
                    ("goal_artifact_command_external_effects_created", "false"),
                ]
            ),
            _ul(
                [
                    f"goal_artifact_now: {_e(next_action)}",
                    f"goal_artifact_click: {target}",
                    (
                        "goal_artifact_latest: "
                        f"{_e(latest_label)} kind={_e(latest_kind)} "
                        f"source={_e(latest_source)} status={_e(latest_status)}"
                    ),
                    "goal_artifact_safety: read-only bounded artifact inventory",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _goal_artifact_explorer(
    root: Path,
    state: dict[str, Any],
    *,
    records: list[dict[str, str]] | None = None,
) -> str:
    goal = state["goal"]
    if records is None:
        records = _goal_artifact_records(root, state)
    groups = {kind: [] for kind in ["markdown", "json", "patch", "text"]}
    sources: dict[str, int] = {}
    for record in records:
        groups[record["kind"]].append(record)
        sources[record["source"]] = sources.get(record["source"], 0) + 1
    type_buttons = [
        (
            "<button type='button' class='goal-artifact-filter-button' "
            "data-goal-artifact-filter-kind='all' data-goal-artifact-filter-active='true' aria-pressed='true'>"
            f"All <span>{len(records)}</span></button>"
        )
    ]
    for kind, label in [
        ("markdown", "Markdown"),
        ("json", "JSON"),
        ("patch", "Patch"),
        ("text", "Text"),
    ]:
        type_buttons.append(
            (
                "<button type='button' class='goal-artifact-filter-button' "
                f"data-goal-artifact-filter-kind='{_e(kind)}' aria-pressed='false'>{_e(label)} "
                f"<span>{len(groups[kind])}</span></button>"
            )
        )
    source_options = [
        f"<option value='{_e(source)}'>{_e(source)} ({count})</option>"
        for source, count in sorted(sources.items())
    ]
    source_summary = (
        ", ".join(f"{source}={count}" for source, count in sorted(sources.items()))
        if sources
        else "none"
    )
    storage_key = f"clankeros-goal-artifact-filter:{goal.id}"
    filter_status = "available" if records else "empty"
    sections = [
        "<section id='goal-artifact-explorer' class='goal-artifact-explorer' data-goal-artifact-explorer='true'><h2>Goal Artifact Explorer</h2>",
        "<div id='goal-artifact-filter' class='goal-artifact-filter' data-goal-artifact-filter='true' "
        f"data-goal-artifact-filter-storage-key='{_e(storage_key)}'>",
        "<h3>Goal Artifact Filter</h3>",
        "<p class='muted'>Filter rendered Goal artifacts by type, source, or text without reading new paths.</p>",
        "<div class='goal-artifact-filter-buttons' data-goal-artifact-filter-buttons='true'>",
        "".join(type_buttons),
        "</div>",
        "<div class='goal-artifact-filter-controls' data-goal-artifact-filter-controls='true'>",
        "<label>Find <input type='search' data-goal-artifact-filter-query='true' placeholder='handoff, diff, status, run...'></label>",
        "<label>Source <select data-goal-artifact-filter-source='true'>",
        f"<option value='all'>All sources ({len(records)})</option>",
        "".join(source_options),
        "</select></label>",
        "</div>",
        "<div class='goal-artifact-filter-memory' data-goal-artifact-filter-memory='true'>",
        "<span class='goal-artifact-filter-memory-status' data-goal-artifact-filter-view-status='true'>View: default</span>",
        "<button type='button' class='goal-artifact-filter-reset' data-goal-artifact-filter-reset='true'>Reset filter</button>",
        "</div>",
        f"<p class='muted' data-goal-artifact-filter-status='true'>Showing {len(records)} of {len(records)} artifacts.</p>",
        "<p class='muted goal-artifact-filter-empty' data-goal-artifact-filter-empty='true' hidden>No artifacts match this filter.</p>",
        "<details class='goal-artifact-filter-evidence' data-goal-artifact-filter-evidence='true'><summary>Goal artifact filter evidence</summary>",
        _kv(
            [
                ("goal_artifact_filter_status", filter_status),
                ("goal_artifact_filter_scope", "browser_local_rendered_artifacts"),
                ("goal_artifact_filter_goal", goal.id),
                ("goal_artifact_filter_project", goal.project_id),
                ("goal_artifact_filter_total_records", str(len(records))),
                ("goal_artifact_filter_markdown_artifacts", str(len(groups["markdown"]))),
                ("goal_artifact_filter_json_artifacts", str(len(groups["json"]))),
                ("goal_artifact_filter_patch_artifacts", str(len(groups["patch"]))),
                ("goal_artifact_filter_text_artifacts", str(len(groups["text"]))),
                ("goal_artifact_filter_sources", source_summary),
                ("goal_artifact_filter_source_count", str(len(sources))),
                ("goal_artifact_filter_source", "data-goal-artifact-item"),
                ("goal_artifact_filter_persistence", "browser_local_view_memory"),
                ("goal_artifact_filter_memory_storage", f"localStorage:{storage_key}"),
                ("goal_artifact_filter_memory_fields", "type source query goal"),
                ("goal_artifact_filter_default_type", "all"),
                ("goal_artifact_filter_default_source", "all"),
                ("goal_artifact_filter_reset", "available"),
                ("goal_artifact_filter_raw_filesystem_browsing", "false"),
                ("goal_artifact_filter_write_on_get", "false"),
                ("goal_artifact_filter_provider_calls_taken", "0"),
                ("goal_artifact_filter_network_actions_taken", "0"),
                ("goal_artifact_filter_external_effects_created", "false"),
            ]
        ),
        _ul(
            [
                "goal_artifact_filter_action: narrow rendered artifact rows by type, source, or text",
                "goal_artifact_filter_memory: restores type/source/query from browser storage per Goal",
                "goal_artifact_filter_reset: clears the browser-local artifact filter",
                "goal_artifact_filter_safety: client-side display filter only",
            ]
        ),
        "</details>",
        "</div>",
        "<details class='goal-artifact-explorer-evidence' data-goal-artifact-explorer-evidence='true'><summary>Artifact explorer evidence</summary>",
        _kv(
            [
                ("artifact_explorer_raw_filesystem_browsing", "false"),
                ("artifact_viewer_route", "/artifacts?path=<repo-relative-artifact>"),
                ("artifact_render_types", "Markdown, JSON, Patch, Text"),
                ("markdown_artifacts", str(len(groups["markdown"]))),
                ("json_artifacts", str(len(groups["json"]))),
                ("patch_artifacts", str(len(groups["patch"]))),
                ("text_artifacts", str(len(groups["text"]))),
            ]
        ),
        "</details>",
        _goal_artifact_reader(root, state, records),
        "<div class='goal-artifact-groups' data-goal-artifact-groups='true'>",
    ]
    if not records:
        sections.append(_ul(["artifact_explorer_status: no_supported_goal_artifacts"]))
    for kind, heading in [
        ("markdown", "Markdown"),
        ("json", "JSON"),
        ("patch", "Patch"),
        ("text", "Text"),
    ]:
        items = [
            (
                "<span data-goal-artifact-item='true' "
                f"data-goal-artifact-type='{_e(record['kind'])}' "
                f"data-goal-artifact-source='{_e(record['source'])}' "
                f"data-goal-artifact-status='{_e(record['status'])}' "
                f"data-goal-artifact-text='{_e(' '.join([record['label'], record['path'], record['kind'], record['status'], record['source']]).lower())}'>"
                f"{_e(record['label'])}: {_artifact_link(record['path'])} "
                f"artifact_type={_e(record['kind'])} "
                f"status={_e(record['status'])} "
                f"source={_e(record['source'])}</span>"
            )
            for record in groups[kind]
        ]
        sections.append(
            f"<details class='goal-artifact-group' data-goal-artifact-group='{_e(kind)}'><summary>{_e(heading)} ({len(groups[kind])})</summary>"
        )
        sections.append(_ul(items or [f"{kind}_artifacts_status: none"]))
        sections.append("</details>")
    sections.append("</div>")
    sections.append("</section>")
    return "".join(sections)


def _goal_artifact_reader(
    root: Path,
    state: dict[str, Any],
    records: list[dict[str, str]],
) -> str:
    goal = state["goal"]
    available_records = [record for record in records if record["status"] == "available"]
    selected_path = _goal_latest_artifact_path(root, state)
    selected_record = next(
        (record for record in available_records if record["path"] == selected_path),
        None,
    )
    if selected_record is None and available_records:
        selected_record = available_records[-1]
        selected_path = selected_record["path"]
    elif selected_record is None:
        selected_path = ""
    previews = [
        _goal_artifact_preview(root, record, selected_path=selected_path)
        for record in available_records
    ]
    selected_preview = next(
        (preview for preview in previews if preview["path"] == selected_path),
        previews[-1] if previews else None,
    )
    options = [
        (
            f"<option value='{_e(preview['path'])}'"
            f"{' selected' if preview['path'] == selected_path else ''}>"
            f"{_e(preview['label'])} · {_e(preview['kind'])}</option>"
        )
        for preview in previews
    ]
    preview_html = "".join(str(preview["html"]) for preview in previews)
    selected_label = str(selected_preview["label"]) if selected_preview else "none"
    selected_kind = str(selected_preview["kind"]) if selected_preview else "none"
    selected_source = str(selected_preview["source"]) if selected_preview else "none"
    selected_renderer = str(selected_preview["renderer"]) if selected_preview else "none"
    selected_bytes = str(selected_preview["rendered_bytes"]) if selected_preview else "0"
    selected_lines = str(selected_preview["line_count"]) if selected_preview else "0"
    selected_truncated = str(selected_preview["truncated"]).lower() if selected_preview else "false"
    selected_href = _artifact_href(root, selected_path) if selected_path else "#goal-artifact-reader"
    storage_key = f"clankeros-goal-artifact-reader:{goal.id}"
    status = "available" if previews else "empty"
    return "".join(
        [
            "<section id='goal-artifact-reader' class='panel goal-artifact-reader' data-goal-artifact-reader='true' "
            f"data-goal-artifact-reader-storage-key='{_e(storage_key)}'>",
            "<h3>Goal Artifact Reader</h3>",
            "<p class='muted'>Preview one known Goal artifact in-page with the same inert Markdown, JSON, patch, and text renderers used by the full artifact viewer.</p>",
            "<div class='goal-artifact-reader-toolbar' data-goal-artifact-reader-toolbar='true'>",
            "<label>Read <select data-goal-artifact-reader-select='true'>",
            "".join(options) if options else "<option value=''>No available artifacts</option>",
            "</select></label>",
            f"<a class='goal-artifact-reader-open' data-goal-artifact-reader-open='true' href='{_e(selected_href)}'>Open full artifact</a>",
            "<span class='goal-artifact-reader-view-status' data-goal-artifact-reader-view-status='true'>View: default</span>",
            "<button type='button' class='goal-artifact-reader-reset' data-goal-artifact-reader-reset='true'>Reset reader</button>",
            "</div>",
            "<details class='goal-artifact-reader-evidence' data-goal-artifact-reader-evidence='true'><summary>Goal artifact reader evidence</summary>",
            _kv(
                [
                    ("goal_artifact_reader_status", status),
                    ("goal_artifact_reader_goal", goal.id),
                    ("goal_artifact_reader_project", goal.project_id),
                    ("goal_artifact_reader_total_records", str(len(records))),
                    ("goal_artifact_reader_preview_records", str(len(previews))),
                    ("goal_artifact_reader_selected_artifact", selected_label),
                    ("goal_artifact_reader_selected_path", selected_path or "none"),
                    ("goal_artifact_reader_selected_kind", selected_kind),
                    ("goal_artifact_reader_selected_source", selected_source),
                    ("goal_artifact_reader_selected_renderer", selected_renderer),
                    ("goal_artifact_reader_selected_bytes", selected_bytes),
                    ("goal_artifact_reader_selected_line_count", selected_lines),
                    ("goal_artifact_reader_selected_truncated", selected_truncated),
                    ("goal_artifact_reader_full_surface", SafeHtml(f"<a href='{_e(selected_href)}'>{_e(selected_href)}</a>")),
                    ("goal_artifact_reader_byte_cap", str(GOAL_ARTIFACT_READER_BYTES)),
                    ("goal_artifact_reader_persistence", "browser_local_view_memory"),
                    ("goal_artifact_reader_memory_storage", f"localStorage:{storage_key}"),
                    ("goal_artifact_reader_memory_fields", "path goal"),
                    ("goal_artifact_reader_reset", "available"),
                    ("goal_artifact_reader_raw_filesystem_browsing", "false"),
                    ("goal_artifact_reader_content_executed", "false"),
                    ("goal_artifact_reader_write_on_get", "false"),
                    ("goal_artifact_reader_provider_calls_taken", "0"),
                    ("goal_artifact_reader_network_actions_taken", "0"),
                    ("goal_artifact_reader_external_effects_created", "false"),
                ]
            ),
            _ul(
                [
                    f"goal_artifact_reader_now: {_e(selected_label)} kind={_e(selected_kind)}",
                    f"goal_artifact_reader_open: <a href='{_e(selected_href)}'>{_e(selected_href)}</a>",
                    "goal_artifact_reader_memory: restores selected known artifact from browser storage per Goal",
                    "goal_artifact_reader_safety: bounded inert in-page preview of registered Goal artifacts only",
                ]
            ),
            "</details>",
            "<div class='goal-artifact-reader-previews' data-goal-artifact-reader-previews='true'>",
            preview_html or "<p class='muted' data-goal-artifact-reader-empty='true'>No available Goal artifacts to preview yet.</p>",
            "</div>",
            "</section>",
        ]
    )


def _goal_artifact_preview(
    root: Path,
    record: dict[str, str],
    *,
    selected_path: str,
) -> dict[str, Any]:
    relative_path = record["path"]
    hidden_attr = "" if relative_path == selected_path else " hidden"
    fallback = {
        "label": record["label"],
        "path": relative_path,
        "kind": record["kind"],
        "source": record["source"],
        "renderer": "missing",
        "rendered_bytes": 0,
        "line_count": 0,
        "truncated": False,
    }
    try:
        path = resolve_artifact_path(root, relative_path)
    except ValueError:
        fallback["html"] = SafeHtml(
            "<article class='goal-artifact-preview' data-goal-artifact-preview='true' "
            f"data-goal-artifact-reader-path='{_e(relative_path)}'{hidden_attr}>"
            f"<h4>{_e(record['label'])}</h4>"
            "<p class='muted'>Artifact path was rejected by the bounded viewer.</p>"
            "</article>"
        )
        return fallback
    if not path.exists() or not path.is_file():
        fallback["html"] = SafeHtml(
            "<article class='goal-artifact-preview' data-goal-artifact-preview='true' "
            f"data-goal-artifact-reader-path='{_e(relative_path)}'{hidden_attr}>"
            f"<h4>{_e(record['label'])}</h4>"
            "<p class='muted'>Artifact file is missing.</p>"
            "</article>"
        )
        return fallback
    size = path.stat().st_size
    data = path.read_bytes()[:GOAL_ARTIFACT_READER_BYTES]
    truncated = size > GOAL_ARTIFACT_READER_BYTES
    text = data.decode("utf-8", errors="replace")
    if path.suffix == ".json" and not truncated:
        try:
            text = json.dumps(json.loads(text), indent=2, sort_keys=True)
        except json.JSONDecodeError:
            pass
    render_family = _artifact_render_family(path)
    renderer = _artifact_renderer_name(path)
    line_count = len(text.splitlines())
    rendered = _render_artifact_content(text, render_family, renderer)
    full_href = _artifact_href(root, relative_path)
    fallback.update(
        {
            "renderer": renderer,
            "rendered_bytes": len(data),
            "line_count": line_count,
            "truncated": truncated,
        }
    )
    fallback["html"] = SafeHtml(
        "<article class='goal-artifact-preview' data-goal-artifact-preview='true' "
        f"data-goal-artifact-reader-path='{_e(relative_path)}' "
        f"data-goal-artifact-reader-label='{_e(record['label'])}' "
        f"data-goal-artifact-reader-kind='{_e(record['kind'])}' "
        f"data-goal-artifact-reader-source='{_e(record['source'])}' "
        f"data-goal-artifact-reader-renderer='{_e(renderer)}' "
        f"data-goal-artifact-reader-bytes='{_e(str(len(data)))}' "
        f"data-goal-artifact-reader-lines='{_e(str(line_count))}' "
        f"data-goal-artifact-reader-truncated='{str(truncated).lower()}'"
        f"{hidden_attr}>"
        "<div class='goal-artifact-preview-header'>"
        f"<h4>{_e(record['label'])}</h4>"
        f"<a class='goal-artifact-reader-open-inline' href='{_e(full_href)}'>Open full artifact</a>"
        "</div>"
        + _kv(
            [
                ("reader_artifact_path", relative_path),
                ("reader_artifact_kind", record["kind"]),
                ("reader_artifact_source", record["source"]),
                ("reader_artifact_renderer", renderer),
                ("reader_artifact_bytes", str(len(data))),
                ("reader_artifact_line_count", str(line_count)),
                ("reader_artifact_truncated", str(truncated).lower()),
            ]
        )
        + rendered
        + ("<p class='muted'>Preview truncated. Open the full artifact for complete content.</p>" if truncated else "")
        + "</article>"
    )
    return fallback


def _goal_artifact_records(root: Path, state: dict[str, Any]) -> list[dict[str, str]]:
    records: list[dict[str, str]] = []
    seen: set[tuple[str, str]] = set()

    def add(label: str, path: str | Path | None, *, source: str) -> None:
        relative_path = _repo_relative_artifact_path(root, path)
        if not relative_path or relative_path == "none":
            return
        kind = _goal_artifact_render_kind(relative_path)
        if kind is None:
            return
        try:
            resolve_artifact_path(root, relative_path)
        except ValueError:
            return
        key = (label, relative_path)
        if key in seen:
            return
        seen.add(key)
        records.append(
            {
                "label": label,
                "path": relative_path,
                "kind": kind,
                "status": _artifact_status(root, relative_path),
                "source": source,
            }
        )

    for task in state["tasks"]:
        for artifact in task.artifacts:
            add(f"task {task.id}", artifact, source="task")
    for row in state["runs"]:
        for label, key in [
            ("run summary", "summary_path"),
            ("run activity", "activity_path"),
            ("run events", "events_path"),
        ]:
            add(f"{label} {row['id']}", row[key], source="run")
    for incident in state["incidents"]:
        add(f"incident {incident['id']}", incident["evidence_path"], source="incident")
    for recommendation in state["recommendations"]:
        add(f"recommendation {recommendation['id']}", recommendation["evidence_path"], source="recommendation")
    for delegation in state["delegations"]:
        metadata = load_delegation_result_metadata(delegation)
        add(f"delegation {delegation.id} result", delegation.result_artifact_path, source="delegation")
        for key in [
            "context_pack_json",
            "context_pack_md",
            "implementation_handoff_json",
            "implementation_handoff_md",
        ]:
            if metadata.get(key):
                add(key, str(metadata[key]), source="delegation_metadata")
    for packet in state["prep_packets"]:
        _add_packet_artifacts(add, packet, source="coder_prep")
    for packet in state["worktree_plans"]:
        _add_packet_artifacts(add, packet, source="worktree_plan")
    for run in state["worktree_runs"]:
        evidence_path = Path(run.evidence_path)
        add(f"coder run {run.id} review", Path("runs") / run.source_run_id / "review.md", source="coder_run")
        for label, path in [
            ("run json", evidence_path / "run.json"),
            ("diff", evidence_path / "diff.patch"),
            ("changed files", evidence_path / "changed_files.json"),
            ("bounded file validation", evidence_path / "bounded_file_validation.json"),
            ("git status", evidence_path / "git_status.txt"),
            ("stdout", evidence_path / "stdout.txt"),
            ("stderr", evidence_path / "stderr.txt"),
            ("verification stdout", evidence_path / "verification_stdout.txt"),
            ("verification stderr", evidence_path / "verification_stderr.txt"),
        ]:
            add(f"coder run {run.id} {label}", path, source="coder_run")
    for approval in state["commit_approvals"]:
        for label, path in [
            ("commit_request", approval.request_artifact_path),
            ("commit_decision", approval.decision_artifact_path),
            ("commit_artifact", approval.commit_artifact_path),
        ]:
            add(label, path, source="commit")
    for publication in state["publications"]:
        for label, path in [
            ("publication_request", publication.request_artifact_path),
            ("publication_decision", publication.decision_artifact_path),
            ("publication_handoff", publication.handoff_artifact_path),
        ]:
            add(label, path, source="publication")
    return records


def _goal_latest_artifact_path(root: Path, state: dict[str, Any]) -> str:
    records = _goal_artifact_records(root, state)
    existing = [
        record
        for record in records
        if (root / record["path"]).exists()
    ]
    if not existing:
        note_path = _goal_operator_notes_path(state["goal"])
        if (root / note_path).exists():
            return note_path.as_posix()
        return ""
    latest = max(
        existing,
        key=lambda record: (root / record["path"]).stat().st_mtime,
    )
    return latest["path"]


def _add_packet_artifacts(
    add: Any,
    packet: dict[str, Any],
    *,
    source: str,
) -> None:
    kind = str(packet.get("kind", source))
    add(kind, packet.get("_path") or packet.get("artifacts", {}).get("json"), source=source)
    artifacts = packet.get("artifacts") if isinstance(packet.get("artifacts"), dict) else {}
    for label, path in artifacts.items():
        add(f"{kind}_{label}", path, source=source)


def _goal_artifact_render_kind(path: str) -> str | None:
    suffix = Path(path).suffix.lower()
    if suffix == ".md":
        return "markdown"
    if suffix == ".json":
        return "json"
    if suffix in {".patch", ".diff"}:
        return "patch"
    if suffix in {".txt", ".log"}:
        return "text"
    return None


def _goal_memory_lines(root: Path, state: dict[str, Any]) -> list[str]:
    storage = _storage(root)
    goal = state["goal"]
    project_memory = Path("projects") / goal.project_id / "knowledge.md"
    global_memory = Path("knowledge.md")
    operator_notes = Path(".clanker") / "projects" / goal.project_id / "goals" / goal.id / "operator-notes.md"
    project_entries = storage.list_memory_entries(project_id=goal.project_id, limit=100)
    global_entries = [
        entry for entry in storage.list_memory_entries(limit=100) if entry.scope == "global"
    ]
    generated_entries = [
        entry for entry in project_entries if entry.source_type != "operator"
    ]
    active_entries = [entry for entry in project_entries if entry.status == "active"]
    proposed_entries = [entry for entry in project_entries if entry.status == "proposed"]
    future_work = [row for row in state["recommendations"] if row["status"] == "open"]
    latest_generated = generated_entries[0] if generated_entries else None
    latest_project_entry = project_entries[0] if project_entries else None
    operator_note_status = "available" if (root / operator_notes).exists() else "not_started"
    return [
        "memory_surface: <a href='/memory'>/memory</a>",
        f"goal_memory_project_id: {_e(goal.project_id)}",
        f"project_memory: {_artifact_link(project_memory.as_posix()) if (root / project_memory).exists() else 'missing'}",
        f"global_memory: {_artifact_link(global_memory.as_posix()) if (root / global_memory).exists() else 'missing'}",
        f"operator_notes: {_artifact_link(operator_notes.as_posix()) if operator_note_status == 'available' else 'not_started'}",
        f"operator_notes_status: {operator_note_status}",
        f"goal_memory_project_entries: {len(project_entries)}",
        f"goal_memory_active_entries: {len(active_entries)}",
        f"goal_memory_proposed_entries: {len(proposed_entries)}",
        f"goal_memory_global_entries: {len(global_entries)}",
        f"goal_generated_memory_count: {len(generated_entries)}",
        f"goal_future_work_count: {len(future_work)}",
        f"latest_project_memory: {_goal_memory_entry_summary(latest_project_entry)}",
        f"latest_generated_memory: {_goal_memory_entry_summary(latest_generated)}",
        "pin_memory_action: available_on_memory_page",
        "pin_memory_from_goal_page=false",
        "goal_memory_external_effects_created=false",
    ]


def _goal_memory_section(root: Path, state: dict[str, Any]) -> str:
    lines = _goal_memory_lines(root, state)
    return _goal_memory_command_bar(root, state, lines) + _collapsible_list_section(
        "Memory",
        lines,
        anchor_id="goal-memory",
        details_class="goal-memory-list",
        data_attr="goal-memory-list",
        summary=f"Detailed memory readback ({len(lines)})",
    )


def _goal_memory_command_bar(
    root: Path,
    state: dict[str, Any],
    memory_lines: list[str],
) -> str:
    storage = _storage(root)
    goal = state["goal"]
    project_memory = Path("projects") / goal.project_id / "knowledge.md"
    global_memory = Path("knowledge.md")
    operator_notes = _goal_operator_notes_path(goal)
    project_entries = storage.list_memory_entries(project_id=goal.project_id, limit=100)
    global_entries = [
        entry for entry in storage.list_memory_entries(limit=100) if entry.scope == "global"
    ]
    generated_entries = [
        entry for entry in project_entries if entry.source_type != "operator"
    ]
    active_entries = [entry for entry in project_entries if entry.status == "active"]
    proposed_entries = [entry for entry in project_entries if entry.status == "proposed"]
    future_work = [row for row in state["recommendations"] if row["status"] == "open"]
    operator_note_status = "available" if (root / operator_notes).exists() else "not_started"
    latest_project_entry = project_entries[0] if project_entries else None
    latest_generated = generated_entries[0] if generated_entries else None
    project_memory_status = "available" if (root / project_memory).exists() else "missing"
    global_memory_status = "available" if (root / global_memory).exists() else "missing"
    project_memory_surface = (
        _artifact_link(project_memory.as_posix())
        if project_memory_status == "available"
        else "missing"
    )
    global_memory_surface = (
        _artifact_link(global_memory.as_posix())
        if global_memory_status == "available"
        else "missing"
    )
    operator_notes_surface = (
        _artifact_link(operator_notes.as_posix())
        if operator_note_status == "available"
        else SafeHtml("<a href='#goal-operator-notes'>Goal Operator Notes</a>")
    )
    first_target = "none"
    next_action = "Capture operator note"
    target_href = "#goal-operator-notes"
    target_label = "Goal Operator Notes"
    reason = "goal_memory_empty_and_operator_note_not_started"
    if proposed_entries:
        first_target = proposed_entries[0].id
        next_action = "Review proposed memory"
        target_href = "/memory#memory-proposed"
        target_label = "/memory#memory-proposed"
        reason = "proposed_goal_memory_waiting_for_operator"
    elif active_entries:
        first_target = active_entries[0].id
        next_action = "Review active goal memory"
        target_href = "/memory#memory-project"
        target_label = "/memory#memory-project"
        reason = "active_goal_memory_available"
    elif operator_note_status == "available":
        first_target = operator_notes.as_posix()
        next_action = "Review operator notes"
        target_href = _artifact_href(root, operator_notes)
        target_label = "operator-notes.md"
        reason = "goal_operator_notes_available"
    elif future_work:
        first_target = str(future_work[0]["id"])
        next_action = "Review future work"
        target_href = "/memory#memory-future-work"
        target_label = "/memory#memory-future-work"
        reason = "open_goal_recommendations_available"
    elif generated_entries:
        first_target = generated_entries[0].id
        next_action = "Review generated memory"
        target_href = "/memory#memory-generated"
        target_label = "/memory#memory-generated"
        reason = "generated_goal_memory_available"
    elif project_entries:
        first_target = project_entries[0].id
        next_action = "Review project memory"
        target_href = "/memory#memory-project"
        target_label = "/memory#memory-project"
        reason = "project_memory_records_available"
    elif global_entries:
        first_target = global_entries[0].id
        next_action = "Review global memory"
        target_href = "/memory#memory-global"
        target_label = "/memory#memory-global"
        reason = "global_memory_records_available"

    if proposed_entries:
        status = "proposed_memory_pending"
    elif active_entries or project_entries or generated_entries or global_entries:
        status = "memory_available"
    elif operator_note_status == "available":
        status = "operator_notes_available"
    elif future_work:
        status = "future_work_available"
    else:
        status = "empty"

    target_surface = SafeHtml(f"<a href='{_e(target_href)}'>{_e(target_label)}</a>")
