def _goal_task_closeout_candidate(root: Path, state: dict[str, Any]) -> dict[str, str]:
    goal = state.get("goal")
    if goal is None:
        return _goal_task_closeout_candidate_record(status="goal_not_found")
    open_tasks = [task for task in state["tasks"] if task.status != "completed"]
    if not open_tasks:
        return _goal_task_closeout_candidate_record(
            status="no_open_tasks",
            goal_id=goal.id,
            project_id=goal.project_id,
            reason="all task rows are already completed",
            target_href="#goal-progress-command-bar",
            target_label="Review progress",
        )
    task = _goal_task_closeout_task(state, open_tasks)
    delegations = [
        delegation
        for delegation in state["delegations"]
        if delegation.parent_task_id == task.id
    ]
    delegation = delegations[0] if delegations else None
    plan_step = state.get("plan_steps")
    linked_step = next(
        (
            step
            for step in (plan_step or [])
            if getattr(step, "task_id", None) == task.id
        ),
        None,
    )
    publication = _goal_ready_publication(state)
    artifacts = _goal_task_closeout_artifacts(root, state, task, publication)
    base = {
        "goal_id": goal.id,
        "project_id": goal.project_id,
        "task_id": task.id,
        "task_status": task.status,
        "task_description": task.description,
        "open_tasks": str(len(open_tasks)),
        "delegation_id": delegation.id if delegation is not None else "none",
        "run_id": getattr(publication, "run_id", None) or _goal_task_closeout_run_id(state),
        "publication_id": getattr(publication, "id", "none") if publication is not None else "none",
        "publication_status": getattr(publication, "status", "none") if publication is not None else "none",
        "artifact_count": str(len(artifacts)),
        "first_artifact": artifacts[0] if artifacts else "none",
        "artifacts_joined": "|".join(artifacts),
        "plan_step_id": linked_step.id if linked_step is not None else "none",
        "plan_step_status": linked_step.status if linked_step is not None else "none",
    }
    if delegation is None:
        return _goal_task_closeout_candidate_record(
            **base,
            status="waiting_for_task_delegation",
            reason="the first open task has no linked workflow delegation yet",
            target_href="#goal-next-action",
            target_label="Continue workflow",
        )
    if publication is None and goal.status != "completed":
        return _goal_task_closeout_candidate_record(
            **base,
            status="waiting_for_publication_handoff",
            reason="publication handoff evidence is not ready yet",
            target_href="#goal-next-action",
            target_label="Continue workflow",
        )
    if not artifacts:
        return _goal_task_closeout_candidate_record(
            **base,
            status="missing_closeout_artifacts",
            reason="ready state exists but no local closeout artifacts were found",
            target_href="#goal-evidence",
            target_label="Inspect evidence",
        )
    return _goal_task_closeout_candidate_record(
        **base,
        status="ready_to_close_task",
        reason="ready publication handoff evidence can close this task row",
        target_href="#goal-task-closeout-form",
        target_label="Close task from evidence",
        form_available="true",
    )


def _goal_task_closeout_candidate_record(**overrides: str) -> dict[str, str]:
    record = {
        "status": "not_ready",
        "reason": "task closeout is not ready",
        "goal_id": "none",
        "project_id": "none",
        "task_id": "none",
        "task_status": "none",
        "task_description": "none",
        "open_tasks": "0",
        "delegation_id": "none",
        "run_id": "none",
        "publication_id": "none",
        "publication_status": "none",
        "artifact_count": "0",
        "first_artifact": "none",
        "artifacts_joined": "",
        "plan_step_id": "none",
        "plan_step_status": "none",
        "target_href": "#goal-remaining-work",
        "target_label": "Review remaining work",
        "form_available": "false",
    }
    record.update({key: str(value) for key, value in overrides.items()})
    return record


def _goal_task_closeout_task(state: dict[str, Any], open_tasks: list[Any]) -> Any:
    delegated_task_ids = {
        delegation.parent_task_id
        for delegation in state["delegations"]
        if getattr(delegation, "parent_task_id", None)
    }
    return next(
        (task for task in open_tasks if task.id in delegated_task_ids),
        open_tasks[0],
    )


def _goal_task_closeout_run_id(state: dict[str, Any]) -> str:
    run = next(
        (item for item in state.get("worktree_runs", []) if item.status == "completed"),
        None,
    )
    if run is not None:
        return run.id
    run_row = next((row for row in state.get("runs", []) if row["status"] == "completed"), None)
    return str(run_row["id"]) if run_row is not None else "none"


def _goal_task_closeout_artifacts(
    root: Path,
    state: dict[str, Any],
    task: Any,
    publication: Any | None,
) -> list[str]:
    artifacts: list[str] = []

    def add(path: str | Path | None) -> None:
        if not path:
            return
        relative = _repo_relative_artifact_path(root, path)
        if relative == "none" or relative in artifacts:
            return
        candidate = root / relative
        if candidate.exists():
            artifacts.append(relative)

    for artifact in getattr(task, "artifacts", []) or []:
        add(artifact)
    if publication is not None:
        handoff = getattr(publication, "handoff_artifact_path", None)
        add(handoff)
        if handoff:
            handoff_path = Path(str(handoff))
            add(handoff_path.with_suffix(".md"))
            add(handoff_path.parent / "pr_body.md")
        add(getattr(publication, "request_artifact_path", None))
        request_path = getattr(publication, "request_artifact_path", None)
        if request_path:
            add(Path(str(request_path)).with_suffix(".md"))
        add(getattr(publication, "decision_artifact_path", None))
        decision_path = getattr(publication, "decision_artifact_path", None)
        if decision_path:
            add(Path(str(decision_path)).with_suffix(".md"))
    for run in state.get("worktree_runs", []):
        if run.status != "completed":
            continue
        evidence_path = getattr(run, "evidence_path", None)
        add(evidence_path)
        if evidence_path:
            add(Path(str(evidence_path)) / "summary.md")
    return artifacts


def _goal_remaining_work_command_bar(
    root: Path,
    state: dict[str, Any],
    next_action: GoalNextAction,
    remaining_lines: list[str],
) -> str:
    goal = state["goal"]
    gates, counts, current_gate = _goal_workflow_gate_summary(root, state, next_action)
    total_gates = len(gates)
    done_gates = counts.get("done", 0)
    pending_gates = counts.get("pending", 0)
    waiting_gates = counts.get("waiting", 0)
    open_tasks = [task for task in state["tasks"] if task.status != "completed"]
    open_incidents = [row for row in state["incidents"] if row["status"] == "open"]
    open_recommendations = [
        row for row in state["recommendations"] if row["status"] == "open"
    ]
    pending_approvals = (
        _count_status(state["worktree_approvals"], "pending_operator_approval")
        + _count_status(state["commit_approvals"], "pending_operator_approval")
        + _count_status(state["publications"], "pending_operator_approval")
    )
    first_open_task = open_tasks[0].id if open_tasks else "none"
    if goal.status == "completed":
        status = "completed"
        reason = "goal_status_completed"
    elif open_incidents:
        status = "blocked_by_incidents"
        reason = "open_incidents"
    elif pending_gates:
        status = "pending_gate"
        reason = f"current_gate={current_gate}"
    elif pending_approvals:
        status = "waiting_for_operator_approval"
        reason = "pending_approvals"
    elif waiting_gates:
        status = "waiting_for_upstream_gate"
        reason = f"current_gate={current_gate}"
    else:
        status = "ready_for_completion_review"
        reason = "no_pending_or_waiting_gates"
    form_available = bool(_goal_next_action_form(state, next_action))
    primary_href = _goal_primary_action_href(
        state,
        next_action,
        form_available=form_available,
    )
    primary_label = _goal_action_cta_label(
        next_action,
        form_available,
        fallback="Open next surface",
    )
    waiting_total = len(open_incidents) + len(open_recommendations) + pending_approvals
    if pending_approvals:
        waiting_href = f"/approvals?goal_id={quote(goal.id)}"
        waiting_label = "Review approvals"
    elif open_incidents:
        waiting_href = "/incidents"
        waiting_label = "Inspect incidents"
    elif open_recommendations:
        target = _goal_recommendation_target(goal, open_recommendations[0])
        waiting_href = target.href
        waiting_label = target.action
    else:
        waiting_href = "#goal-remaining-work"
        waiting_label = "Review gates"
    finish_label = (
        "Completion readiness"
        if status == "ready_for_completion_review"
        else "Review finish posture"
    )
    target_surface = SafeHtml(
        f"<a href='{_e(next_action.href)}'>{_e(next_action.href)}</a>"
    )
    primary_surface = SafeHtml(
        f"<a href='{_e(primary_href)}'>{_e(primary_label)}</a>"
    )
    action_cards = "".join(
        [
            "<div class='goal-remaining-work-card goal-remaining-work-primary' data-goal-remaining-work-now='true'>",
            "<h3>Now</h3>",
            f"<strong>{_e(next_action.action)}</strong>",
            f"<p>{_e(current_gate)} gate is {_e(status.replace('_', ' '))}.</p>",
            f"<a class='goal-remaining-work-action' href='{_e(primary_href)}'>{_e(primary_label)}</a>",
            "</div>",
            "<div class='goal-remaining-work-card' data-goal-remaining-work-progress='true'>",
            "<h3>Gate Progress</h3>",
            f"<strong>{done_gates}/{total_gates} done</strong>",
            f"<p>{pending_gates} pending; {waiting_gates} waiting.</p>",
            "<a class='goal-remaining-work-link' href='#goal-workflow-map'>Workflow map</a>",
            "</div>",
            "<div class='goal-remaining-work-card' data-goal-remaining-work-waiting='true'>",
            "<h3>Waiting</h3>",
            f"<strong>{waiting_total} item(s)</strong>",
            f"<p>{pending_approvals} approvals; {len(open_incidents)} incidents; {len(open_recommendations)} recommendations.</p>",
            f"<a class='goal-remaining-work-link' href='{_e(waiting_href)}'>{_e(waiting_label)}</a>",
            "</div>",
            "<div class='goal-remaining-work-card' data-goal-remaining-work-open='true'>",
            "<h3>Open Work</h3>",
            f"<strong>{len(open_tasks)} task(s)</strong>",
            f"<p>First open task: {_e(first_open_task)}.</p>",
            "<a class='goal-remaining-work-link' href='#goal-remaining-work'>Checklist</a>",
            "</div>",
            "<div class='goal-remaining-work-card' data-goal-remaining-work-finish='true'>",
            "<h3>Finish</h3>",
            f"<strong>{_e(finish_label)}</strong>",
            "<p>Confirm the manual publish boundary before completion.</p>",
            "<a class='goal-remaining-work-link' href='#goal-completion-readiness'>Completion readiness</a>",
            "</div>",
        ]
    )
    return "".join(
        [
            "<section id='goal-remaining-work-command-bar' class='panel goal-remaining-work-command-bar' data-goal-remaining-work-command-bar='true'><h3>Goal Remaining Work Command Bar</h3>",
            "<p class='muted'>Gate and queue posture before the detailed remaining-work checklist.</p>",
            "<div class='goal-remaining-work-grid' data-goal-remaining-work-actions='true'>",
            action_cards,
            "</div>",
            "<details class='goal-remaining-work-evidence' data-goal-remaining-work-evidence='true'><summary>Goal remaining work evidence</summary>",
            _kv(
                [
                    ("goal_remaining_work_command_goal", goal.id),
                    ("goal_remaining_work_command_project", goal.project_id),
                    ("goal_remaining_work_command_status", status),
                    ("goal_remaining_work_command_items", str(len(remaining_lines))),
                    ("goal_remaining_work_command_current_gate", current_gate),
                    ("goal_remaining_work_command_gate_progress", f"{done_gates}/{total_gates} gates done"),
                    ("goal_remaining_work_command_done_gates", str(done_gates)),
                    ("goal_remaining_work_command_pending_gates", str(pending_gates)),
                    ("goal_remaining_work_command_waiting_gates", str(waiting_gates)),
                    ("goal_remaining_work_command_open_tasks", str(len(open_tasks))),
                    ("goal_remaining_work_command_first_open_task", first_open_task),
                    ("goal_remaining_work_command_open_incidents", str(len(open_incidents))),
                    ("goal_remaining_work_command_open_recommendations", str(len(open_recommendations))),
                    ("goal_remaining_work_command_pending_approvals", str(pending_approvals)),
                    ("goal_remaining_work_command_next_action", next_action.action),
                    ("goal_remaining_work_command_primary_surface", primary_surface),
                    ("goal_remaining_work_command_action_form_available", str(form_available).lower()),
                    ("goal_remaining_work_command_target_surface", target_surface),
                    ("goal_remaining_work_command_reason", reason),
                    ("goal_remaining_work_command_source", "goal_remaining_work_gates"),
                    ("goal_remaining_work_command_waiting_items", str(waiting_total)),
                    ("goal_remaining_work_command_waiting_surface", SafeHtml(f"<a href='{_e(waiting_href)}'>{_e(waiting_label)}</a>")),
                    (
                        "goal_remaining_work_command_completion_surface",
                        SafeHtml("<a href='#goal-completion-readiness'>Completion readiness</a>"),
                    ),
                    ("goal_remaining_work_command_write_on_get", "false"),
                    ("goal_remaining_work_command_provider_calls_taken", "0"),
                    ("goal_remaining_work_command_network_actions_taken", "0"),
                    ("goal_remaining_work_command_external_effects_created", "false"),
                ]
            ),
            _ul(
                [
                    f"goal_remaining_work_now: {_e(next_action.action)}",
                    f"goal_remaining_work_primary: <a href='{_e(primary_href)}'>{_e(primary_label)}</a>",
                    f"goal_remaining_work_click: {target_surface}",
                    f"goal_remaining_work_gate: {_e(current_gate)} status={_e(status)}",
                    f"goal_remaining_work_waiting: approvals={pending_approvals} incidents={len(open_incidents)} recommendations={len(open_recommendations)}",
                    "goal_remaining_work_safety: read-only local gate posture",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _goal_remaining_work_lines(
    root: Path,
    state: dict[str, Any],
    next_action: GoalNextAction,
) -> list[str]:
    tasks = [task for task in state["tasks"] if task.status != "completed"]
    open_incidents = [row for row in state["incidents"] if row["status"] == "open"]
    open_recommendations = [
        row for row in state["recommendations"] if row["status"] == "open"
    ]
    gate_lines = _goal_remaining_work_gate_lines(root, state, next_action)
    lines = [
        "remaining_work_source: goal_state_workflow_gates",
        f"remaining_work_next_action: {_e(next_action.action)}",
        f"remaining_work_next_surface: {_e(next_action.href)}",
        f"remaining_work_open_tasks: {len(tasks)}",
        f"remaining_work_open_incidents: {len(open_incidents)}",
        f"remaining_work_open_recommendations: {len(open_recommendations)}",
        "remaining_work_external_effects_created: false",
    ]
    lines.extend(
        f"remaining_work_open_task: {_e(task.id)} status={_e(task.status)} type={_e(task.task_type)}"
        for task in tasks[:10]
    )
    lines.extend(gate_lines)
    if not tasks and next_action.action == "Manual publish outside ClankerOS":
        lines.append("manual publication remains outside ClankerOS")
    if not tasks and not any("status=pending" in line for line in gate_lines):
        lines.append("no open task rows; inspect timeline and evidence before marking complete")
    return lines


def _goal_remaining_work_gate_lines(
    root: Path,
    state: dict[str, Any],
    next_action: GoalNextAction,
) -> list[str]:
    delegations = state["delegations"]
    has_delegation = bool(delegations)
    has_context_pack = any(
        _delegation_has_context_pack(
            root,
            delegation,
            load_delegation_result_metadata(delegation),
        )
        for delegation in delegations
    )
    completed_delegation = any(
        delegation.status == "completed" for delegation in delegations
    )
    has_handoff = any(
        _goal_delegation_has_handoff(state, delegation) for delegation in delegations
    )
    has_prep = bool(state["prep_packets"])
    has_worktree_plan = bool(state["worktree_plans"])
    worktree_pending = _count_status(
        state["worktree_approvals"],
        "pending_operator_approval",
    )
    worktree_approved = _count_status(state["worktree_approvals"], "approved")
    has_completed_run = any(run.status == "completed" for run in state["worktree_runs"])
    has_running_run = any(run.status == "running" for run in state["worktree_runs"])
    has_review = any(
        run.status == "completed"
        and _run_review_gate_state(root, run).get("commit_request_form_available")
        for run in state["worktree_runs"]
    )
    commit_pending = _count_status(state["commit_approvals"], "pending_operator_approval")
    commit_approved = _count_status(state["commit_approvals"], "approved")
    has_local_commit = _count_status(state["commit_approvals"], "committed") > 0
    publication_pending = _count_status(
        state["publications"],
        "pending_operator_approval",
    )
    publication_approved = _count_status(state["publications"], "approved")
    publication_ready = _count_status(state["publications"], "ready_for_operator")
    has_publication_request = bool(state["publications"])

    gates: list[tuple[str, str, str, str]] = []

    def add(name: str, status: str, *, next_step: str = "", detail: str = "") -> None:
        gates.append((name, status, next_step, detail))

    def pending_if_ready(done: bool, ready: bool, next_step: str) -> str:
        if done:
            return "done"
        if ready or next_action.action == next_step:
            return "pending"
        return "waiting"

    add(
        "scout_delegation",
        pending_if_ready(
            has_delegation,
            bool(state["tasks"]),
            "Create scout delegation",
        ),
        next_step="Create scout delegation",
        detail=f"delegations={len(delegations)}",
    )
    add(
        "context_pack",
        pending_if_ready(has_context_pack, has_delegation, "Generate context pack"),
        next_step="Generate context pack",
    )
    add(
        "implementation_handoff",
        pending_if_ready(
            has_handoff,
            has_context_pack or completed_delegation,
            "Run delegation",
        ),
        next_step="Run delegation",
        detail=(
            "completed_delegations="
            f"{sum(1 for delegation in delegations if delegation.status == 'completed')}"
        ),
    )
    add(
        "coder_prep",
        pending_if_ready(has_prep, has_handoff, "Run coder prep"),
        next_step="Run coder prep",
    )
    add(
        "worktree_plan",
        pending_if_ready(has_worktree_plan, has_prep, "Create worktree plan"),
        next_step="Create worktree plan",
    )
    add(
        "worktree_approval",
        pending_if_ready(
            worktree_approved > 0 or has_completed_run or has_running_run,
            has_worktree_plan,
            "Request worktree approval",
        ),
        next_step="Request worktree approval",
        detail=f"pending={worktree_pending} approved={worktree_approved}",
    )
    add(
        "worktree_run",
        pending_if_ready(
            has_completed_run,
            worktree_approved > 0 or has_running_run,
            "Run approved worktree",
        ),
        next_step="Run approved worktree",
        detail=(
            f"running={sum(1 for run in state['worktree_runs'] if run.status == 'running')} "
            f"completed={sum(1 for run in state['worktree_runs'] if run.status == 'completed')}"
        ),
    )
    add(
        "review",
        pending_if_ready(has_review, has_completed_run, "Open review"),
        next_step="Open review",
    )
    add(
        "commit_request",
        pending_if_ready(
            bool(state["commit_approvals"]),
            has_review,
            "Create commit request",
        ),
        next_step="Create commit request",
        detail=f"requests={len(state['commit_approvals'])}",
    )
    add(
        "commit_approval",
        pending_if_ready(
            commit_approved > 0 or has_local_commit,
            commit_pending > 0,
            "Approve commit",
        ),
        next_step="Approve commit",
        detail=f"pending={commit_pending} approved={commit_approved}",
    )
    add(
        "local_commit",
        pending_if_ready(has_local_commit, commit_approved > 0, "Commit approved worktree"),
        next_step="Commit approved worktree",
    )
    add(
        "publication_request",
        pending_if_ready(
            has_publication_request,
            has_local_commit,
            "Create publication request",
        ),
        next_step="Create publication request",
        detail=f"requests={len(state['publications'])}",
    )
    add(
        "publication_approval",
        pending_if_ready(
            publication_approved > 0 or publication_ready > 0,
            publication_pending > 0,
            "Approve publication",
        ),
        next_step="Approve publication",
        detail=f"pending={publication_pending} approved={publication_approved}",
    )
    add(
        "publication_handoff",
        pending_if_ready(publication_ready > 0, publication_approved > 0, "Create publication handoff"),
        next_step="Create publication handoff",
        detail=f"ready_for_operator={publication_ready}",
    )
    add(
        "manual_publish",
        (
            "done"
            if state["goal"].status == "completed"
            else ("pending" if publication_ready > 0 else "waiting")
        ),
        next_step="Manual publish outside ClankerOS",
        detail="outside_clankeros=true",
    )

    counts: dict[str, int] = {}
    for _, status, _, _ in gates:
        counts[status] = counts.get(status, 0) + 1
    lines = [
        "remaining_work_gate_counts: "
        + " ".join(
            f"{status}={counts.get(status, 0)}"
            for status in ["done", "pending", "waiting"]
        )
    ]
    for name, status, next_step, detail in gates:
        parts = [f"remaining_work_gate: {name}", f"status={status}"]
        if status == "pending" and next_step:
            parts.append(f"next={_e(next_step)}")
        if detail:
            parts.append(f"detail={_e(detail)}")
        lines.append(" ".join(parts))
    return lines


def _highest_risk(risks: list[str]) -> str:
    order = {"low": 1, "medium": 2, "high": 3}
    if not risks:
        return "unknown"
    return max(risks, key=lambda value: order.get(value, 0))


def _risk_counts(tasks: list[Any]) -> dict[str, int]:
    counts: dict[str, int] = {}
    for task in tasks:
        risk = str(getattr(task, "risk_level", "") or "unknown")
        counts[risk] = counts.get(risk, 0) + 1
    return counts


def _risk_counts_label(counts: dict[str, int]) -> str:
    if not counts:
        return "none"
    order = ["unknown", "high", "medium", "low"]
    labels = [
        f"{risk}={counts[risk]}"
        for risk in order
        if risk in counts
    ]
    labels.extend(
        f"{risk}={count}"
        for risk, count in sorted(counts.items())
        if risk not in order
    )
    return ",".join(labels)


def _criteria_items(text: str) -> list[str]:
    items: list[str] = []
    for line in text.splitlines():
        stripped = line.strip()
        if not stripped:
            continue
        if stripped.startswith("- "):
            stripped = stripped[2:].strip()
        items.append(stripped)
    return items


def _task_completion_items(tasks: list[Any]) -> list[dict[str, str]]:
    items: list[dict[str, str]] = []
    for task in tasks:
        verification_plan = getattr(task, "verification_plan", {}) or {}
        acceptance = str(
            verification_plan.get("acceptance_criteria")
            or verification_plan.get("expected")
            or task.description
        ).strip()
        if not acceptance:
            continue
        items.append(
            {
                "task_id": task.id,
                "status": task.status,
                "acceptance": acceptance,
            }
        )
    return items


def _goal_delegation_has_handoff(state: dict[str, Any], delegation: Any) -> bool:
    metadata = load_delegation_result_metadata(delegation)
    return bool(metadata.get("implementation_handoff_md") or metadata.get("implementation_handoff_json"))


def _workflow(
    root: Path,
    *,
    delegation_id: str | None = None,
    run_id: str | None = None,
) -> str:
    selected_statuses = _workflow_step_statuses(
        root,
        delegation_id=delegation_id,
        run_id=run_id,
    )
    return "".join(
        [
            "<section><h1>Modern Operator Workflow</h1>",
            _non_claim_banner(),
            _workflow_operator_workbench(
                root,
                delegation_id=delegation_id,
                run_id=run_id,
            ),
            _workflow_scope_picker(root, delegation_id=delegation_id, run_id=run_id),
            _workflow_journey(root, delegation_id=delegation_id, run_id=run_id),
            _workflow_live_state(root, delegation_id=delegation_id, run_id=run_id),
            _workflow_finish_today(root, delegation_id=delegation_id, run_id=run_id),
            _workflow_command_bar(root, delegation_id=delegation_id, run_id=run_id),
            _selected_workflow_state(root, delegation_id=delegation_id, run_id=run_id),
            _selected_workflow_continuation(
                root,
                delegation_id=delegation_id,
                run_id=run_id,
            ),
            "<section id='workflow-stepper' data-workflow-stepper='true'><h2>Workflow Stepper</h2>",
            _workflow_list(compact=False, selected_statuses=selected_statuses),
            "</section>",
            "</section>",
        ]
    )


def _workflow_operator_context(
    root: Path,
    *,
    delegation_id: str | None = None,
    run_id: str | None = None,
) -> dict[str, Any]:
    selected_statuses = _workflow_step_statuses(
        root,
        delegation_id=delegation_id,
        run_id=run_id,
    )
    base: dict[str, Any] = {
        "status": "no_selection",
        "scope": "all",
        "delegation_id": "none",
        "delegation_surface": SafeHtml("<a href='/delegation-runs'>/delegation-runs</a>"),
        "run_id": "none",
        "run_surface": SafeHtml("<a href='/delegation-runs'>/delegation-runs</a>"),
        "goal_id": "none",
        "goal_surface": SafeHtml("<a href='/goals'>/goals</a>"),
        "project": "none",
        "current_stage": "overview",
        "next_action": "Select delegation or run",
        "target_href": "/delegation-runs",
        "target_label": "/delegation-runs",
        "reason": "select a workflow scope to continue",
        "primary_summary": "Choose the delegation or coder run you want to continue.",
        "state_href": "#workflow-stepper",
        "state_label": "Workflow Stepper",
        "queue_href": "/delegation-runs",
        "queue_label": "Delegation Runs",
        "resume_href": "/goals",
        "resume_label": "/goals",
        "finish_href": "#workflow-finish-today",
        "finish_label": "Finish Today",
        "resume_surface": "/workflow",
        "last_artifact": "",
        "selected_step_count": str(len(selected_statuses)),
        "selected_status_count": str(len(selected_statuses)),
    }
    if not delegation_id and not run_id:
        return base

    storage = _storage(root)
    selected_run = get_coder_worktree_run(storage, run_id) if run_id else None
    if run_id and selected_run is None:
        return {
            **base,
            "status": "run_not_found",
            "scope": "run",
            "run_id": run_id,
            "run_surface": SafeHtml(f"<a href='/delegation-runs'>{_e(run_id)}</a>"),
            "current_stage": "select_run",
            "next_action": "Open delegation runs",
            "reason": "selected run was not found",
            "primary_summary": "The selected run is not available in local state.",
            "resume_surface": f"/workflow?run_id={quote(run_id)}",
            "selected_step_count": str(len(selected_statuses)),
            "selected_status_count": str(len(selected_statuses)),
        }

    if selected_run is not None:
        delegation_id = selected_run.delegation_id

    delegation = storage.get_subagent_delegation(delegation_id or "")
    if delegation_id and delegation is None:
        return {
            **base,
            "status": "delegation_not_found",
            "scope": "delegation",
            "delegation_id": delegation_id,
            "delegation_surface": SafeHtml(f"<a href='/delegation-runs'>{_e(delegation_id)}</a>"),
            "run_id": run_id or "none",
            "current_stage": "select_delegation",
            "next_action": "Open delegation runs",
            "reason": "selected delegation was not found",
            "primary_summary": "The selected delegation is not available in local state.",
            "resume_surface": f"/workflow?delegation_id={quote(delegation_id)}",
            "selected_step_count": str(len(selected_statuses)),
            "selected_status_count": str(len(selected_statuses)),
        }

    summary = summarize_implementation_handoff(root, delegation)
    prep_packets = [
        item
        for item in list_coder_prep_packets(root)
        if item.get("source", {}).get("delegation_id") == delegation.id
    ]
    plan_packets = [
        item
        for item in list_coder_worktree_plan_packets(root)
        if item.get("source", {}).get("delegation_id") == delegation.id
    ]
    worktree_approvals = list_coder_worktree_approvals(
        root,
        delegation_id=delegation.id,
        limit=50,
    )
    worktree_runs = list_coder_worktree_runs(root, delegation_id=delegation.id, limit=50)
    commit_approvals = list_coder_worktree_commit_approvals(
        root,
        delegation_id=delegation.id,
        limit=50,
    )
    publications = list_coder_publications(root, delegation_id=delegation.id, limit=50)
    if selected_run is None:
        selected_run = _workflow_command_selected_run(
            root,
            worktree_runs=worktree_runs,
            commit_approvals=commit_approvals,
            publications=publications,
        )
    next_action = _delegation_next_action(
        root,
        summary=summary,
        prep_count=len(prep_packets),
        plan_count=len(plan_packets),
        worktree_approvals=worktree_approvals,
        worktree_runs=worktree_runs,
        commit_approvals=commit_approvals,
        publications=publications,
    )
    target_href, target_label, reason = _workflow_command_target(
        next_action,
        delegation=delegation,
        run=selected_run,
    )
    project = (
        selected_run.project_id
        if selected_run is not None
        else _task_project(storage, delegation.parent_task_id)
    )
    last_artifact = ""
    if selected_run is not None:
        summary_path = Path(selected_run.evidence_path) / "summary.md"
        last_artifact = _repo_relative_artifact_path(root, summary_path)
    if not last_artifact or last_artifact == "none":
        markdown_path = str(summary.get("markdown_path") or "")
        if _artifact_status(root, markdown_path) == "available":
            last_artifact = markdown_path
    stage = _workflow_stage_for_action(next_action)
    resume_surface = (
        f"/workflow?run_id={quote(run_id)}"
        if run_id
        else f"/workflow?delegation_id={quote(delegation.id)}"
    )
    return {
        **base,
        "status": "run_selected" if run_id else "delegation_selected",
        "scope": "run" if run_id else "delegation",
        "delegation_id": delegation.id,
        "delegation_surface": SafeHtml(f"<a href='/delegations/{quote(delegation.id)}'>{_e(delegation.id)}</a>"),
        "run_id": selected_run.id if selected_run is not None else run_id or "none",
        "run_surface": SafeHtml(
            f"<a href='/runs/{quote(selected_run.id)}'>{_e(selected_run.id)}</a>"
            if selected_run is not None
            else "<a href='/delegation-runs'>select run</a>"
        ),
        "goal_id": delegation.parent_goal_id,
        "goal_surface": SafeHtml(f"<a href='/goals/{quote(delegation.parent_goal_id)}'>{_e(delegation.parent_goal_id)}</a>"),
        "project": project,
        "current_stage": stage,
        "next_action": next_action,
        "target_href": target_href,
        "target_label": target_label,
        "reason": reason,
        "primary_summary": f"{stage} is the current workflow stage for this {('run' if run_id else 'delegation')}.",
        "state_href": "#workflow-stepper",
        "state_label": "Workflow Stepper",
        "queue_href": "/approvals",
        "queue_label": "/approvals",
        "resume_href": "/resume",
        "resume_label": "/resume",
        "finish_href": "#workflow-finish-today",
        "finish_label": "Finish Today",
        "resume_surface": resume_surface,
        "last_artifact": last_artifact,
        "selected_step_count": str(len(selected_statuses)),
        "selected_status_count": str(len(selected_statuses)),
    }


