def _approval_decision_brief(
    root: Path,
    worktree_approvals: list[Any],
    commit_approvals: list[Any],
    publication_approvals: list[Any],
    focus: dict[str, Any],
) -> str:
    status = "empty"
    kind = "none"
    decision_id = "none"
    project = "none"
    action = "No pending approvals"
    action_name = "none"
    decision_surface = SafeHtml("<a href='/goals'>/goals</a>")
    run_surface: str | SafeHtml = "none"
    source_run = "none"
    delegation_surface: str | SafeHtml = "none"
    workflow_surface: str | SafeHtml = SafeHtml("<a href='/goals'>/goals</a>")
    request_artifact: str | SafeHtml = "none"
    evidence_artifact: str | SafeHtml = "none"
    after_decision = "none"
    after_surface: str | SafeHtml = SafeHtml("<a href='/goals'>/goals</a>")
    typed_commit_message_required = "false"
    changed_files = "0"
    remote_target = "none"
    reason = "no_pending_local_approval_decisions"
    context_run = "none"
    context_delegation = "none"
    decision_href = "/goals"
    decision_label = "/goals"
    inspect_href = "/goals"
    inspect_label = "/goals"
    evidence_href = "#approval-decision-brief"
    evidence_label = "Evidence"
    after_href = "/goals"
    after_label = "/goals"

    focus_kind = str(focus.get("kind") or "none")
    if focus_kind == "worktree":
        item = focus["item"]
        status = "needs_worktree_decision"
        kind = "worktree"
        decision_id = item.id
        project = item.project_id
        action = "Approve worktree"
        action_name = "approve-coder-worktree"
        decision_surface = SafeHtml(
            f"<a href='#approval-workbench-action-form'>{_e(action)}</a>"
        )
        decision_href = "#approval-workbench-action-form"
        decision_label = action
        run_surface = "not_created_yet"
        source_run = item.source_run_id or "none"
        context_run = "not_created_yet"
        context_delegation = item.delegation_id
        delegation_surface = _path_link(
            f"/delegations/{quote(item.delegation_id)}"
        )
        inspect_href = f"/workflow?delegation_id={quote(item.delegation_id)}"
        inspect_label = "Workflow"
        workflow_surface = _path_link(
            inspect_href
        )
        request_artifact_path = _repo_relative_artifact_path(root, item.request_artifact_path)
        evidence_artifact_path = _repo_relative_artifact_path(root, item.source_plan_path)
        request_artifact = _artifact_link(request_artifact_path)
        evidence_artifact = _artifact_link(evidence_artifact_path)
        evidence_href = f"/artifacts?path={quote(evidence_artifact_path)}"
        evidence_label = "Plan evidence"
        after_decision = "run approved worktree from goal or run surface"
        after_surface = workflow_surface
        after_href = inspect_href
        after_label = "Workflow"
        reason = "bounded_worktree_plan_waiting_for_operator"
    elif focus_kind == "commit":
        item = focus["item"]
        status = "needs_commit_decision"
        kind = "commit"
        decision_id = item.id
        project = item.project_id
        action = "Approve commit"
        action_name = "approve-coder-commit"
        decision_surface = SafeHtml(
            f"<a href='#approval-workbench-action-form'>{_e(action)}</a>"
        )
        decision_href = "#approval-workbench-action-form"
        decision_label = action
        inspect_href = f"/runs/{quote(item.run_id)}"
        inspect_label = "Run Detail"
        run_surface = _path_link(inspect_href)
        source_run = item.source_run_id or "none"
        context_run = item.run_id
        context_delegation = item.delegation_id
        delegation_surface = _path_link(
            f"/delegations/{quote(item.delegation_id)}"
        )
        workflow_surface = _path_link(f"/workflow?run_id={quote(item.run_id)}")
        request_artifact_path = _repo_relative_artifact_path(root, item.request_artifact_path)
        evidence_artifact_path = _repo_relative_artifact_path(root, item.review_path)
        request_artifact = _artifact_link(request_artifact_path)
        evidence_artifact = _artifact_link(evidence_artifact_path)
        evidence_href = f"/artifacts?path={quote(evidence_artifact_path)}"
        evidence_label = "Review evidence"
        after_decision = "commit approved worktree with typed message"
        after_surface = run_surface
        after_href = inspect_href
        after_label = "Run Detail"
        typed_commit_message_required = "true"
        changed_files = str(len(item.changed_files))
        reason = "reviewed_worktree_commit_waiting_for_operator"
    elif focus_kind == "publication":
        item = focus["item"]
        status = "needs_publication_decision"
        kind = "publication"
        decision_id = item.id
        project = item.project_id
        action = "Approve publication"
        action_name = "approve-coder-publication"
        decision_surface = SafeHtml(
            f"<a href='#approval-workbench-action-form'>{_e(action)}</a>"
        )
        decision_href = "#approval-workbench-action-form"
        decision_label = action
        inspect_href = f"/runs/{quote(item.run_id)}"
        inspect_label = "Run Detail"
        run_surface = _path_link(inspect_href)
        source_run = item.source_run_id or "none"
        context_run = item.run_id
        context_delegation = item.delegation_id
        delegation_surface = _path_link(
            f"/delegations/{quote(item.delegation_id)}"
        )
        workflow_surface = _path_link(f"/workflow?run_id={quote(item.run_id)}")
        request_artifact_path = _repo_relative_artifact_path(root, item.request_artifact_path)
        evidence_artifact_path = _repo_relative_artifact_path(root, item.source_commit_artifact_path)
        request_artifact = _artifact_link(request_artifact_path)
        evidence_artifact = _artifact_link(evidence_artifact_path)
        evidence_href = f"/artifacts?path={quote(evidence_artifact_path)}"
        evidence_label = "Commit evidence"
        after_decision = "prepare publication handoff for manual push/PR"
        after_surface = run_surface
        after_href = inspect_href
        after_label = "Run Detail"
        remote_target = f"{item.remote}/{item.target_branch}"
        reason = "committed_worktree_publication_waiting_for_operator"

    lines = [
        f"approval_decision_now: {_e(action)}",
        f"approval_decision_click: {decision_surface}",
        (
            "approval_decision_context: "
            f"project={_e(project)} run={_e(context_run)} "
            f"delegation={_e(context_delegation)}"
        ),
        f"approval_decision_reason: {_e(reason)}",
        (
            "approval_decision_scope: "
            f"status={_e(focus['scope_status'])} "
            f"run={_e(focus['scope_run_id'])} "
            f"goal={_e(focus['scope_goal_id'])}"
        ),
        f"approval_decision_evidence: {evidence_artifact}",
        f"approval_decision_after: {_e(after_decision)} at {after_surface}",
        "approval_decision_safety: confirmed local decision artifact only",
    ]
    if status == "empty":
        lines.append("approval_decision_empty: no pending local approval decisions")

    return "".join(
        [
            (
                "<section id='approval-decision-brief' class='panel approval-decision-brief' "
                "data-approval-decision-brief='true' "
                f"data-approval-decision-status='{_e(status)}'>"
                "<h2>Approval Decision Brief</h2>"
            ),
            "<p class='muted'>The next local approval decision with direct inspection links and post-decision routing.</p>",
            "<div class='approval-decision-grid' data-approval-decision-actions='true'>",
            "<article class='approval-decision-card approval-decision-primary' data-approval-decision-card='decision'><h3>Decision</h3>",
            f"<p>{_e(action)} · {_e(kind)}</p><a class='approval-decision-action' data-approval-decision-primary='true' href='{_e(decision_href)}'>{_e(decision_label)}</a></article>",
            "<article class='approval-decision-card' data-approval-decision-card='inspect'><h3>Inspect</h3>",
            f"<p>{_e(reason)}</p><a class='approval-decision-link' href='{_e(inspect_href)}'>{_e(inspect_label)}</a></article>",
            "<article class='approval-decision-card' data-approval-decision-card='evidence'><h3>Evidence</h3>",
            f"<p>{_e(project)} · {changed_files} changed file{'s' if changed_files != '1' else ''}</p><a class='approval-decision-link' href='{_e(evidence_href)}'>{_e(evidence_label)}</a></article>",
            "<article class='approval-decision-card' data-approval-decision-card='after'><h3>After</h3>",
            f"<p>{_e(after_decision)}</p><a class='approval-decision-link' href='{_e(after_href)}'>{_e(after_label)}</a></article>",
            "<article class='approval-decision-card' data-approval-decision-card='safety'><h3>Safety</h3>",
            "<p>GET is read-only; approval forms create local decision artifacts only after confirmation.</p><a class='approval-decision-link' href='#approval-decision-brief'>Read-only</a></article>",
            "</div>",
            "<details class='approval-decision-evidence' data-approval-decision-evidence='true'><summary>Approval decision evidence</summary>",
            _kv(
                [
                    ("approval_decision_status", status),
                    ("approval_decision_scope_status", focus["scope_status"]),
                    ("approval_decision_scope_run", focus["scope_run_id"]),
                    ("approval_decision_scope_goal", focus["scope_goal_id"]),
                    ("approval_decision_kind", kind),
                    ("approval_decision_id", decision_id),
                    ("approval_decision_project", project),
                    ("approval_decision_action", action),
                    ("approval_decision_action_name", action_name),
                    ("approval_decision_surface", decision_surface),
                    ("approval_decision_run", run_surface),
                    ("approval_decision_source_run", source_run),
                    ("approval_decision_delegation", delegation_surface),
                    ("approval_decision_workflow", workflow_surface),
                    ("approval_decision_request_artifact", request_artifact),
                    ("approval_decision_evidence_artifact", evidence_artifact),
                    ("approval_decision_after_decision", after_decision),
                    ("approval_decision_after_surface", after_surface),
                    (
                        "approval_decision_typed_commit_message_required",
                        typed_commit_message_required,
                    ),
                    ("approval_decision_changed_files", changed_files),
                    ("approval_decision_remote_target", remote_target),
                    ("approval_decision_write_on_get", "false"),
                    ("approval_decision_executes_work", "false"),
                    ("approval_decision_provider_calls_taken_by_clankeros", "0"),
                    ("approval_decision_network_actions_taken", "0"),
                    ("approval_decision_external_effects_created", "false"),
                ]
            ),
            _ul(lines),
            "</details>",
            "</section>",
        ]
    )


def _approval_queue_command_bar(
    worktree_approvals: list[Any],
    commit_approvals: list[Any],
    publication_approvals: list[Any],
    focus: dict[str, Any],
) -> str:
    total = len(worktree_approvals) + len(commit_approvals) + len(publication_approvals)
    first_kind = "none"
    first_id = "none"
    first_project = "none"
    first_action = "No pending approvals"
    first_surface = SafeHtml("<a href='/goals'>/goals</a>")
    after_decision = "none"
    focus_kind = str(focus.get("kind") or "none")
    if focus_kind == "worktree":
        item = focus["item"]
        first_kind = "worktree"
        first_id = item.id
        first_project = item.project_id
        first_action = "Approve worktree"
        first_surface = SafeHtml("<a href='#pending-worktree-approvals'>Pending Worktree Approvals</a>")
        after_decision = "run approved worktree from goal or run surface"
    elif focus_kind == "commit":
        item = focus["item"]
        first_kind = "commit"
        first_id = item.id
        first_project = item.project_id
        first_action = "Approve commit"
        first_surface = SafeHtml("<a href='#pending-commit-approvals'>Pending Commit Approvals</a>")
        after_decision = "commit approved worktree with typed message"
    elif focus_kind == "publication":
        item = focus["item"]
        first_kind = "publication"
        first_id = item.id
        first_project = item.project_id
        first_action = "Approve publication"
        first_surface = SafeHtml("<a href='#pending-publication-approvals'>Pending Publication Approvals</a>")
        after_decision = "prepare publication handoff for manual push/PR"
    lines = [
        f"approval_queue_now: {_e(first_action)}",
        f"approval_queue_click: {first_surface}",
        (
            "approval_queue_scope: "
            f"status={_e(focus['scope_status'])} "
            f"run={_e(focus['scope_run_id'])} "
            f"goal={_e(focus['scope_goal_id'])}"
        ),
        f"approval_queue_after_decision: {_e(after_decision)}",
        "approval_queue_safety: local decision artifact only",
    ]
    if total == 0:
        lines.append("approval_queue_empty: no pending local approval decisions")
    return "".join(
        [
            "<section class='panel approval-queue-command-bar' data-approval-queue-command-bar='true'><h2>Approval Queue Command Bar</h2>",
            "<p class='muted'>One read-only summary of the local decisions waiting for the operator.</p>",
            "<details class='approval-command-evidence' data-approval-command-evidence='true'><summary>Approval command evidence</summary>",
            _kv(
                [
                    ("approval_queue_status", "available"),
                    ("approval_queue_scope_status", focus["scope_status"]),
                    ("approval_queue_scope_run", focus["scope_run_id"]),
                    ("approval_queue_scope_goal", focus["scope_goal_id"]),
                    ("approval_queue_total_pending", str(total)),
                    ("approval_queue_worktree_pending", str(len(worktree_approvals))),
                    ("approval_queue_commit_pending", str(len(commit_approvals))),
                    ("approval_queue_publication_pending", str(len(publication_approvals))),
                    ("approval_queue_first_kind", first_kind),
                    ("approval_queue_first_id", first_id),
                    ("approval_queue_first_project", first_project),
                    ("approval_queue_first_action", first_action),
                    ("approval_queue_first_surface", first_surface),
                    ("approval_queue_after_decision", after_decision),
                    ("approval_queue_write_on_get", "false"),
                    ("approval_queue_network_actions_taken", "0"),
                    ("approval_queue_external_effects_created", "false"),
                ]
            ),
            _ul(lines),
            "</details>",
            "</section>",
        ]
    )


def _incidents(root: Path) -> str:
    storage = _storage(root)
    incidents = storage.list_recent_incidents(limit=50)
    recommendations = storage.list_task_recommendations(limit=50)
    open_incidents = [item for item in incidents if item.status == "open"]
    resolved_incidents = [item for item in incidents if item.status != "open"]
    open_recommendations = [item for item in recommendations if item.status == "open"]
    context = _incident_triage_context(
        incidents=incidents,
        open_incidents=open_incidents,
        resolved_incidents=resolved_incidents,
        recommendations=recommendations,
        open_recommendations=open_recommendations,
    )
    return "".join(
        [
            "<section><h1>Incidents</h1>",
            "<p class='muted'>Read-only triage board for local incidents and recovery recommendations. Resolution still happens through explicit operator commands, not page load.</p>",
            "</section>",
            _incident_operator_workbench(
                context=context,
                incidents=incidents,
                open_incidents=open_incidents,
                resolved_incidents=resolved_incidents,
                recommendations=recommendations,
                open_recommendations=open_recommendations,
            ),
            _incident_triage_command_bar(
                context=context,
            ),
            _list_section(
                "Open Incidents",
                [_incident_line(item) for item in open_incidents],
                anchor_id="incident-open",
            ),
            _list_section(
                "Resolved Incidents",
                [_incident_line(item) for item in resolved_incidents],
                anchor_id="incident-resolved",
            ),
            _list_section(
                "Task Recommendations",
                [_task_recommendation_line(item) for item in recommendations],
                anchor_id="incident-recommendations",
            ),
            _non_claim_banner(),
        ]
    )


def _incident_triage_context(
    *,
    incidents: list[Any],
    open_incidents: list[Any],
    resolved_incidents: list[Any],
    recommendations: list[Any],
    open_recommendations: list[Any],
) -> dict[str, Any]:
    status = "empty"
    first_kind = "none"
    first_id = "none"
    first_project = "none"
    first_goal = "none"
    first_task = "none"
    first_run = "none"
    first_severity = "none"
    first_reason = "no local incidents or recommendations"
    first_evidence_path = "none"
    next_action = "No incident triage needed"
    target_href = "/goals"
    target_label = "/goals"
    if open_incidents:
        item = open_incidents[0]
        status = "open_incident"
        first_kind = "incident"
        first_id = item.id
        first_project = item.project_id
        first_goal = item.goal_id or "none"
        first_task = item.task_id or "none"
        first_run = item.run_id or "none"
        first_severity = item.severity
        first_reason = item.summary
        first_evidence_path = item.evidence_path or "none"
        next_action = "Inspect open incident"
        target_href = "#incident-open"
        target_label = "Open Incidents"
    elif open_recommendations:
        item = open_recommendations[0]
        status = "open_recommendation"
        first_kind = "recommendation"
        first_id = item.id
        first_project = item.project_id
        first_goal = item.goal_id
        first_task = item.task_id
        first_run = item.run_id or "none"
        first_severity = item.source_status
        first_reason = item.reason
        first_evidence_path = item.evidence_path
        next_action = "Review recovery recommendation"
        target_href = "#incident-recommendations"
        target_label = "Task Recommendations"
    elif resolved_incidents:
        item = resolved_incidents[0]
        status = "resolved_history"
        first_kind = "resolved_incident"
        first_id = item.id
        first_project = item.project_id
        first_goal = item.goal_id or "none"
        first_task = item.task_id or "none"
        first_run = item.run_id or "none"
        first_severity = item.severity
        first_reason = item.summary
        first_evidence_path = item.evidence_path or "none"
        next_action = "Review resolved incident history"
        target_href = "#incident-resolved"
        target_label = "Resolved Incidents"
    elif recommendations:
        item = recommendations[0]
        status = "recommendation_history"
        first_kind = "recommendation_history"
        first_id = item.id
        first_project = item.project_id
        first_goal = item.goal_id
        first_task = item.task_id
        first_run = item.run_id or "none"
        first_severity = item.source_status
        first_reason = item.reason
        first_evidence_path = item.evidence_path
        next_action = "Review recommendation history"
        target_href = "#incident-recommendations"
        target_label = "Task Recommendations"
    return {
        "status": status,
        "first_kind": first_kind,
        "first_id": first_id,
        "first_project": first_project,
        "first_goal": first_goal,
        "first_task": first_task,
        "first_run": first_run,
        "first_severity": first_severity,
        "first_reason": first_reason,
        "first_evidence_path": first_evidence_path,
        "first_evidence": _artifact_link(first_evidence_path),
        "next_action": next_action,
        "target_href": target_href,
        "target_label": target_label,
        "target_surface": SafeHtml(
            f"<a href='{_e(target_href)}'>{_e(target_label)}</a>"
        ),
        "total_incidents": len(incidents),
        "open_incidents": len(open_incidents),
        "resolved_incidents": len(resolved_incidents),
        "total_recommendations": len(recommendations),
        "open_recommendations": len(open_recommendations),
    }


def _incident_operator_workbench(
    *,
    context: dict[str, Any],
    incidents: list[Any],
    open_incidents: list[Any],
    resolved_incidents: list[Any],
    recommendations: list[Any],
    open_recommendations: list[Any],
) -> str:
    evidence_path = str(context["first_evidence_path"])
    if evidence_path != "none":
        evidence_href = f"/artifacts?path={quote(evidence_path)}"
        evidence_label = "Evidence Artifact"
    else:
        evidence_href = str(context["target_href"])
        evidence_label = str(context["target_label"])

    recovery_href = "/goals"
    recovery_label = "/goals"
    recovery_text = "No local incident recovery is queued"
    if open_recommendations:
        recovery_href = "#incident-recommendations"
        recovery_label = "Task Recommendations"
        recovery_text = f"{len(open_recommendations)} open recovery recommendation(s)"
    elif open_incidents:
        first_goal = str(context["first_goal"])
        if first_goal != "none":
            recovery_href = f"/goals/{quote(first_goal)}"
            recovery_label = "Owning Goal"
            recovery_text = "Open the owning Goal after reviewing evidence"
        else:
            recovery_href = "#incident-open"
            recovery_label = "Open Incidents"
            recovery_text = f"{len(open_incidents)} open local incident(s)"
    elif resolved_incidents:
        recovery_href = "#incident-resolved"
        recovery_label = "Resolved Incidents"
        recovery_text = "Review resolved incident history"
    elif recommendations:
        recovery_href = "#incident-recommendations"
        recovery_label = "Task Recommendations"
        recovery_text = "Review recommendation history"

    recovery_surface = SafeHtml(
        f"<a href='{_e(recovery_href)}'>{_e(recovery_label)}</a>"
    )
    finish_form = _input_form(
        "save-workspace",
        {
            "open_project": "" if context["first_project"] == "none" else str(context["first_project"]),
            "open_goal": "" if context["first_goal"] == "none" else str(context["first_goal"]),
            "return_to": "/incidents",
        },
        {
            "filters": f"incident:{context['first_kind']}:{context['first_id']}",
            "expanded_panels": "incident-workbench,open,recommendations",
            "last_viewed_artifact": "" if evidence_path == "none" else evidence_path,
            "updated_by": "incident-operator-workbench",
        },
    )
    lines = [
        f"incident_workbench_now: {_e(context['next_action'])}",
        f"incident_workbench_click: <a href='{_e(context['target_href'])}'>{_e(context['target_label'])}</a>",
        f"incident_workbench_evidence: {_artifact_link(evidence_path)}",
        f"incident_workbench_recover: <a href='{_e(recovery_href)}'>{_e(recovery_label)}</a>",
        "incident_workbench_finish: <a href='#incident-finish-today'>Finish Today</a>",
        "incident_workbench_safety: read-only local triage; no resolution, retry, provider, network, or external effect on GET",
    ]
    if not incidents and not recommendations:
        lines.append("incident_workbench_empty: no local incident or recommendation records")
    return "".join(
        [
            "<section id='incident-operator-workbench' class='panel incident-operator-workbench' data-incident-operator-workbench='true'><h2>Incident Operator Workbench</h2>",
            "<div class='incident-workbench-grid' data-incident-workbench-actions='true'>",
            "<article class='incident-workbench-card incident-workbench-primary'><h3>Now</h3>",
            f"<p>{_e(context['next_action'])}</p>",
            (
                "<a class='incident-workbench-action' "
                "data-incident-workbench-primary='true' "
                f"href='{_e(context['target_href'])}'>{_e(context['target_label'])}</a>"
            ),
            "</article>",
            "<article class='incident-workbench-card'><h3>Evidence</h3>",
            f"<p>{_e(context['first_reason'])}</p>",
            f"<a class='incident-workbench-link' href='{_e(evidence_href)}'>{_e(evidence_label)}</a>",
            "</article>",
            "<article class='incident-workbench-card'><h3>Recover</h3>",
            f"<p>{_e(recovery_text)}</p>",
            f"<a class='incident-workbench-link' href='{_e(recovery_href)}'>{_e(recovery_label)}</a>",
            "</article>",
            "<article class='incident-workbench-card'><h3>Finish Today</h3>",
            "<p>Save this triage context</p>",
            "<a class='incident-workbench-link' data-open-details='true' href='#incident-finish-today'>Open save form</a>",
            "</article>",
            "</div>",
            "<details class='incident-workbench-evidence' data-incident-workbench-evidence='true'><summary>Incident workbench evidence</summary>",
            _kv(
                [
                    ("incident_workbench_status", context["status"]),
                    ("incident_workbench_total_incidents", str(context["total_incidents"])),
                    ("incident_workbench_open_incidents", str(context["open_incidents"])),
                    ("incident_workbench_resolved_incidents", str(context["resolved_incidents"])),
                    ("incident_workbench_total_recommendations", str(context["total_recommendations"])),
                    ("incident_workbench_open_recommendations", str(context["open_recommendations"])),
                    ("incident_workbench_first_kind", context["first_kind"]),
                    ("incident_workbench_first_id", context["first_id"]),
                    ("incident_workbench_first_project", context["first_project"]),
                    ("incident_workbench_first_goal", context["first_goal"]),
                    ("incident_workbench_first_task", context["first_task"]),
                    ("incident_workbench_first_run", context["first_run"]),
                    ("incident_workbench_first_severity_or_source", context["first_severity"]),
                    ("incident_workbench_next_action", context["next_action"]),
                    ("incident_workbench_primary_surface", context["target_surface"]),
                    ("incident_workbench_recovery_surface", recovery_surface),
                    ("incident_workbench_reason", context["first_reason"]),
                    ("incident_workbench_evidence_artifact", context["first_evidence"]),
                    ("incident_workbench_action_form_available", "false"),
                    ("incident_workbench_resolution_form_available", "false"),
                    ("incident_workbench_finish_form_available", "true"),
                    ("incident_workbench_write_on_get", "false"),
                    ("incident_workbench_resolution_on_get", "false"),
                    ("incident_workbench_retry_on_get", "false"),
                    ("incident_workbench_provider_calls_taken", "0"),
                    ("incident_workbench_network_actions_taken", "0"),
                    ("incident_workbench_external_effects_created", "false"),
                ]
            ),
            _ul(lines),
            "</details>",
            "<details id='incident-finish-today' class='incident-finish-details' data-incident-finish-details='true'><summary>Finish Today save form</summary>",
            "<p class='muted'>Save this incident/recommendation context as the next resume point. This writes only `.clanker/app/workspace.json` after confirmation.</p>",
            finish_form,
            "</details>",
            "</section>",
        ]
    )


