def _project_detail(root: Path, project_id: str) -> str:
    storage = _storage(root)
    project = storage.get_registered_project(project_id)
    if project is None:
        return "<p class='error'>Project not found.</p>"
    repo = _repo_state(Path(project.root_path))
    goal_rows = _table_rows(
        storage.db_path,
        "select * from goals where project_id = ? order by updated_at desc limit 20",
        (project_id,),
    )
    task_rows = _table_rows(
        storage.db_path,
        "select id, goal_id, status, task_type, description from tasks where project_id = ? order by updated_at desc limit 20",
        (project_id,),
    )
    delegations = [
        delegation
        for delegation in storage.list_recent_subagent_delegations(limit=None)
        if _task_project(storage, delegation.parent_task_id) == project_id
    ][:20]
    operator_state = _project_operator_state(
        root,
        storage,
        project_id=project_id,
        task_rows=task_rows,
    )
    return "".join(
        [
            f"<section><h1>Project {_e(project.name)}</h1>",
            _kv(
                [
                    ("root_path", project.root_path),
                    ("default_test_command", project.default_test_command),
                    ("current_branch", repo["branch"]),
                    ("current_commit", repo["commit"]),
                    ("allowed_write_roots", ", ".join(project.allowed_write_roots)),
                ]
            ),
            "</section>",
            _project_operator_workbench(
                root,
                project_id=project_id,
                repo=repo,
                goal_rows=goal_rows,
                task_rows=task_rows,
                delegations=delegations,
                operator_state=operator_state,
            ),
            _project_command_bar(
                root,
                project_id=project_id,
                repo=repo,
                goal_rows=goal_rows,
                task_rows=task_rows,
                delegations=delegations,
                operator_state=operator_state,
            ),
            _project_goal_creation_panel(project_id, goal_rows),
            _project_goal_map(
                root,
                storage,
                project_id=project_id,
                goal_rows=goal_rows,
                task_rows=task_rows,
                delegations=delegations,
                operator_state=operator_state,
            ),
            _list_section(
                "Project Goals",
                [
                    _goal_index_line(root, storage, row)
                    for row in goal_rows
                ],
            ),
            _list_section(
                "Project Tasks",
                [
                    f"{_e(row['id'])}: status={_e(row['status'])} "
                    f"goal={_e(row['goal_id'])} type={_e(row['task_type'])} - {_e(row['description'])}"
                    for row in task_rows
                ],
            ),
            _list_section(
                "Delegations",
                [
                    f"<a href='/delegations/{quote(delegation.id)}'>{_e(delegation.id)}</a>: {delegation.status} {delegation.title}"
                    for delegation in delegations
                ],
            ),
            _list_section(
                "Delegation Runs",
                _delegation_run_lines(root, storage, project_id=project_id, limit=20),
                "/delegation-runs",
            ),
            _project_operator_guidance(
                root,
                storage,
                project_id=project_id,
                task_rows=task_rows,
                operator_state=operator_state,
            ),
            _project_workflow_launchpad(
                root,
                storage,
                project_id=project_id,
                delegations=delegations,
            ),
            _list_section(
                "Implementation Handoffs",
                _implementation_handoff_lines(root, storage, project_id=project_id, limit=20),
            ),
            _list_section(
                "Coder Prep / Worktree / Publication Artifacts",
                _artifact_links(
                    list_coder_prep_packets(root)
                    + list_coder_worktree_plan_packets(root)
                    + [
                        {"_path": publication.request_artifact_path, "kind": "coder_publication", "id": publication.id}
                        for publication in list_coder_publications(root, limit=20)
                        if publication.project_id == project_id
                    ]
                ),
            ),
        ]
    )


def _project_operator_workbench(
    root: Path,
    *,
    project_id: str,
    repo: dict[str, Any],
    goal_rows: list[sqlite3.Row],
    task_rows: list[sqlite3.Row],
    delegations: list[Any],
    operator_state: dict[str, Any],
) -> str:
    active_goals = [row for row in goal_rows if _goal_bucket(row) == "active"]
    paused_goals = [row for row in goal_rows if _goal_bucket(row) == "paused"]
    completed_goals = [row for row in goal_rows if _goal_bucket(row) == "completed"]
    lead_goal = (
        active_goals[0]
        if active_goals
        else (paused_goals[0] if paused_goals else (goal_rows[0] if goal_rows else None))
    )
    next_action = _project_next_action(
        root,
        open_incidents=operator_state["open_incidents"],
        recommendations=operator_state["recommendations"],
        worktree_approvals=operator_state["worktree_approvals"],
        worktree_runs=operator_state["worktree_runs"],
        commit_approvals=operator_state["commit_approvals"],
        publications=operator_state["publications"],
    )
    if not goal_rows:
        next_action = "start_project_goal"
    target_href, target_label, reason = _project_next_action_target(
        root,
        project_id,
        next_action=next_action,
        goal_rows=goal_rows,
        delegations=delegations,
        operator_state=operator_state,
    )
    pending_approvals = (
        _count_status(operator_state["worktree_approvals"], "pending_operator_approval")
        + _count_status(operator_state["commit_approvals"], "pending_operator_approval")
        + _count_status(operator_state["publications"], "pending_operator_approval")
    )
    open_incidents = len(operator_state["open_incidents"])
    open_recommendations = len(operator_state["recommendations"])
    ready_publications = _count_status(operator_state["publications"], "ready_for_operator")
    waiting_items = pending_approvals + open_incidents + open_recommendations
    if not goal_rows:
        status = "needs_goal"
    elif waiting_items:
        status = "attention_ready"
    elif next_action == "review_project_state":
        status = "project_ready"
    else:
        status = "action_ready"

    lead_goal_id = str(lead_goal["id"]) if lead_goal is not None else ""
    lead_goal_label = (
        str(lead_goal["title"] or lead_goal["description"] or lead_goal_id)
        if lead_goal is not None
        else "none"
    )
    lead_goal_href = (
        f"/goals/{quote(lead_goal_id)}"
        if lead_goal_id
        else f"/projects/{quote(project_id)}#start-goal-for-this-project"
    )
    lead_goal_surface: str | SafeHtml = (
        SafeHtml(f"<a href='{_e(lead_goal_href)}'>{_e(_compact_label(lead_goal_label, 72))}</a>")
        if lead_goal_id
        else "none"
    )
    lead_goal_action_label = "Open lead goal" if lead_goal_id else "Start Goal"

    if open_incidents or open_recommendations:
        unblock_href = "/incidents"
        unblock_label = "Review incidents"
        unblock_reason = "project_attention"
    elif pending_approvals:
        unblock_href = "/approvals"
        unblock_label = "Review approvals"
        unblock_reason = "pending_project_approvals"
    elif lead_goal_id:
        unblock_href = lead_goal_href
        unblock_label = "Review goal"
        unblock_reason = "no_project_blockers"
    else:
        unblock_href = f"/projects/{quote(project_id)}#start-goal-for-this-project"
        unblock_label = "Start Goal"
        unblock_reason = "no_project_goals"

    artifact_path = (
        f".clanker/projects/{project_id}/goals/{lead_goal_id}/GOAL.md"
        if lead_goal_id
        else ""
    )
    finish_form = _input_form(
        "save-workspace",
        {
            "open_project": project_id,
            "open_goal": lead_goal_id,
            "return_to": f"/projects/{project_id}",
        },
        {
            "filters": f"project:{project_id}",
            "expanded_panels": "project-workbench,goals,workflow,approvals",
            "last_viewed_artifact": artifact_path,
            "updated_by": "project-operator-workbench",
        },
    )
    return "".join(
        [
            "<section id='project-operator-workbench' class='panel project-operator-workbench' data-project-operator-workbench='true'><h2>Project Operator Workbench</h2>",
            "<p class='muted'>Project-level daily moves: do the next project action, open the lead Goal, clear blockers, and save this project as the resume point.</p>",
            "<div class='project-workbench-grid' data-project-workbench-actions='true'>",
            "<div class='project-workbench-card project-workbench-primary'>",
            "<h3>Do Now</h3>",
            f"<p>{_e(next_action)}</p>",
            (
                "<a class='project-workbench-action' "
                "data-project-workbench-primary='true' "
                f"href='{_e(target_href)}'>{_e(target_label)}</a>"
            ),
            "</div>",
            "<div class='project-workbench-card'>",
            "<h3>Goal</h3>",
            f"<p>{_e(_compact_label(lead_goal_label, 80))}</p>",
            f"<a class='project-workbench-link' href='{_e(lead_goal_href)}'>{_e(lead_goal_action_label)}</a>",
            "</div>",
            "<div class='project-workbench-card'>",
            "<h3>Unblock</h3>",
            f"<p>{waiting_items} waiting item(s)</p>",
            f"<a class='project-workbench-link' href='{_e(unblock_href)}'>{_e(unblock_label)}</a>",
            "</div>",
            "<div class='project-workbench-card'>",
            "<h3>Finish Today</h3>",
            "<p>Save project resume state</p>",
            "<a class='project-workbench-link' href='#project-finish-today'>Open save form</a>",
            "</div>",
            "</div>",
            "<details class='project-workbench-evidence' data-project-workbench-evidence='true'><summary>Project workbench evidence</summary>",
            _kv(
                [
                    ("project_workbench_status", status),
                    ("project_workbench_project", project_id),
                    ("project_workbench_branch", repo["branch"]),
                    ("project_workbench_commit", repo["commit"]),
                    ("project_workbench_lead_goal", lead_goal_surface),
                    ("project_workbench_active_goals", str(len(active_goals))),
                    ("project_workbench_paused_goals", str(len(paused_goals))),
                    ("project_workbench_completed_goals", str(len(completed_goals))),
                    ("project_workbench_tasks", str(len(task_rows))),
                    ("project_workbench_delegations", str(len(delegations))),
                    ("project_workbench_coder_runs", str(len(operator_state["worktree_runs"]))),
                    ("project_workbench_pending_approvals", str(pending_approvals)),
                    ("project_workbench_open_incidents", str(open_incidents)),
                    ("project_workbench_open_recommendations", str(open_recommendations)),
                    ("project_workbench_publication_handoffs", str(ready_publications)),
                    ("project_workbench_waiting_items", str(waiting_items)),
                    ("project_workbench_next_action", next_action),
                    (
                        "project_workbench_primary_surface",
                        SafeHtml(f"<a href='{_e(target_href)}'>{_e(target_label)}</a>"),
                    ),
                    ("project_workbench_reason", reason),
                    (
                        "project_workbench_unblock_surface",
                        SafeHtml(f"<a href='{_e(unblock_href)}'>{_e(unblock_label)}</a>"),
                    ),
                    ("project_workbench_unblock_reason", unblock_reason),
                    (
                        "project_workbench_goal_surface",
                        SafeHtml(f"<a href='{_e(lead_goal_href)}'>{_e(lead_goal_action_label)}</a>"),
                    ),
                    (
                        "project_workbench_finish_surface",
                        SafeHtml("<a href='#project-finish-today'>Finish Today</a>"),
                    ),
                    ("project_workbench_finish_form_available", "true"),
                    ("project_workbench_finish_confirmation_required", "true"),
                    ("project_workbench_saved_project", project_id),
                    ("project_workbench_saved_goal", lead_goal_id or "none"),
                    (
                        "project_workbench_saved_artifact",
                        SafeHtml(_artifact_link(artifact_path)) if artifact_path else "none",
                    ),
                    ("project_workbench_source", "project_operator_state"),
                    ("project_workbench_write_on_get", "false"),
                    ("project_workbench_provider_calls_taken", "0"),
                    ("project_workbench_network_actions_taken", "0"),
                    ("project_workbench_external_effects_created", "false"),
                    ("project_workbench_push_created", "false"),
                    ("project_workbench_pr_created", "false"),
                    ("project_workbench_deploy_created", "false"),
                ]
            ),
            _ul(
                [
                    f"project_workbench_now: {_e(next_action)}",
                    f"project_workbench_click: <a href='{_e(target_href)}'>{_e(target_label)}</a>",
                    f"project_workbench_goal: <a href='{_e(lead_goal_href)}'>{_e(lead_goal_action_label)}</a>",
                    f"project_workbench_unblock: <a href='{_e(unblock_href)}'>{_e(unblock_label)}</a>",
                    "project_workbench_finish: <a href='#project-finish-today'>Finish Today</a>",
                    "project_workbench_safety: confirmed local actions only; no write on GET",
                ]
            ),
            "</details>",
            "<details id='project-finish-today' class='project-finish-details' data-project-finish-details='true'><summary>Project Finish Today</summary>",
            _kv(
                [
                    ("project_finish_status", "available"),
                    ("project_finish_action", "save-workspace"),
                    ("project_finish_project", project_id),
                    ("project_finish_goal", lead_goal_id or "none"),
                    ("project_finish_artifact", artifact_path or "none"),
                    ("project_finish_confirmation_required", "true"),
                    ("project_finish_write_on_get", "false"),
                    ("project_finish_external_effects_created", "false"),
                ]
            ),
            finish_form,
            "</details>",
            "</section>",
        ]
    )


def _project_command_bar(
    root: Path,
    *,
    project_id: str,
    repo: dict[str, Any],
    goal_rows: list[sqlite3.Row],
    task_rows: list[sqlite3.Row],
    delegations: list[Any],
    operator_state: dict[str, Any],
) -> str:
    active_goals = [row for row in goal_rows if _goal_bucket(row) == "active"]
    paused_goals = [row for row in goal_rows if _goal_bucket(row) == "paused"]
    completed_goals = [row for row in goal_rows if _goal_bucket(row) == "completed"]
    next_action = _project_next_action(
        root,
        open_incidents=operator_state["open_incidents"],
        recommendations=operator_state["recommendations"],
        worktree_approvals=operator_state["worktree_approvals"],
        worktree_runs=operator_state["worktree_runs"],
        commit_approvals=operator_state["commit_approvals"],
        publications=operator_state["publications"],
    )
    if not goal_rows:
        next_action = "start_project_goal"
    target_href, target_label, reason = _project_next_action_target(
        root,
        project_id,
        next_action=next_action,
        goal_rows=goal_rows,
        delegations=delegations,
        operator_state=operator_state,
    )
    pending_approvals = (
        _count_status(operator_state["worktree_approvals"], "pending_operator_approval")
        + _count_status(operator_state["commit_approvals"], "pending_operator_approval")
        + _count_status(operator_state["publications"], "pending_operator_approval")
    )
    ready_publications = _count_status(operator_state["publications"], "ready_for_operator")
    open_incidents = len(operator_state["open_incidents"])
    open_recommendations = len(operator_state["recommendations"])
    lead_goal = active_goals[0] if active_goals else (paused_goals[0] if paused_goals else (goal_rows[0] if goal_rows else None))
    lead_goal_value: str | SafeHtml = "none"
    if lead_goal is not None:
        lead_goal_id = str(lead_goal["id"])
        lead_goal_label = str(lead_goal["title"] or lead_goal["description"] or lead_goal_id)
        lead_goal_value = SafeHtml(
            f"<a href='/goals/{quote(lead_goal_id)}'>{_e(_compact_label(lead_goal_label, 72))}</a>"
        )
    lines = [
        f"project_command_now: {_e(next_action)}",
        f"project_command_click: <a href='{_e(target_href)}'>{_e(target_label)}</a>",
        f"project_command_reason: {_e(reason)}",
        "project_command_safety: read-only project guidance",
    ]
    if not goal_rows:
        lines.append("project_command_empty: create the first goal for this project")
    return "".join(
        [
            "<section class='panel project-command-bar' data-project-command-bar='true'><h2>Project Command Bar</h2>",
            "<p class='muted'>One read-only project summary for the next local operator action before the longer project inventory.</p>",
            "<details class='project-command-evidence' data-project-command-evidence='true'><summary>Project command evidence</summary>",
            _kv(
                [
                    ("project_command_status", "available"),
                    ("project_command_project", project_id),
                    ("project_command_branch", repo["branch"]),
                    ("project_command_commit", repo["commit"]),
                    ("project_command_active_goals", str(len(active_goals))),
                    ("project_command_paused_goals", str(len(paused_goals))),
                    ("project_command_completed_goals", str(len(completed_goals))),
                    ("project_command_tasks", str(len(task_rows))),
                    ("project_command_delegations", str(len(delegations))),
                    ("project_command_coder_runs", str(len(operator_state["worktree_runs"]))),
                    ("project_command_pending_approvals", str(pending_approvals)),
                    ("project_command_open_incidents", str(open_incidents)),
                    ("project_command_open_recommendations", str(open_recommendations)),
                    ("project_command_publication_handoffs", str(ready_publications)),
                    ("project_command_lead_goal", lead_goal_value),
                    ("project_command_next_action", next_action),
                    ("project_command_target_surface", SafeHtml(f"<a href='{_e(target_href)}'>{_e(target_label)}</a>")),
                    ("project_command_reason", reason),
                    ("project_command_write_on_get", "false"),
                    ("project_command_network_actions_taken", "0"),
                    ("project_command_external_effects_created", "false"),
                ]
            ),
            _ul(lines),
            "</details>",
            "</section>",
        ]
    )


def _project_next_action_target(
    root: Path,
    project_id: str,
    *,
    next_action: str,
    goal_rows: list[sqlite3.Row],
    delegations: list[Any],
    operator_state: dict[str, Any],
) -> tuple[str, str, str]:
    if operator_state["open_incidents"]:
        incident = operator_state["open_incidents"][0]
        return "/incidents", "/incidents", str(incident["summary"])
    if operator_state["recommendations"]:
        recommendation = operator_state["recommendations"][0]
        return "/incidents", "/incidents", str(recommendation.reason)
    ready_publication = next(
        (item for item in operator_state["publications"] if item.status == "ready_for_operator"),
        None,
    )
    if ready_publication is not None:
        return (
            f"/runs/{quote(ready_publication.run_id)}",
            f"/runs/{ready_publication.run_id}",
            "manual publication handoff is ready outside ClankerOS",
        )
    approved_publication = next(
        (item for item in operator_state["publications"] if item.status == "approved"),
        None,
    )
    if approved_publication is not None:
        return (
            f"/runs/{quote(approved_publication.run_id)}",
            f"/runs/{approved_publication.run_id}",
            "approved publication needs a local handoff packet",
        )
    pending_publication = next(
        (item for item in operator_state["publications"] if item.status == "pending_operator_approval"),
        None,
    )
    if pending_publication is not None:
        return "/approvals", "/approvals", f"publication approval {pending_publication.id} is pending"
    committed = next(
        (item for item in operator_state["commit_approvals"] if item.status == "committed"),
        None,
    )
    if committed is not None and not operator_state["publications"]:
        return (
            f"/runs/{quote(committed.run_id)}",
            f"/runs/{committed.run_id}",
            "local commit exists and needs a publication request",
        )
    approved_commit = next(
        (item for item in operator_state["commit_approvals"] if item.status == "approved"),
        None,
    )
    if approved_commit is not None:
        return (
            f"/runs/{quote(approved_commit.run_id)}",
            f"/runs/{approved_commit.run_id}",
            "commit approval is ready for local worktree commit",
        )
    pending_commit = next(
        (item for item in operator_state["commit_approvals"] if item.status == "pending_operator_approval"),
        None,
    )
    if pending_commit is not None:
        return "/approvals", "/approvals", f"commit approval {pending_commit.id} is pending"
    reviewed_run = next(
        (
            item
            for item in operator_state["worktree_runs"]
            if item.status == "completed"
            and _run_review_gate_state(root, item)["commit_request_form_available"]
        ),
        None,
    )
    if reviewed_run is not None:
        return (
            f"/runs/{quote(reviewed_run.id)}",
            f"/runs/{reviewed_run.id}",
            "reviewed coder run can request commit approval",
        )
    pending_worktree = next(
        (item for item in operator_state["worktree_approvals"] if item.status == "pending_operator_approval"),
        None,
    )
    if pending_worktree is not None:
        return "/approvals", "/approvals", f"worktree approval {pending_worktree.id} is pending"
    approved_worktree = next(
        (item for item in operator_state["worktree_approvals"] if item.status == "approved"),
        None,
    )
    if approved_worktree is not None and not operator_state["worktree_runs"]:
        return (
            f"/workflow?delegation_id={quote(approved_worktree.delegation_id)}",
            f"/workflow?delegation_id={approved_worktree.delegation_id}",
            "approved worktree is waiting for confirmed execution",
        )
    if delegations:
        delegation = delegations[0]
        return (
            f"/delegations/{quote(delegation.id)}",
            f"/delegations/{delegation.id}",
            "project has delegation evidence to review",
        )
    if goal_rows:
        goal_id = str(goal_rows[0]["id"])
        return (
            f"/goals/{quote(goal_id)}",
            f"/goals/{goal_id}",
            f"{next_action} for latest project goal",
        )
    return (
        f"/projects/{quote(project_id)}#start-goal-for-this-project",
        "Start Goal For This Project",
        "no project goals exist yet",
    )


def _project_goal_creation_panel(project_id: str, goal_rows: list[sqlite3.Row]) -> str:
    return "".join(
        [
            "<section id='start-goal-for-this-project'><h2>Start Goal For This Project</h2>",
            "<p class='muted'>Create the next local goal for this registered project without leaving the project page.</p>",
            _kv(
                [
                    ("project_goal_creation_form_available", "true"),
                    ("project_goal_creation_project_id", project_id),
                    ("project_goal_creation_existing_goal_count", str(len(goal_rows))),
                    ("project_goal_creation_confirmation_required", "true"),
                    ("project_goal_creation_provider_calls_taken_by_clankeros", "0"),
                    ("project_goal_creation_network_actions_taken", "0"),
                    ("project_goal_creation_external_effects_created", "false"),
                ]
            ),
            _input_form(
                "create-goal",
                {"project_id": project_id},
                {
                    "prompt": "Describe the next local coding goal for this project.",
                    "created_by_profile": "planner",
                },
            ),
            "</section>",
        ]
    )


def _project_goal_map(
    root: Path,
    storage: Storage,
    *,
    project_id: str,
    goal_rows: list[sqlite3.Row],
    task_rows: list[sqlite3.Row],
    delegations: list[Any],
    operator_state: dict[str, Any],
) -> str:
    active_goals = [row for row in goal_rows if _goal_bucket(row) == "active"]
    paused_goals = [row for row in goal_rows if _goal_bucket(row) == "paused"]
    completed_goals = [row for row in goal_rows if _goal_bucket(row) == "completed"]
    lead_goal = (
        active_goals[0]
        if active_goals
        else (paused_goals[0] if paused_goals else (goal_rows[0] if goal_rows else None))
    )
    lead_goal_id = str(lead_goal["id"]) if lead_goal is not None else ""
    lead_goal_label = (
        str(lead_goal["title"] or lead_goal["description"] or lead_goal_id)
        if lead_goal is not None
        else "No Goal yet"
    )
    start_href = f"/projects/{quote(project_id)}#start-goal-for-this-project"
    lead_goal_href = (
        f"/goals/{quote(lead_goal_id)}"
        if lead_goal_id
        else start_href
    )
    lead_goal_action = "Open Goal" if lead_goal_id else "Start Goal"
    lead_state = _goal_state(root, storage, lead_goal_id) if lead_goal_id else None
    lead_phase = _goal_current_phase(lead_state) if lead_state is not None else "No Goal"
    lead_next = (
        _goal_next_action(root, lead_state)
        if lead_state is not None
        else GoalNextAction("Create first project Goal", lead_goal_href, "project_has_no_goals")
    )

    pending_approvals = (
        _count_status(operator_state["worktree_approvals"], "pending_operator_approval")
        + _count_status(operator_state["commit_approvals"], "pending_operator_approval")
        + _count_status(operator_state["publications"], "pending_operator_approval")
    )
    open_incidents = len(operator_state["open_incidents"])
    open_recommendations = len(operator_state["recommendations"])
    waiting_items = pending_approvals + open_incidents + open_recommendations
    latest_run = operator_state["worktree_runs"][0] if operator_state["worktree_runs"] else None
    latest_delegation = delegations[0] if delegations else None
    if latest_run is not None:
        workflow_href = f"/workflow?run_id={quote(latest_run.id)}"
        workflow_label = "Open latest run workflow"
        workflow_summary = f"run={latest_run.status}"
        latest_run_id = latest_run.id
    elif latest_delegation is not None:
        workflow_href = f"/workflow?delegation_id={quote(latest_delegation.id)}"
        workflow_label = "Open delegation workflow"
        workflow_summary = f"delegation={latest_delegation.status}"
        latest_run_id = "none"
    else:
        workflow_href = "/workflow"
        workflow_label = "Open workflow"
        workflow_summary = "no workflow artifacts yet"
        latest_run_id = "none"
    latest_delegation_id = latest_delegation.id if latest_delegation is not None else "none"

    if open_incidents:
        waiting_href = "/incidents"
        waiting_label = "Inspect incidents"
        waiting_summary = f"{open_incidents} incident(s)"
    elif pending_approvals:
        waiting_href = "/approvals"
        waiting_label = "Review approvals"
        waiting_summary = f"{pending_approvals} approval(s)"
    elif open_recommendations:
        waiting_href = "/incidents"
        waiting_label = "Review recommendations"
        waiting_summary = f"{open_recommendations} recommendation(s)"
    else:
        waiting_href = lead_goal_href
        waiting_label = lead_goal_action
        waiting_summary = "no waiting items"

    if not goal_rows:
        status = "needs_goal"
    elif waiting_items:
        status = "attention_ready"
    elif lead_phase in {"Ready to commit", "Ready to publish", "Ready to run", "Waiting for approval", "Needs review"}:
        status = "goal_action_ready"
    else:
        status = "goal_ready"

    cards = [
        (
            "lead",
            "Lead Goal",
            _compact_label(lead_goal_label, 92),
            lead_goal_href,
            lead_goal_action,
            "primary",
        ),
        (
            "phase",
            "Phase",
            lead_phase,
            lead_goal_href,
            "Open phase" if lead_goal_id else "Start Goal",
            "",
        ),
        (
            "work",
            "Work",
            workflow_summary,
            workflow_href,
            workflow_label,
            "",
        ),
        (
            "waiting",
            "Waiting",
            waiting_summary,
            waiting_href,
            waiting_label,
            "",
        ),
        (
            "finish",
            "Finish",
            "Save this project return point",
            "#project-finish-today",
            "Finish Today",
            "",
        ),
    ]
    card_html: list[str] = []
    lines: list[str] = []
    for key, title, summary, href, label, kind in cards:
        class_name = "project-goal-map-card"
        if kind == "primary":
            class_name += " project-goal-map-primary"
        card_html.append(
            f"<article class='{class_name}' data-project-goal-card='{_e(key)}'>"
            f"<h3>{_e(title)}</h3>"
            f"<p>{_e(summary)}</p>"
            f"<a class='project-goal-map-link' href='{_e(href)}'>{_e(label)}</a>"
            "</article>"
        )
        lines.append(
            f"project_goal_map_card: {_e(key)} surface=<a href='{_e(href)}'>{_e(label)}</a>"
        )

    return "".join(
        [
            "<section id='project-goal-map' class='panel project-goal-map' data-project-goal-map='true'><h2>Project Goal Map</h2>",
            "<p class='muted'>The project-to-Goal bridge: pick the lead Goal, check its phase, continue work, clear waiting items, or save the return point.</p>",
            "<div class='project-goal-map-grid' data-project-goal-map-actions='true'>",
            "".join(card_html),
            "</div>",
            "<details class='project-goal-map-evidence' data-project-goal-map-evidence='true'><summary>Project goal map evidence</summary>",
            _kv(
                [
                    ("project_goal_map_status", status),
                    ("project_goal_map_project", project_id),
                    (
                        "project_goal_map_lead_goal",
                        SafeHtml(f"<a href='{_e(lead_goal_href)}'>{_e(lead_goal_id)}</a>")
                        if lead_goal_id
                        else "none",
                    ),
                    ("project_goal_map_lead_goal_label", lead_goal_label),
                    ("project_goal_map_lead_goal_phase", lead_phase),
                    ("project_goal_map_lead_goal_next_action", lead_next.action),
                    ("project_goal_map_active_goals", str(len(active_goals))),
                    ("project_goal_map_paused_goals", str(len(paused_goals))),
                    ("project_goal_map_completed_goals", str(len(completed_goals))),
                    ("project_goal_map_total_goals", str(len(goal_rows))),
                    ("project_goal_map_tasks", str(len(task_rows))),
                    ("project_goal_map_delegations", str(len(delegations))),
                    ("project_goal_map_coder_runs", str(len(operator_state["worktree_runs"]))),
                    ("project_goal_map_latest_delegation", latest_delegation_id),
                    ("project_goal_map_latest_run", latest_run_id),
                    ("project_goal_map_pending_approvals", str(pending_approvals)),
                    ("project_goal_map_open_incidents", str(open_incidents)),
                    ("project_goal_map_open_recommendations", str(open_recommendations)),
                    ("project_goal_map_waiting_items", str(waiting_items)),
                    (
                        "project_goal_map_goal_surface",
                        SafeHtml(f"<a href='{_e(lead_goal_href)}'>{_e(lead_goal_action)}</a>"),
                    ),
                    (
                        "project_goal_map_workflow_surface",
                        SafeHtml(f"<a href='{_e(workflow_href)}'>{_e(workflow_label)}</a>"),
                    ),
                    (
                        "project_goal_map_waiting_surface",
                        SafeHtml(f"<a href='{_e(waiting_href)}'>{_e(waiting_label)}</a>"),
                    ),
                    (
                        "project_goal_map_finish_surface",
                        SafeHtml("<a href='#project-finish-today'>Finish Today</a>"),
                    ),
                    (
                        "project_goal_map_start_surface",
                        SafeHtml(
                            f"<a href='{_e(start_href)}'>Start Goal For This Project</a>"
                        ),
                    ),
                    ("project_goal_map_card_count", str(len(cards))),
                    ("project_goal_map_source", "project_goal_rows_and_operator_state"),
                    ("project_goal_map_write_on_get", "false"),
                    ("project_goal_map_provider_calls_taken", "0"),
                    ("project_goal_map_network_actions_taken", "0"),
                    ("project_goal_map_external_effects_created", "false"),
                    ("project_goal_map_push_created", "false"),
                    ("project_goal_map_pr_created", "false"),
                    ("project_goal_map_deploy_created", "false"),
                ]
            ),
            _ul(lines + ["project_goal_map_safety: read-only project-to-goal guidance; confirmed forms own writes"]),
            "</details>",
            "</section>",
        ]
    )


def _project_operator_guidance(
    root: Path,
    storage: Storage,
    *,
    project_id: str,
    task_rows: list[sqlite3.Row],
    operator_state: dict[str, Any] | None = None,
) -> str:
    state = operator_state or _project_operator_state(
        root,
        storage,
        project_id=project_id,
        task_rows=task_rows,
    )
    incidents = state["incidents"]
    open_incidents = state["open_incidents"]
    recommendations = state["recommendations"]
    worktree_approvals = state["worktree_approvals"]
    worktree_runs = state["worktree_runs"]
    commit_approvals = state["commit_approvals"]
    publications = state["publications"]
    completed_runs = [item for item in worktree_runs if item.status == "completed"]
    reviewed_runs = [
        item
        for item in completed_runs
        if _run_review_gate_state(root, item)["commit_request_form_available"]
    ]
    guidance = "<section><h2>Project Operator Guidance</h2>" + _kv(
        [
            (
                "project_next_recommended_action",
                _project_next_action(
                    root,
                    open_incidents=open_incidents,
                    recommendations=recommendations,
                    worktree_approvals=worktree_approvals,
                    worktree_runs=worktree_runs,
                    commit_approvals=commit_approvals,
                    publications=publications,
                ),
            ),
            ("tasks", str(len(task_rows))),
            ("open_project_incidents", str(len(open_incidents))),
            ("task_recommendations", str(len(recommendations))),
            (
                "pending_worktree_approvals",
                str(_count_status(worktree_approvals, "pending_operator_approval")),
            ),
            ("completed_worktree_runs", str(len(completed_runs))),
            ("reviewed_completed_worktree_runs", str(len(reviewed_runs))),
            (
                "pending_commit_approvals",
                str(_count_status(commit_approvals, "pending_operator_approval")),
            ),
            ("local_commits", str(_count_status(commit_approvals, "committed"))),
            (
                "pending_publication_approvals",
                str(_count_status(publications, "pending_operator_approval")),
            ),
            ("publication_handoffs", str(_count_status(publications, "ready_for_operator"))),
        ]
    ) + "</section>"
    incident_lines = [
        f"{_e(row['id'])}: status={_e(row['status'])} severity={_e(row['severity'])} "
        f"{_e(row['summary'])} evidence={_artifact_link(row['evidence_path'] or 'none')}"
        for row in incidents
    ]
    recommendation_lines = [
        _task_recommendation_line(item)
        for item in recommendations
    ]
    return guidance + _list_section(
        "Incidents / Recommendations",
        incident_lines + recommendation_lines,
        "/incidents" if incidents else None,
    )


def _project_workflow_launchpad(
    root: Path,
    storage: Storage,
    *,
    project_id: str,
    delegations: list[Any],
) -> str:
    coder_runs = [
        item
        for item in list_coder_worktree_runs(root, limit=100)
        if item.project_id == project_id
    ]
    project_lines = [
        "project_workflow_stage: project_ready",
        "<a href='/workflow'>open full workflow stepper</a>",
        "<a href='/actions'>open safe action catalog</a>",
        "<a href='/dogfooding'>open manual dogfooding checklist</a>",
        "<a href='/verification'>open verification handoff</a>",
    ]
    delegation_lines = [
        f"<a href='/delegations/{quote(delegation.id)}'>{_e(delegation.id)}</a>: "
        f"<a href='/workflow?delegation_id={quote(delegation.id)}'>selected workflow</a> "
        f"status={_e(delegation.status)} title={_e(delegation.title)}"
        for delegation in delegations[:10]
    ]
    run_lines = [
        f"<a href='/runs/{quote(run.id)}'>{_e(run.id)}</a>: "
        f"<a href='/workflow?run_id={quote(run.id)}'>selected workflow</a> "
        f"status={_e(run.status)} changed_files={_e(str(len(run.changed_files)))}"
        for run in coder_runs[:10]
    ]
    return "".join(
        [
            "<section><h2>Project Workflow Launchpad</h2>",
            _ul(project_lines),
            "</section>",
            _list_section("Launch Delegation Workflows", delegation_lines),
            _list_section("Launch Coder Run Workflows", run_lines),
        ]
    )


def _project_operator_state(
    root: Path,
    storage: Storage,
    *,
    project_id: str,
    task_rows: list[sqlite3.Row],
) -> dict[str, Any]:
    task_ids = [str(row["id"]) for row in task_rows]
    incidents = _table_rows(
        storage.db_path,
        "select id, status, severity, summary, evidence_path from incidents where project_id = ? order by created_at desc limit 20",
        (project_id,),
    )
    return {
        "incidents": incidents,
        "open_incidents": [row for row in incidents if row["status"] == "open"],
        "recommendations": _project_task_recommendations(storage, task_ids),
        "worktree_approvals": [
            item
            for item in list_coder_worktree_approvals(root, limit=100)
            if item.project_id == project_id
        ],
        "worktree_runs": [
            item
            for item in list_coder_worktree_runs(root, limit=100)
            if item.project_id == project_id
        ],
        "commit_approvals": [
            item
            for item in list_coder_worktree_commit_approvals(root, limit=100)
            if item.project_id == project_id
        ],
        "publications": [
            item
            for item in list_coder_publications(root, limit=100)
            if item.project_id == project_id
        ],
    }


def _project_task_recommendations(
    storage: Storage,
    task_ids: list[str],
) -> list[Any]:
    recommendations: list[Any] = []
    seen: set[str] = set()
    for task_id in task_ids:
        for item in storage.list_task_recommendations(
            task_id=task_id,
            status="open",
            limit=10,
        ):
            if item.id in seen:
                continue
            seen.add(item.id)
            recommendations.append(item)
    return recommendations[:20]


def _dashboard_next_action(root: Path, storage: Storage) -> DashboardNextAction:
    open_incidents = _table_rows(
        storage.db_path,
        "select id, project_id, summary from incidents "
        "where status = 'open' order by created_at desc limit 1",
    )
    if open_incidents:
        incident = open_incidents[0]
        return DashboardNextAction(
            "review_project_incidents",
            "/incidents",
            str(incident["id"]),
            str(incident["summary"]),
        )

    recommendations = _table_rows(
        storage.db_path,
        "select id, task_id, reason from task_recommendations "
        "where status = 'open' order by created_at desc limit 1",
    )
    if recommendations:
        recommendation = recommendations[0]
        return DashboardNextAction(
            "review_task_recommendations",
            "/incidents",
            str(recommendation["id"]),
            str(recommendation["reason"]),
        )

    publications = list_coder_publications(root, limit=200)
    for status, action, href in [
        ("ready_for_operator", "manual_operator_push_pr_outside_clankeros", None),
        ("approved", "prepare_publication_handoff", None),
        (
            "pending_operator_approval",
            "approve_or_reject_publication_request",
            "/approvals",
        ),
    ]:
        publication = next((item for item in publications if item.status == status), None)
        if publication is not None:
            return DashboardNextAction(
                action,
                href or f"/runs/{quote(publication.run_id)}",
                publication.run_id,
                f"publication_status={publication.status} project={publication.project_id}",
            )

    commit_approvals = list_coder_worktree_commit_approvals(root, limit=200)
    publication_run_ids = {item.run_id for item in publications}
    committed_without_publication = next(
        (
            item
            for item in commit_approvals
            if item.status == "committed" and item.run_id not in publication_run_ids
        ),
        None,
    )
    if committed_without_publication is not None:
        return DashboardNextAction(
            "request_publication_handoff",
            f"/runs/{quote(committed_without_publication.run_id)}",
            committed_without_publication.run_id,
            f"local_commit={committed_without_publication.commit_sha or 'recorded'}",
        )

    approved_commit = next(
        (item for item in commit_approvals if item.status == "approved"),
        None,
    )
    if approved_commit is not None:
        return DashboardNextAction(
            "commit_approved_worktree",
            f"/runs/{quote(approved_commit.run_id)}",
            approved_commit.run_id,
            f"commit_approval={approved_commit.id}",
        )

    pending_commit = next(
        (
            item
            for item in commit_approvals
            if item.status == "pending_operator_approval"
        ),
        None,
    )
    if pending_commit is not None:
        return DashboardNextAction(
            "approve_or_reject_commit_request",
            "/approvals",
            pending_commit.id,
            f"run={pending_commit.run_id}",
        )

    worktree_runs = list_coder_worktree_runs(root, limit=200)
    commit_run_ids = {item.run_id for item in commit_approvals}
    reviewed_run = next(
        (
            item
            for item in worktree_runs
            if item.status == "completed"
            and item.id not in commit_run_ids
            and _run_review_gate_state(root, item)["commit_request_form_available"]
        ),
        None,
    )
    if reviewed_run is not None:
        return DashboardNextAction(
            "request_commit_for_reviewed_run",
            f"/runs/{quote(reviewed_run.id)}",
            reviewed_run.id,
            f"review_exists_for_source_run={reviewed_run.source_run_id}",
        )

    worktree_approvals = list_coder_worktree_approvals(root, limit=200)
    pending_worktree = next(
        (
            item
            for item in worktree_approvals
            if item.status == "pending_operator_approval"
        ),
        None,
    )
    if pending_worktree is not None:
        return DashboardNextAction(
            "decide_pending_worktree_approval",
            "/approvals",
            pending_worktree.id,
            f"delegation={pending_worktree.delegation_id}",
        )

    run_delegation_ids = {item.delegation_id for item in worktree_runs}
    approved_worktree = next(
        (
            item
            for item in worktree_approvals
            if item.status == "approved" and item.delegation_id not in run_delegation_ids
        ),
        None,
    )
    if approved_worktree is not None:
        return DashboardNextAction(
            "run_approved_worktree_from_cli",
            f"/workflow?delegation_id={quote(approved_worktree.delegation_id)}",
            approved_worktree.delegation_id,
            f"worktree_approval={approved_worktree.id}",
        )

    project_count = len(storage.list_registered_projects())
    if project_count:
        return DashboardNextAction(
            "review_project_state",
            "/projects",
            f"projects={project_count}",
            "no higher-priority approval, reviewed run, publication, incident, or recommendation is pending",
        )
    return DashboardNextAction(
        "run_demo_scenario_or_register_project",
        "/demo",
        "no_registered_projects",
        "create fixture state or register a real local project",
    )


def _dashboard_next_action_section(next_action: DashboardNextAction) -> str:
    return "<section><h2>Next Recommended Action</h2>" + _kv(
        [
            ("dashboard_next_recommended_action", next_action.action),
            ("target", next_action.target),
            ("reason", next_action.reason),
            (
                "open_surface",
                SafeHtml(
                    f"<a href='{_e(next_action.href)}'>{_e(next_action.href)}</a>"
                ),
            ),
        ]
    ) + (
        "<p class='muted'>This is read-only operator guidance; it does not "
        "execute approvals, commits, publication handoffs, pushes, PRs, "
        "deploys, provider calls, or external mutations.</p></section>"
    )


def _project_next_action(
    root: Path,
    *,
    open_incidents: list[Any],
    recommendations: list[Any],
    worktree_approvals: list[Any],
    worktree_runs: list[Any],
    commit_approvals: list[Any],
    publications: list[Any],
) -> str:
    if open_incidents:
        return "review_project_incidents"
    if recommendations:
        return "review_task_recommendations"
    if _count_status(publications, "ready_for_operator"):
        return "manual_operator_push_pr_outside_clankeros"
    if _count_status(publications, "approved"):
        return "prepare_publication_handoff"
    if _count_status(publications, "pending_operator_approval"):
        return "approve_or_reject_publication_request"
    if _count_status(commit_approvals, "committed") and not publications:
        return "request_publication_handoff"
    if _count_status(commit_approvals, "approved"):
        return "commit_approved_worktree"
    if _count_status(commit_approvals, "pending_operator_approval"):
        return "approve_or_reject_commit_request"
    reviewed_runs = [
        item
        for item in worktree_runs
        if item.status == "completed"
        and _run_review_gate_state(root, item)["commit_request_form_available"]
    ]
    if reviewed_runs and not commit_approvals:
        return "request_commit_for_reviewed_run"
    if _count_status(worktree_approvals, "pending_operator_approval"):
        return "decide_pending_worktree_approval"
    if _count_status(worktree_approvals, "approved") and not worktree_runs:
        return "run_approved_worktree_from_cli"
    return "review_project_state"


def _task_recommendation_line(item: Any) -> str:
    commands = ", ".join(item.recommended_commands) or "none"
    return (
        f"{_e(item.id)}: status={_e(item.status)} task={_e(item.task_id)} "
        f"type={_e(item.recommendation_type)} reason={_e(item.reason)} "
        f"commands={_e(commands)} evidence={_artifact_link(item.evidence_path)}"
    )


def _delegation_detail(root: Path, delegation_id: str) -> str:
    storage = _storage(root)
    delegation = storage.get_subagent_delegation(delegation_id)
    if delegation is None:
        return "<p class='error'>Delegation not found.</p>"
    summary = summarize_implementation_handoff(root, delegation)
    metadata = load_delegation_result_metadata(delegation)
    run_id = summary.get("run_id") or metadata.get("execution_run_id") or "unknown"
    sections = [
        f"<section><h1>Delegation {_e(delegation.id)}</h1>",
        _kv(
            [
                ("status", delegation.status),
                ("profile", delegation.assigned_profile),
                ("category", delegation.category),
                ("parent_task_id", delegation.parent_task_id),
                ("run_id", str(run_id)),
                ("result_summary", delegation.result_summary or "none"),
            ]
        ),
        "</section>",
        _handoff_block(summary),
        _delegation_workflow_readiness(root, delegation, summary),
        _list_section("Coder Prep", _artifact_links(list_coder_prep_packets(root), delegation_id=delegation_id)),
        _list_section("Coder Worktree Plan", _artifact_links(list_coder_worktree_plan_packets(root), delegation_id=delegation_id)),
        _list_section("Worktree Approvals", [_approval_line(item) for item in list_coder_worktree_approvals(root, delegation_id=delegation_id, limit=20)]),
        _list_section(
            "Worktree Runs",
            [
                _coder_run_line(root, item)
                for item in list_coder_worktree_runs(
                    root,
                    delegation_id=delegation_id,
                    limit=20,
                )
            ],
        ),
        _list_section("Commit Requests / Local Commits", [_commit_line(item) for item in list_coder_worktree_commit_approvals(root, delegation_id=delegation_id, limit=20)]),
        _list_section("Publication Requests / Handoffs", [_publication_line(root, item) for item in list_coder_publications(root, delegation_id=delegation_id, limit=20)]),
        _safe_action_forms(
            delegation_id=delegation_id,
            handoff_md=str(summary["markdown_path"]),
        ),
    ]
    return "".join(sections)


def _run_detail(root: Path, run_id: str) -> str:
    storage = _storage(root)
    run = storage.get_run(run_id) if _row_exists(storage.db_path, "runs", run_id) else None
    coder_runs = [item for item in list_coder_worktree_runs(root, limit=50) if item.id == run_id]
    delegation_run = _delegation_for_execution_run(storage, run_id)
    if run is None and not coder_runs and delegation_run is None:
        return "<p class='error'>Run not found.</p>"
    parts = [f"<section><h1>Run {_e(run_id)}</h1>"]
    if run is not None:
        parts.append(
            _kv(
                [
                    ("goal_id", run.goal_id),
                    ("project_id", run.project_id),
                    ("status", run.status),
                    ("summary_path", run.summary_path or "none"),
                    ("events_path", run.events_path or "none"),
                ]
            )
        )
    for coder_run in coder_runs:
        evidence_path = Path(coder_run.evidence_path)
        review_path = Path("runs") / coder_run.source_run_id / "review.md"
        evidence_links = [
            ("review", str(review_path)),
            ("run_json", str(evidence_path / "run.json")),
            ("diff", str(evidence_path / "diff.patch")),
            ("changed_files", str(evidence_path / "changed_files.json")),
            ("bounded_file_validation", str(evidence_path / "bounded_file_validation.json")),
            ("git_status", str(evidence_path / "git_status.txt")),
            ("stdout", str(evidence_path / "stdout.txt")),
            ("stderr", str(evidence_path / "stderr.txt")),
            ("verification_stdout", str(evidence_path / "verification_stdout.txt")),
            ("verification_stderr", str(evidence_path / "verification_stderr.txt")),
        ]
        parts.append(
            _kv(
                [
                    ("coder_worktree_status", coder_run.status),
                    ("delegation_id", coder_run.delegation_id),
                    ("source_run_id", coder_run.source_run_id),
                    ("worktree_path", coder_run.worktree_path),
                    ("branch_name", coder_run.branch_name),
                    ("changed_files", ", ".join(coder_run.changed_files) or "none"),
                    ("outside_allowed_files", ", ".join(coder_run.outside_allowed_files) or "none"),
                    ("verification_exit_code", str(coder_run.verification_exit_code)),
                    ("evidence_path", coder_run.evidence_path),
                ]
            )
        )
        parts.append(_run_command_bar(root, coder_run))
        parts.append(_run_operator_workbench(root, coder_run))
        parts.append(_run_gate_map(root, coder_run))
        parts.append(_run_continuation_strip(root, coder_run))
        parts.append(_run_workflow_state(root, coder_run))
        parts.append(_run_review_gate(root, coder_run))
        parts.append(_run_evidence_map(root, coder_run))
        parts.append(
            _list_section(
                "Coder Worktree Evidence",
                [
                    f"{_e(label)}: {_artifact_link(path)}"
                    for label, path in evidence_links
                    if (root / path).exists()
                ],
                anchor_id="coder-worktree-evidence",
            )
        )
        parts.append(_run_action_forms(root, coder_run.id))
    if delegation_run is not None:
        delegation, metadata = delegation_run
        parts.append(_delegation_execution_run_detail(root, storage, delegation, metadata, run_id))
    parts.append("</section>")
    return "".join(parts)


def _delegation_for_execution_run(
    storage: Storage,
    run_id: str,
) -> tuple[Any, dict[str, Any]] | None:
    for delegation in storage.list_recent_subagent_delegations(limit=None):
        metadata = load_delegation_result_metadata(delegation)
        metadata_run_id = metadata.get("execution_run_id") or metadata.get("run_id")
        if metadata_run_id == run_id:
            return delegation, metadata
    return None


def _delegation_execution_run_detail(
    root: Path,
    storage: Storage,
    delegation: Any,
    metadata: dict[str, Any],
    run_id: str,
) -> str:
    summary = summarize_implementation_handoff(root, delegation)
    project_id = str(metadata.get("target_project_id") or _task_project(storage, delegation.parent_task_id))
    evidence_dir = str(metadata.get("execution_evidence_dir") or metadata.get("evidence_dir") or "none")
    next_action = _delegation_run_next_action(delegation, metadata)
    context_pack_status = "available" if (
        metadata.get("context_pack_json") or metadata.get("context_pack_md")
    ) else "missing"
    implementation_handoff_status = "available" if (
        metadata.get("implementation_handoff_json") or metadata.get("implementation_handoff_md")
    ) else "missing"
    retry_candidate = str(
        delegation.status != "completed" or bool(metadata.get("incident_id"))
    ).lower()
    return "".join(
        [
            _delegation_run_continuation_strip(
                root,
                delegation=delegation,
                metadata=metadata,
                run_id=run_id,
                project_id=project_id,
                next_action=next_action,
                context_pack_status=context_pack_status,
                implementation_handoff_status=implementation_handoff_status,
                retry_candidate=retry_candidate,
            ),
            "<section><h2>Delegation Run Evidence</h2>",
            _kv(
                [
                    ("delegation_id", SafeHtml(f"<a href='/delegations/{quote(delegation.id)}'>{_e(delegation.id)}</a>")),
                    ("run_id", run_id),
                    ("status", delegation.status),
                    ("project_id", project_id),
                    ("profile", delegation.assigned_profile),
                    ("category", delegation.category),
                    ("parent_task_id", delegation.parent_task_id),
                    ("result_summary", delegation.result_summary or "none"),
                    ("evidence_dir", evidence_dir),
                    ("provider_calls_taken_by_clankeros", str(metadata.get("provider_calls_taken_by_clankeros", "unknown"))),
                    ("network_actions_taken", str(metadata.get("network_actions_taken", "unknown"))),
                    ("external_mutations_taken", str(metadata.get("external_mutations_taken", "unknown"))),
                    ("incident", str(metadata.get("incident_id") or "none")),
                    ("retry_candidate", retry_candidate),
                    ("next_recommended_action", next_action),
                ]
            ),
            "</section>",
            _list_section(
                "Delegation Execution Artifacts",
                _delegation_execution_artifact_lines(root, delegation, metadata),
                anchor_id="delegation-execution-artifacts",
            ),
            "<section><h2>Delegation Run Workflow State</h2>",
            _kv(
                [
                    ("context_pack_status", context_pack_status),
                    ("context_pack", _artifact_link(str(metadata.get("context_pack_md") or metadata.get("context_pack_json") or "none"))),
                    ("implementation_handoff_status", implementation_handoff_status),
                    ("implementation_handoff", _artifact_link(str(metadata.get("implementation_handoff_md") or metadata.get("implementation_handoff_json") or "none"))),
                    ("implementation_handoff_readback", str(summary["status"])),
                    ("coder_prep_status", _delegation_packet_status(list_coder_prep_packets(root), delegation.id)),
                    ("coder_worktree_plan_status", _delegation_packet_status(list_coder_worktree_plan_packets(root), delegation.id)),
                    ("next_recommended_action", next_action),
                ]
            ),
            "</section>",
        ]
    )


def _delegation_run_continuation_strip(
    root: Path,
    *,
    delegation: Any,
    metadata: dict[str, Any],
    run_id: str,
    project_id: str,
    next_action: str,
    context_pack_status: str,
    implementation_handoff_status: str,
    retry_candidate: str,
) -> str:
    goal_id = delegation.parent_goal_id or ""
    action_label = _delegation_run_action_label(next_action)
    delegation_href = f"/delegations/{quote(delegation.id)}"
    run_href = f"/runs/{quote(run_id)}"
    safe_actions_href = f"{delegation_href}#safe-local-actions"
    workflow_href = f"/workflow?delegation_id={quote(delegation.id)}"
    goal_href = f"/goals/{quote(goal_id)}" if goal_id else "/goals"
    goal_label = f"/goals/{goal_id}" if goal_id else "/goals"
    result_artifact = _repo_relative_artifact_path(root, delegation.result_artifact_path)
    evidence_dir = str(metadata.get("execution_evidence_dir") or metadata.get("evidence_dir") or "none")
    incident_id = str(metadata.get("incident_id") or "none")
    inline_action = _delegation_run_continuation_inline_action(
        root,
        delegation=delegation,
        metadata=metadata,
        run_id=run_id,
        project_id=project_id,
        goal_id=goal_id,
        next_action=next_action,
        run_href=run_href,
        safe_actions_href=safe_actions_href,
    )
    if incident_id != "none":
        primary_href = "/incidents"
        primary_label = "/incidents"
        continuation_status = "needs_attention"
        reason = f"incident={incident_id}"
    elif inline_action["available"]:
        primary_href = "#delegation-run-continuation-action-form"
        primary_label = action_label
        continuation_status = "action_form_ready"
        reason = next_action
    elif next_action in {
        "prepare_coder_from_handoff",
        "create_implementation_handoff",
        "run_delegation",
    }:
        primary_href = safe_actions_href
        primary_label = "Safe Local Actions"
        continuation_status = "action_form_unavailable"
        reason = str(inline_action["blocked_reason"])
    elif next_action == "review_delegation_result":
        primary_href = "#delegation-execution-artifacts"
        primary_label = "Delegation Execution Artifacts"
        continuation_status = "review_ready"
        reason = "delegation_result_available"
    else:
        primary_href = delegation_href
        primary_label = "Delegation"
        continuation_status = "navigation_ready"
        reason = next_action
    handoff_path = str(
        metadata.get("implementation_handoff_md")
        or metadata.get("implementation_handoff_json")
        or "none"
    )
    context_pack_path = str(
        metadata.get("context_pack_md")
        or metadata.get("context_pack_json")
        or "none"
    )
    action_form_available = bool(inline_action["available"])
    action_form_surface: str | SafeHtml = (
        SafeHtml(f"<a href='#delegation-run-continuation-action-form'>{_e(action_label)}</a>")
        if action_form_available
        else "none"
    )
    source_primary_surface = SafeHtml(f"<a href='{_e(safe_actions_href)}'>Safe Local Actions</a>")
    return "".join(
        [
            (
                "<section id='delegation-run-continuation' "
                "class='panel delegation-run-continuation' "
                "data-delegation-run-continuation='true'>"
                "<h2>Delegation Run Continuation</h2>"
            ),
            "<p class='muted'>One handoff for continuing scout evidence into context review, coder prep, workflow inspection, or incident triage.</p>",
            "<div class='delegation-run-continuation-grid' data-delegation-run-continuation-actions='true'>",
            "<article class='delegation-run-continuation-card delegation-run-continuation-primary'><h3>Now</h3>",
            f"<p>{_e(action_label)}</p>",
            f"<a class='delegation-run-continuation-action' href='{_e(primary_href)}'>{_e(primary_label)}</a></article>",
            "<article class='delegation-run-continuation-card'><h3>Workflow</h3>",
            "<p>See context, handoff, prep, and worktree gates.</p>",
            f"<a class='delegation-run-continuation-link' href='{_e(workflow_href)}'>Workflow</a></article>",
            "<article class='delegation-run-continuation-card'><h3>Handoff</h3>",
            f"<p>Context {context_pack_status}; handoff {implementation_handoff_status}.</p>",
            f"<a class='delegation-run-continuation-link' href='{_e(safe_actions_href)}'>Safe actions</a></article>",
            "<article class='delegation-run-continuation-card'><h3>Artifacts</h3>",
            f"<p>{_e(result_artifact)}</p>",
            "<a class='delegation-run-continuation-link' href='#delegation-execution-artifacts'>Open artifacts</a></article>",
            "<article class='delegation-run-continuation-card'><h3>Goal</h3>",
            f"<p>{_e(goal_id or 'No parent Goal found')}</p>",
            f"<a class='delegation-run-continuation-link' href='{_e(goal_href)}'>Return to Goal</a></article>",
            "</div>",
            str(inline_action["html"]),
            "<details class='delegation-run-continuation-evidence' data-delegation-run-continuation-evidence='true'><summary>Delegation run continuation evidence</summary>",
            _kv(
                [
                    ("delegation_run_continuation_status", continuation_status),
                    ("delegation_run_continuation_run_id", run_id),
                    ("delegation_run_continuation_delegation", SafeHtml(f"<a href='{_e(delegation_href)}'>{_e(delegation.id)}</a>")),
                    ("delegation_run_continuation_goal", goal_id or "none"),
                    ("delegation_run_continuation_project", project_id),
                    ("delegation_run_continuation_profile", delegation.assigned_profile),
                    ("delegation_run_continuation_category", delegation.category),
                    ("delegation_run_continuation_delegation_status", delegation.status),
                    ("delegation_run_continuation_next_action", next_action),
                    ("delegation_run_continuation_action_label", action_label),
                    (
                        "delegation_run_continuation_primary_surface",
                        SafeHtml(f"<a href='{_e(primary_href)}'>{_e(primary_label)}</a>"),
                    ),
                    ("delegation_run_continuation_source_primary_surface", source_primary_surface),
                    ("delegation_run_continuation_reason", reason),
                    (
                        "delegation_run_continuation_workflow_surface",
                        SafeHtml(f"<a href='{_e(workflow_href)}'>Workflow</a>"),
                    ),
                    (
                        "delegation_run_continuation_safe_actions_surface",
                        SafeHtml(f"<a href='{_e(safe_actions_href)}'>Safe Local Actions</a>"),
                    ),
                    ("delegation_run_continuation_action_form_available", str(action_form_available).lower()),
                    (
                        "delegation_run_continuation_action_form_surface",
                        action_form_surface,
                    ),
                    (
                        "delegation_run_continuation_action_form_kind",
                        str(inline_action["kind"]),
                    ),
                    (
                        "delegation_run_continuation_action_form_action",
                        str(inline_action["action"]),
                    ),
                    (
                        "delegation_run_continuation_action_form_blocked_reason",
                        str(inline_action["blocked_reason"]),
                    ),
                    (
                        "delegation_run_continuation_confirmation_required",
                        str(bool(inline_action["confirmation_required"])).lower(),
                    ),
                    ("delegation_run_continuation_context_pack_status", context_pack_status),
                    ("delegation_run_continuation_context_pack", _artifact_link(context_pack_path)),
                    (
                        "delegation_run_continuation_implementation_handoff_status",
                        implementation_handoff_status,
                    ),
                    ("delegation_run_continuation_implementation_handoff", _artifact_link(handoff_path)),
                    (
                        "delegation_run_continuation_artifacts_surface",
                        SafeHtml("<a href='#delegation-execution-artifacts'>Delegation Execution Artifacts</a>"),
                    ),
                    ("delegation_run_continuation_result_artifact", _artifact_link(result_artifact)),
                    ("delegation_run_continuation_evidence_dir", evidence_dir),
                    (
                        "delegation_run_continuation_goal_surface",
                        SafeHtml(f"<a href='{_e(goal_href)}'>{_e(goal_label)}</a>"),
                    ),
                    ("delegation_run_continuation_incident", incident_id),
                    ("delegation_run_continuation_retry_candidate", retry_candidate),
                    ("delegation_run_continuation_source", "delegation_execution_run_metadata"),
                    ("delegation_run_continuation_write_on_get", "false"),
                    ("delegation_run_continuation_provider_calls_taken", "0"),
                    ("delegation_run_continuation_network_actions_taken", "0"),
                    ("delegation_run_continuation_external_effects_created", "false"),
                    ("delegation_run_continuation_push_created", "false"),
                    ("delegation_run_continuation_pr_created", "false"),
                    ("delegation_run_continuation_deploy_created", "false"),
                ]
            ),
            _ul(
                [
                    f"delegation_run_continuation_now: {_e(action_label)}",
                    f"delegation_run_continuation_click: <a href='{_e(primary_href)}'>{_e(primary_label)}</a>",
                    f"delegation_run_continuation_source: <a href='{_e(safe_actions_href)}'>Safe Local Actions</a>",
                    (
                        "delegation_run_continuation_action_form: "
                        f"available={str(action_form_available).lower()} "
                        f"action={_e(str(inline_action['action']))} "
                        f"source=<a href='{_e(safe_actions_href)}'>Safe Local Actions</a>"
                    ),
                    f"delegation_run_continuation_workflow: <a href='{_e(workflow_href)}'>Workflow</a>",
                    f"delegation_run_continuation_safe_actions: <a href='{_e(safe_actions_href)}'>Safe Local Actions</a>",
                    "delegation_run_continuation_artifacts: <a href='#delegation-execution-artifacts'>Delegation Execution Artifacts</a>",
                    f"delegation_run_continuation_goal: <a href='{_e(goal_href)}'>{_e(goal_label)}</a>",
                    "delegation_run_continuation_safety: read-only delegation run continuation; confirmed forms own writes",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _delegation_run_continuation_inline_action(
    root: Path,
    *,
    delegation: Any,
    metadata: dict[str, Any],
    run_id: str,
    project_id: str,
    goal_id: str,
    next_action: str,
    run_href: str,
    safe_actions_href: str,
) -> dict[str, str | bool | SafeHtml]:
    common_fields = {
        "delegation_id": delegation.id,
        "run_id": run_id,
        "return_to": run_href,
        "resume_surface": run_href,
        "open_project": "" if project_id == "none" else project_id,
        "open_goal": goal_id,
    }
    action = "none"
    kind = "none"
    blocked_reason = "next_action_not_form_backed"
    title = _delegation_run_action_label(next_action)
    body = "Continue this delegation from the run page."
    fields = dict(common_fields)
    artifact_label = "none"
    artifact_value: str | SafeHtml = "none"
    if next_action == "prepare_coder_from_handoff":
        handoff_md = str(metadata.get("implementation_handoff_md") or "").strip()
        if handoff_md:
            action = "coder-prep-from-handoff"
            kind = "coder_prep_from_handoff"
            blocked_reason = "none"
            fields["handoff_md"] = handoff_md
            artifact_label = "implementation_handoff_md"
            artifact_value = _artifact_link(handoff_md)
            body = "Convert the reviewed implementation handoff into a bounded coder-prep packet."
        elif metadata.get("implementation_handoff_json"):
            blocked_reason = "implementation_handoff_markdown_missing"
        else:
            blocked_reason = "implementation_handoff_missing"
    elif next_action == "create_implementation_handoff":
        action = "implementation-handoff"
        kind = "implementation_handoff"
        blocked_reason = "none"
        artifact_label = "delegation"
        artifact_value = SafeHtml(f"<a href='{_e(safe_actions_href)}'>Safe Local Actions</a>")
        body = "Review or create the implementation handoff summary for this delegation."
    elif next_action == "run_delegation":
        action = "run-delegation"
        kind = "run_delegation"
        blocked_reason = "none"
        fields["operator_id"] = "operator"
        artifact_label = "delegation"
        artifact_value = SafeHtml(f"<a href='{_e(safe_actions_href)}'>Safe Local Actions</a>")
        body = "Run the local delegation adapter through the existing confirmation gate."

    available = action != "none" and blocked_reason == "none"
    confirmation_required = bool(available and action != "implementation-handoff")
    if not available:
        return {
            "html": SafeHtml(""),
            "available": False,
            "kind": kind,
            "action": action,
            "blocked_reason": blocked_reason,
            "confirmation_required": False,
        }
    html = "".join(
        [
            (
                "<section id='delegation-run-continuation-action-form' "
                "class='delegation-run-continuation-action-form' "
                "data-delegation-run-continuation-action-form='true' "
                f"data-delegation-run-continuation-action-kind='{_e(kind)}' "
                f"data-delegation-run-continuation-action-name='{_e(action)}' "
                f"data-delegation-run-continuation-action-delegation='{_e(delegation.id)}' "
                f"data-delegation-run-continuation-action-run='{_e(run_id)}' "
                f"data-delegation-run-continuation-confirmation-required='{str(confirmation_required).lower()}'>"
            ),
            f"<h3>{_e(title)}</h3>",
            f"<p class='muted'>{_e(body)}</p>",
            _form(action, fields),
            "<details class='delegation-run-continuation-action-evidence' data-delegation-run-continuation-action-evidence='true'><summary>Inline action evidence</summary>",
            _kv(
                [
                    ("continuation_action", action),
                    ("continuation_action_kind", kind),
                    ("continuation_action_run", run_id),
                    (
                        "continuation_action_delegation",
                        SafeHtml(f"<a href='{_e(safe_actions_href)}'>{_e(delegation.id)}</a>"),
                    ),
                    ("continuation_action_return_to", SafeHtml(f"<a href='{_e(run_href)}'>{_e(run_href)}</a>")),
                    ("continuation_action_resume_surface", SafeHtml(f"<a href='{_e(run_href)}'>{_e(run_href)}</a>")),
                    ("continuation_action_project", common_fields["open_project"] or "none"),
                    ("continuation_action_goal", goal_id or "none"),
                    (artifact_label, artifact_value),
                    ("continuation_action_confirmation_required", str(confirmation_required).lower()),
                    ("continuation_action_source_surface", SafeHtml(f"<a href='{_e(safe_actions_href)}'>Safe Local Actions</a>")),
                    ("continuation_action_write_on_get", "false"),
                    ("continuation_action_provider_calls_taken", "0"),
                    ("continuation_action_network_actions_taken", "0"),
                    ("continuation_action_external_effects_created", "false"),
                ]
            ),
            "</details>",
            "</section>",
        ]
    )
    return {
        "html": SafeHtml(html),
        "available": True,
        "kind": kind,
        "action": action,
        "blocked_reason": "none",
        "confirmation_required": confirmation_required,
    }


def _delegation_execution_artifact_lines(
    root: Path,
    delegation: Any,
    metadata: dict[str, Any],
) -> list[str]:
    artifacts: list[tuple[str, str]] = [
        ("result_artifact", _repo_relative_artifact_path(root, delegation.result_artifact_path)),
        ("context_pack_json", str(metadata.get("context_pack_json") or "none")),
        ("context_pack_md", str(metadata.get("context_pack_md") or "none")),
        ("implementation_handoff_json", str(metadata.get("implementation_handoff_json") or "none")),
        ("implementation_handoff_md", str(metadata.get("implementation_handoff_md") or "none")),
    ]
    evidence_dir = metadata.get("execution_evidence_dir") or metadata.get("evidence_dir")
    if evidence_dir:
        for filename in [
            "input.json",
            "prompt.md",
            "stdout.txt",
            "stderr.txt",
            "raw_output.txt",
            "parsed_output.json",
            "validation.json",
            "result.json",
            "project.json",
            "repo_files.json",
            "context_pack_metadata.json",
        ]:
            artifacts.append((filename, str(Path(str(evidence_dir)) / filename)))
    lines = []
    seen: set[str] = set()
    for label, path in artifacts:
        if not path or path == "none" or path in seen:
            continue
        seen.add(path)
        if (root / path).exists():
            lines.append(f"{_e(label)}: {_artifact_link(path)}")
    return lines


def _delegation_packet_status(packets: list[dict[str, Any]], delegation_id: str) -> str:
    return "available" if any(
        packet.get("source", {}).get("delegation_id") == delegation_id
        for packet in packets
    ) else "missing"


def _run_command_bar(root: Path, coder_run: Any) -> str:
    commit_approvals = [
        item
        for item in list_coder_worktree_commit_approvals(root, limit=50)
        if item.run_id == coder_run.id
    ]
    publications = [
        item
        for item in list_coder_publications(root, limit=50)
        if item.run_id == coder_run.id
    ]
    review_gate = _run_review_gate_state(root, coder_run)
    change_summary = coder_worktree_change_summary(root, coder_run)
    next_action, target_href, target_label, reason = _run_command_next_action(
        coder_run,
        review_gate=review_gate,
        commit_approvals=commit_approvals,
        publications=publications,
    )
    target = SafeHtml(f"<a href='{_e(target_href)}'>{_e(target_label)}</a>")
    lines = [
        f"run_command_now: {_e(next_action)}",
        f"run_command_click: <a href='{_e(target_href)}'>{_e(target_label)}</a>",
        f"run_command_reason: {_e(reason)}",
        "run_command_safety: read-only run guidance",
    ]
    return "".join(
        [
            "<section class='panel run-command-bar' data-run-command-bar='true'><h2>Run Command Bar</h2>",
            "<p class='muted'>One read-only summary of the run gate, evidence posture, and next local operator action before the detailed evidence and forms.</p>",
            _kv(
                [
                    ("run_command_status", "available"),
                    ("run_command_run_id", coder_run.id),
                    ("run_command_project", coder_run.project_id),
                    ("run_command_delegation", SafeHtml(f"<a href='/delegations/{quote(coder_run.delegation_id)}'>{_e(coder_run.delegation_id)}</a>")),
                    ("run_command_worktree_status", coder_run.status),
                    ("run_command_review_status", str(review_gate["status"])),
                    ("run_command_review_path", SafeHtml(_artifact_link(str(review_gate["review_path"]))) if review_gate["exists"] else str(review_gate["review_path"])),
                    ("run_command_commit_request_status", _status_counts(commit_approvals)),
                    ("run_command_publication_status", _status_counts(publications)),
                    ("run_command_changed_files_count", change_summary["changed_files_count"]),
                    ("run_command_diff_summary", change_summary["diff_summary"]),
                    ("run_command_next_action", next_action),
                    ("run_command_target_surface", target),
                    ("run_command_reason", reason),
                    ("run_command_write_on_get", "false"),
                    ("run_command_network_actions_taken", "0"),
                    ("run_command_external_effects_created", "false"),
                    ("run_command_push_created", "false"),
                    ("run_command_pr_created", "false"),
                    ("run_command_deploy_created", "false"),
                ]
            ),
            _ul(lines),
            "</section>",
        ]
    )


def _run_workbench_action_form(
    root: Path,
    coder_run: Any,
    *,
    goal_id: str,
    next_action: str,
    target_href: str,
    target_label: str,
    review_gate: dict[str, Any],
    commit_approvals: list[Any],
    publications: list[Any],
) -> dict[str, Any]:
    result: dict[str, Any] = {
        "available": False,
        "kind": "none",
        "action_name": "none",
        "html": "",
        "primary_href": "",
        "primary_label": "",
        "form_href": "#run-workbench-action-form",
        "form_label": "",
        "source_href": target_href,
        "source_label": target_label,
        "blocked_reason": "no_same_page_form_for_action",
        "confirmation_required": False,
    }
    resume_surface = f"/runs/{quote(coder_run.id)}"

    def hidden_fields(extra: dict[str, str]) -> dict[str, str]:
        return {
            **extra,
            "return_to": resume_surface,
            "resume_surface": resume_surface,
            "open_project": coder_run.project_id,
            "open_goal": goal_id,
        }

    title = ""
    body = ""
    form = ""
    kind = "none"
    action_name = "none"
    if target_href == "#run-approval-actions" and next_action == "Create commit request":
        if not review_gate.get("commit_request_form_available"):
            result["blocked_reason"] = str(
                review_gate.get("blocked_reason") or "review_gate_blocked"
            )
            return result
        kind = "commit_request"
        action_name = "coder-commit-request"
        title = "Request Commit"
        body = (
            "Create the local commit approval request from this run workbench. It does not "
            "stage, commit, push, create a PR, deploy, call providers, or use the network."
        )
        form = _input_form(
            action_name,
            hidden_fields({"run_id": coder_run.id, "requested_by": "operator"}),
            {
                "message": "Implement bounded change from approved worktree run",
                "note": "Request local commit after run review",
            },
        )
    elif target_href == "#confirmed-local-commit-action":
        approved_commit = next(
            (item for item in commit_approvals if item.status == "approved"),
            None,
        )
        if approved_commit is None:
            result["blocked_reason"] = "approved_commit_request_missing"
            return result
        kind = "local_commit"
        action_name = "commit-coder-worktree"
        title = "Commit Approved Worktree"
        body = (
            "Create the isolated local commit for this approved run. It does not push, "
            "create a PR, deploy, call providers, or use the network."
        )
        form = _input_form(
            action_name,
            hidden_fields({"run_id": coder_run.id, "committed_by": "operator"}),
            {
                "message": getattr(
                    approved_commit,
                    "commit_message",
                    "Implement bounded change from approved worktree run",
                )
                or "Implement bounded change from approved worktree run",
            },
        )
    elif target_href == "#run-approval-actions" and next_action == "Create publication request":
        committed = next(
            (item for item in commit_approvals if item.status == "committed"),
            None,
        )
        if committed is None:
            result["blocked_reason"] = "local_commit_missing"
            return result
        if publications:
            result["blocked_reason"] = "publication_request_already_exists"
            return result
        kind = "publication_request"
        action_name = "coder-publication-request"
        title = "Request Publication"
        body = (
            "Create the local publication approval request from this committed run. It does "
            "not push, create a PR, deploy, call providers, or use the network."
        )
        form = _input_form(
            action_name,
            hidden_fields(
                {
                    "run_id": coder_run.id,
                    "requested_by": "operator",
                    "remote": "origin",
                    "target_branch": "main",
                }
            ),
            {"note": "Request publication handoff"},
        )
    elif target_href == "#publication-handoff-action":
        approved_publication = next(
            (item for item in publications if item.status == "approved"),
            None,
        )
        if approved_publication is None:
            result["blocked_reason"] = "approved_publication_request_missing"
            return result
        kind = "publication_handoff"
        action_name = "coder-publication-handoff"
        title = "Create Publication Handoff"
        body = (
            "Write local publication handoff and PR-body artifacts with suggested manual "
            "commands only. It does not push, create a PR, deploy, call providers, or use the network."
        )
        form = _form(
            action_name,
            hidden_fields({"run_id": coder_run.id}),
        )
    else:
        return result

    result.update(
        {
            "available": True,
            "kind": kind,
            "action_name": action_name,
            "primary_href": "#run-workbench-action-form",
            "primary_label": next_action,
            "form_label": next_action,
            "blocked_reason": "none",
            "confirmation_required": True,
            "html": "".join(
                [
                    (
                        "<section id='run-workbench-action-form' "
                        "class='run-workbench-action-form' "
                        "data-run-workbench-action-form='true' "
                        f"data-run-workbench-action-kind='{_e(kind)}' "
                        f"data-run-workbench-action-name='{_e(action_name)}' "
                        f"data-run-workbench-action-run='{_e(coder_run.id)}'>"
                    ),
                    f"<h3>{_e(title)}</h3>",
                    f"<p class='muted'>{_e(body)}</p>",
                    form,
                    "</section>",
                ]
            ),
        }
    )
    return result


def _run_operator_workbench(root: Path, coder_run: Any) -> str:
    storage = _storage(root)
    delegation = storage.get_subagent_delegation(coder_run.delegation_id)
    goal_id = delegation.parent_goal_id if delegation is not None else ""
    goal_surface: str | SafeHtml = (
        SafeHtml(f"<a href='/goals/{quote(goal_id)}'>{_e(goal_id)}</a>")
        if goal_id
        else "none"
    )
    goal_href = f"/goals/{quote(goal_id)}" if goal_id else "/goals"
    commit_approvals = [
        item
        for item in list_coder_worktree_commit_approvals(root, limit=50)
        if item.run_id == coder_run.id
    ]
    publications = [
        item
        for item in list_coder_publications(root, limit=50)
        if item.run_id == coder_run.id
    ]
    review_gate = _run_review_gate_state(root, coder_run)
    change_summary = coder_worktree_change_summary(root, coder_run)
    next_action, target_href, target_label, reason = _run_command_next_action(
        coder_run,
        review_gate=review_gate,
        commit_approvals=commit_approvals,
        publications=publications,
    )
    action_form = _run_workbench_action_form(
        root,
        coder_run,
        goal_id=goal_id,
        next_action=next_action,
        target_href=target_href,
        target_label=target_label,
        review_gate=review_gate,
        commit_approvals=commit_approvals,
        publications=publications,
    )
    action_form_available = bool(action_form["available"])
    manual_boundary = target_href == "#publication-handoff-commands"
    if action_form_available:
        status = "action_form_ready"
    elif target_href.startswith("/approvals"):
        status = "approval_queue_ready"
    elif manual_boundary:
        status = "manual_boundary_ready"
    elif target_href.startswith("#"):
        status = "same_page_review"
    else:
        status = "navigation_ready"
    primary_href = str(action_form["primary_href"] or target_href)
    primary_label = str(action_form["primary_label"] or target_label)
    primary_surface = SafeHtml(f"<a href='{_e(primary_href)}'>{_e(primary_label)}</a>")
    source_primary_surface = SafeHtml(f"<a href='{_e(target_href)}'>{_e(target_label)}</a>")
    action_form_surface: str | SafeHtml = (
        SafeHtml(
            f"<a href='{_e(str(action_form['form_href']))}'>{_e(str(action_form['form_label']))}</a>"
        )
        if action_form_available
        else "none"
    )
    bounded_validation_path = Path(coder_run.evidence_path) / "bounded_file_validation.json"
    bounded_status = _artifact_status(root, bounded_validation_path)
    review_artifact = (
        str(review_gate["review_path"])
        if review_gate["exists"]
        else str(Path(coder_run.evidence_path) / "run.json")
    )
    finish_form = _input_form(
        "save-workspace",
        {
            "open_project": coder_run.project_id,
            "open_goal": goal_id,
            "return_to": f"/runs/{coder_run.id}",
        },
        {
            "filters": f"run:{coder_run.id}",
            "expanded_panels": "run-workbench,workflow,review,evidence,actions",
            "last_viewed_artifact": review_artifact,
            "updated_by": "run-operator-workbench",
        },
    )
    return "".join(
        [
            "<section id='run-operator-workbench' class='panel run-operator-workbench' data-run-operator-workbench='true'><h2>Run Operator Workbench</h2>",
            "<div class='run-workbench-grid' data-run-workbench-actions='true'>",
            "<div class='run-workbench-card run-workbench-primary'>",
            "<h3>Do Now</h3>",
            f"<p>{_e(next_action)}</p>",
            f"<a class='run-workbench-action' href='{_e(primary_href)}'>{_e(primary_label)}</a>",
            "</div>",
            "<div class='run-workbench-card'>",
            "<h3>Check</h3>",
            f"<p>Review: {_e(str(review_gate['status']))}</p>",
            "<a class='run-workbench-link' href='#run-review-gate'>Open review gate</a>",
            "</div>",
            "<div class='run-workbench-card'>",
            "<h3>Unblock</h3>",
            f"<p>Commit: {_e(_status_counts(commit_approvals))}</p>",
            "<a class='run-workbench-link' href='/approvals'>Open approvals</a>",
            "</div>",
            "<div class='run-workbench-card'>",
            "<h3>Finish Today</h3>",
            "<p>Save run resume state</p>",
            "<a class='run-workbench-link' href='#run-finish-today'>Open save form</a>",
            "</div>",
            "</div>",
            str(action_form["html"]),
            _kv(
                [
                    ("run_workbench_status", status),
                    ("run_workbench_run_id", coder_run.id),
                    ("run_workbench_goal", goal_surface),
                    ("run_workbench_project", coder_run.project_id),
                    (
                        "run_workbench_delegation",
                        SafeHtml(f"<a href='/delegations/{quote(coder_run.delegation_id)}'>{_e(coder_run.delegation_id)}</a>"),
                    ),
                    ("run_workbench_worktree_status", coder_run.status),
                    ("run_workbench_review_status", str(review_gate["status"])),
                    ("run_workbench_bounded_validation_status", bounded_status),
                    ("run_workbench_commit_request_status", _status_counts(commit_approvals)),
                    ("run_workbench_publication_status", _status_counts(publications)),
                    ("run_workbench_changed_files_count", change_summary["changed_files_count"]),
                    ("run_workbench_diff_summary", change_summary["diff_summary"]),
                    ("run_workbench_next_action", next_action),
                    ("run_workbench_primary_surface", primary_surface),
                    ("run_workbench_source_primary_surface", source_primary_surface),
                    ("run_workbench_reason", reason),
                    (
                        "run_workbench_action_form_available",
                        str(action_form_available).lower(),
                    ),
                    ("run_workbench_action_form_surface", action_form_surface),
                    ("run_workbench_action_form_kind", str(action_form["kind"])),
                    ("run_workbench_action_form_action", str(action_form["action_name"])),
                    (
                        "run_workbench_action_form_blocked_reason",
                        str(action_form["blocked_reason"]),
                    ),
                    (
                        "run_workbench_confirmation_required",
                        str(bool(action_form["confirmation_required"])).lower(),
                    ),
                    (
                        "run_workbench_approval_surface",
                        SafeHtml("<a href='/approvals'>/approvals</a>"),
                    ),
                    (
                        "run_workbench_evidence_surface",
                        SafeHtml("<a href='#coder-worktree-evidence'>Coder Worktree Evidence</a>"),
                    ),
                    (
                        "run_workbench_goal_surface",
                        SafeHtml(f"<a href='{_e(goal_href)}'>{_e(goal_href)}</a>"),
                    ),
                    (
                        "run_workbench_finish_surface",
                        SafeHtml("<a href='#run-finish-today'>Finish Today</a>"),
                    ),
                    ("run_workbench_finish_form_available", "true"),
                    ("run_workbench_finish_confirmation_required", "true"),
                    ("run_workbench_saved_artifact", SafeHtml(_artifact_link(review_artifact))),
                    ("run_workbench_source", "coder_worktree_run_gate_state"),
                    ("run_workbench_write_on_get", "false"),
                    ("run_workbench_provider_calls_taken", "0"),
                    ("run_workbench_network_actions_taken", "0"),
                    ("run_workbench_external_effects_created", "false"),
                    ("run_workbench_push_created", "false"),
                    ("run_workbench_pr_created", "false"),
                    ("run_workbench_deploy_created", "false"),
                ]
            ),
            _ul(
                [
                    f"run_workbench_now: {_e(next_action)}",
                    f"run_workbench_click: <a href='{_e(primary_href)}'>{_e(primary_label)}</a>",
                    f"run_workbench_source: <a href='{_e(target_href)}'>{_e(target_label)}</a>",
                    f"run_workbench_action_form: available={str(action_form_available).lower()} action={_e(str(action_form['action_name']))} source=<a href='{_e(target_href)}'>{_e(target_label)}</a>",
                    "run_workbench_check: <a href='#run-review-gate'>Run Review Gate</a>",
                    "run_workbench_unblock: <a href='/approvals'>/approvals</a>",
                    f"run_workbench_goal: <a href='{_e(goal_href)}'>{_e(goal_href)}</a>",
                    "run_workbench_finish: <a href='#run-finish-today'>Finish Today</a>",
                    "run_workbench_safety: confirmed local actions only",
                ]
            ),
            "<h3 id='run-finish-today'>Finish Today</h3>",
            "<p class='muted'>Save this run, current filters, expanded panels, and review/evidence artifact as tomorrow's resume point. This writes only `.clanker/app/workspace.json` after confirmation.</p>",
            finish_form,
            "</section>",
        ]
    )


def _run_gate_map(root: Path, coder_run: Any) -> str:
    commit_approvals = [
        item
        for item in list_coder_worktree_commit_approvals(root, limit=50)
        if item.run_id == coder_run.id
    ]
    publications = [
        item
        for item in list_coder_publications(root, limit=50)
        if item.run_id == coder_run.id
    ]
    review_gate = _run_review_gate_state(root, coder_run)
    next_action, target_href, target_label, reason = _run_command_next_action(
        coder_run,
        review_gate=review_gate,
        commit_approvals=commit_approvals,
        publications=publications,
    )
    statuses = _run_gate_statuses(
        review_gate=review_gate,
        commit_approvals=commit_approvals,
        publications=publications,
    )
    current_gate = next(
        (
            name
            for name, status in statuses.items()
            if status in {"current", "blocked", "attention"}
        ),
        "complete",
    )
    counts: dict[str, int] = {}
    for status in statuses.values():
        counts[status] = counts.get(status, 0) + 1
    total = len(RUN_GATE_STEPS)
    done = counts.get("done", 0)
    waiting = counts.get("waiting", 0)
    blocked = counts.get("blocked", 0) + counts.get("attention", 0)
    target_surface = SafeHtml(f"<a href='{_e(target_href)}'>{_e(target_label)}</a>")

    items: list[str] = []
    lines: list[str] = []
    for index, (gate, label, action, href, surface_label) in enumerate(
        RUN_GATE_STEPS,
        start=1,
    ):
        status = statuses.get(gate, "waiting")
        marker = "current" if gate == current_gate else status
        surface = _run_gate_surface(href, surface_label, run_id=coder_run.id)
        lines.append(
            f"run_gate_step: {_e(gate)} status={_e(status)} "
            f"marker={_e(marker)} action={_e(action)} surface={surface}"
        )
        items.append(
            "<li "
            f"data-run-gate='{_e(gate)}' "
            f"data-run-gate-status='{_e(status)}' "
            f"data-run-gate-marker='{_e(marker)}' "
            f"data-run-gate-action='{_e(action)}'>"
            f"<span class='workflow-map-index'>{index}</span> "
            f"<strong>{_e(label)}</strong> "
            f"status={_e(status)} marker={_e(marker)} "
            f"action={_e(action)} surface={surface}</li>"
        )

    return "".join(
        [
            "<section id='run-gate-map' class='panel run-gate-map' data-run-gate-map='true'><h2>Run Gate Map</h2>",
            "<p class='muted'>A run-scoped rail from review through local commit, publication handoff, and the manual publish boundary.</p>",
            _kv(
                [
                    ("run_gate_status", "available"),
                    ("run_gate_run_id", coder_run.id),
                    ("run_gate_project", coder_run.project_id),
                    (
                        "run_gate_delegation",
                        SafeHtml(
                            f"<a href='/delegations/{quote(coder_run.delegation_id)}'>{_e(coder_run.delegation_id)}</a>"
                        ),
                    ),
                    ("run_gate_current_gate", current_gate),
                    ("run_gate_current_step", current_gate),
                    ("run_gate_current_action", next_action),
                    ("run_gate_current_surface", target_surface),
                    ("run_gate_reason", reason),
                    ("run_gate_progress", f"{done}/{total} gates done"),
                    ("run_gate_step_count", str(total)),
                    ("run_gate_done_count", str(done)),
                    ("run_gate_waiting_count", str(waiting)),
                    ("run_gate_blocked_count", str(blocked)),
                    ("run_gate_review_status", statuses["review"]),
                    ("run_gate_commit_request_status", statuses["commit_request"]),
                    ("run_gate_commit_approval_status", statuses["commit_approval"]),
                    ("run_gate_local_commit_status", statuses["local_commit"]),
                    (
                        "run_gate_publication_request_status",
                        statuses["publication_request"],
                    ),
                    (
                        "run_gate_publication_approval_status",
                        statuses["publication_approval"],
                    ),
                    (
                        "run_gate_publication_handoff_status",
                        statuses["publication_handoff"],
                    ),
                    ("run_gate_manual_publish_status", statuses["manual_publish"]),
                    ("run_gate_manual_boundary", "outside_clankeros"),
                    ("run_gate_source", "coder_worktree_run_gate_state"),
                    ("run_gate_write_on_get", "false"),
                    ("run_gate_provider_calls_taken", "0"),
                    ("run_gate_network_actions_taken", "0"),
                    ("run_gate_external_effects_created", "false"),
                    ("run_gate_push_created", "false"),
                    ("run_gate_pr_created", "false"),
                    ("run_gate_deploy_created", "false"),
                ]
            ),
            "<ol class='workflow-map-rail run-gate-rail'>",
            "".join(items),
            "</ol>",
            _ul(
                lines
                + [
                    f"run_gate_now: {_e(next_action)} at <a href='{_e(target_href)}'>{_e(target_label)}</a>",
                    "run_gate_safety: read-only run guidance; confirmed local forms remain on existing gate surfaces",
                ]
            ),
            "</section>",
        ]
    )


def _run_continuation_strip(root: Path, coder_run: Any) -> str:
    storage = _storage(root)
    delegation = storage.get_subagent_delegation(coder_run.delegation_id)
    goal_id = delegation.parent_goal_id if delegation is not None else ""
    goal_href = f"/goals/{quote(goal_id)}" if goal_id else "/goals"
    goal_label = f"/goals/{goal_id}" if goal_id else "/goals"
    commit_approvals = [
        item
        for item in list_coder_worktree_commit_approvals(root, limit=50)
        if item.run_id == coder_run.id
    ]
    publications = [
        item
        for item in list_coder_publications(root, limit=50)
        if item.run_id == coder_run.id
    ]
    review_gate = _run_review_gate_state(root, coder_run)
    change_summary = coder_worktree_change_summary(root, coder_run)
    next_action, target_href, target_label, reason = _run_command_next_action(
        coder_run,
        review_gate=review_gate,
        commit_approvals=commit_approvals,
        publications=publications,
    )
    statuses = _run_gate_statuses(
        review_gate=review_gate,
        commit_approvals=commit_approvals,
        publications=publications,
    )
    current_gate = next(
        (
            name
            for name, status in statuses.items()
            if status in {"current", "blocked", "attention"}
        ),
        "complete",
    )
    action_form_available = target_href in {
        "#run-approval-actions",
        "#confirmed-local-commit-action",
        "#publication-handoff-action",
    }
    approval_href = f"/approvals?run_id={quote(coder_run.id)}"
    pending_approval_count = sum(
        1 for item in commit_approvals + publications if item.status == "pending_operator_approval"
    )
    approval_summary = (
        f"{pending_approval_count} pending"
        if pending_approval_count
        else f"commit={_status_counts(commit_approvals)} publication={_status_counts(publications)}"
    )
    ready_publication = next(
        (item for item in publications if item.status == "ready_for_operator"),
        None,
    )
    manual_boundary_status = (
        "ready_outside_clankeros" if ready_publication is not None else "not_ready"
    )
    manual_href = (
        "#publication-handoff-commands" if ready_publication is not None else "#run-gate-map"
    )
    manual_label = (
        "Publication Handoff Commands"
        if ready_publication is not None
        else "Run Gate Map"
    )
    review_artifact = (
        str(review_gate["review_path"])
        if review_gate["exists"]
        else str(Path(coder_run.evidence_path) / "run.json")
    )
    if action_form_available:
        continuation_status = "action_form_ready"
    elif target_href.startswith("/approvals"):
        continuation_status = "approval_queue_ready"
    elif manual_boundary_status == "ready_outside_clankeros":
        continuation_status = "manual_boundary_ready"
    elif target_href.startswith("#"):
        continuation_status = "same_page_review"
    else:
        continuation_status = "navigation_ready"
    return "".join(
        [
            (
                "<section id='run-continuation-strip' "
                "class='panel run-continuation-strip' "
                "data-run-continuation-strip='true'>"
                "<h2>Run Continuation Strip</h2>"
            ),
            "<p class='muted'>One run handoff for the next gate, scoped approval queue, evidence, parent Goal, and the manual publication boundary.</p>",
            "<div class='run-continuation-grid' data-run-continuation-actions='true'>",
            "<article class='run-continuation-card run-continuation-primary'><h3>Next Gate</h3>",
            f"<p>{_e(current_gate)}: {_e(next_action)}</p>",
            f"<a class='run-continuation-action' href='{_e(target_href)}'>{_e(target_label)}</a></article>",
            "<article class='run-continuation-card'><h3>Approval</h3>",
            f"<p>{_e(approval_summary)}</p>",
            f"<a class='run-continuation-link' href='{_e(approval_href)}'>Scoped approvals</a></article>",
            "<article class='run-continuation-card'><h3>Evidence</h3>",
            f"<p>{_e(change_summary['changed_files_count'])} files, {_e(change_summary['diff_summary'])}</p>",
            "<a class='run-continuation-link' href='#coder-worktree-evidence'>Open evidence</a></article>",
            "<article class='run-continuation-card'><h3>Goal</h3>",
            f"<p>{_e(goal_id or 'No parent Goal found')}</p>",
            f"<a class='run-continuation-link' href='{_e(goal_href)}'>Return to Goal</a></article>",
            "<article class='run-continuation-card'><h3>Boundary</h3>",
            f"<p>{_e(manual_boundary_status)}</p>",
            f"<a class='run-continuation-link' href='{_e(manual_href)}'>{_e(manual_label)}</a></article>",
            "</div>",
            "<details class='run-continuation-evidence' data-run-continuation-evidence='true'><summary>Run continuation evidence</summary>",
            _kv(
                [
                    ("run_continuation_status", continuation_status),
                    ("run_continuation_run_id", coder_run.id),
                    ("run_continuation_goal", goal_id or "none"),
                    ("run_continuation_project", coder_run.project_id),
                    ("run_continuation_delegation", SafeHtml(f"<a href='/delegations/{quote(coder_run.delegation_id)}'>{_e(coder_run.delegation_id)}</a>")),
                    ("run_continuation_current_gate", current_gate),
                    ("run_continuation_next_action", next_action),
                    (
                        "run_continuation_primary_surface",
                        SafeHtml(f"<a href='{_e(target_href)}'>{_e(target_label)}</a>"),
                    ),
                    ("run_continuation_reason", reason),
                    ("run_continuation_action_form_available", str(action_form_available).lower()),
                    ("run_continuation_confirmation_required", str(action_form_available).lower()),
                    (
                        "run_continuation_approval_surface",
                        SafeHtml(f"<a href='{_e(approval_href)}'>/approvals</a>"),
                    ),
                    ("run_continuation_pending_approvals", str(pending_approval_count)),
                    ("run_continuation_commit_request_status", _status_counts(commit_approvals)),
                    ("run_continuation_publication_status", _status_counts(publications)),
                    (
                        "run_continuation_evidence_surface",
                        SafeHtml("<a href='#coder-worktree-evidence'>Coder Worktree Evidence</a>"),
                    ),
                    ("run_continuation_review_artifact", SafeHtml(_artifact_link(review_artifact))),
                    ("run_continuation_changed_files_count", change_summary["changed_files_count"]),
                    ("run_continuation_diff_summary", change_summary["diff_summary"]),
                    (
                        "run_continuation_goal_surface",
                        SafeHtml(f"<a href='{_e(goal_href)}'>{_e(goal_label)}</a>"),
                    ),
                    ("run_continuation_manual_boundary", "outside_clankeros"),
                    ("run_continuation_manual_boundary_status", manual_boundary_status),
                    (
                        "run_continuation_manual_boundary_surface",
                        SafeHtml(f"<a href='{_e(manual_href)}'>{_e(manual_label)}</a>"),
                    ),
                    ("run_continuation_source", "coder_worktree_run_gate_state"),
                    ("run_continuation_write_on_get", "false"),
                    ("run_continuation_provider_calls_taken", "0"),
                    ("run_continuation_network_actions_taken", "0"),
                    ("run_continuation_external_effects_created", "false"),
                    ("run_continuation_push_created", "false"),
                    ("run_continuation_pr_created", "false"),
                    ("run_continuation_deploy_created", "false"),
                ]
            ),
            _ul(
                [
                    f"run_continuation_now: {_e(next_action)}",
                    f"run_continuation_click: <a href='{_e(target_href)}'>{_e(target_label)}</a>",
                    f"run_continuation_approval: <a href='{_e(approval_href)}'>/approvals</a>",
                    "run_continuation_evidence: <a href='#coder-worktree-evidence'>Coder Worktree Evidence</a>",
                    f"run_continuation_goal: <a href='{_e(goal_href)}'>{_e(goal_label)}</a>",
                    f"run_continuation_boundary: <a href='{_e(manual_href)}'>{_e(manual_label)}</a>",
                    "run_continuation_safety: read-only run continuation; confirmed forms own writes",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _run_gate_statuses(
    *,
    review_gate: dict[str, Any],
    commit_approvals: list[Any],
    publications: list[Any],
) -> dict[str, str]:
    statuses = {gate: "waiting" for gate, *_ in RUN_GATE_STEPS}
    if not commit_approvals:
        if review_gate["commit_request_form_available"]:
            statuses["review"] = "done"
            statuses["commit_request"] = "current"
        else:
            statuses["review"] = "current"
            statuses["commit_request"] = "waiting"
        return statuses

    statuses["review"] = "done"
    statuses["commit_request"] = "done"
    commit_status = _preferred_status(
        commit_approvals,
        ["committed", "approved", "pending_operator_approval", "rejected"],
        "unknown",
    )
    if commit_status == "pending_operator_approval":
        statuses["commit_approval"] = "current"
        return statuses
    if commit_status == "rejected":
        statuses["commit_approval"] = "blocked"
        return statuses
    statuses["commit_approval"] = "done"
    if commit_status == "approved":
        statuses["local_commit"] = "current"
        return statuses
    if commit_status != "committed":
        statuses["local_commit"] = "attention"
        return statuses

    statuses["local_commit"] = "done"
    if not publications:
        statuses["publication_request"] = "current"
        return statuses

    statuses["publication_request"] = "done"
    publication_status = _preferred_status(
        publications,
        ["ready_for_operator", "approved", "pending_operator_approval", "rejected"],
        "unknown",
    )
    if publication_status == "pending_operator_approval":
        statuses["publication_approval"] = "current"
        return statuses
    if publication_status == "rejected":
        statuses["publication_approval"] = "blocked"
        return statuses
    statuses["publication_approval"] = "done"
    if publication_status == "approved":
        statuses["publication_handoff"] = "current"
        return statuses
    if publication_status == "ready_for_operator":
        statuses["publication_handoff"] = "done"
        statuses["manual_publish"] = "current"
        return statuses
    statuses["publication_handoff"] = "attention"
    return statuses


def _run_gate_surface(href: str, label: str, *, run_id: str | None = None) -> SafeHtml | str:
    if href == "outside_clankeros":
        return "outside_clankeros"
    if href == "/approvals" and run_id:
        href = f"/approvals?run_id={quote(run_id)}"
    return SafeHtml(f"<a href='{_e(href)}'>{_e(label)}</a>")


