def _action_notice_next_step_form_section(
    root: Path,
    current_path: str,
    recommendation: dict[str, str],
) -> str:
    try:
        focus_context = _operator_focus_context(root, current_path)
    except Exception:
        return ""
    if str(focus_context.get("status") or "") != "available":
        return ""
    goal = focus_context.get("goal")
    goal_state = focus_context.get("goal_state")
    next_action = focus_context.get("next_action")
    if goal is None or not isinstance(goal_state, dict) or not isinstance(next_action, GoalNextAction):
        return ""
    action_form = str(focus_context.get("action_form") or "")
    if not action_form:
        return ""
    phase = str(focus_context.get("phase") or "unknown")
    try:
        _, _, current_gate = _goal_workflow_gate_summary(root, goal_state, next_action)
    except Exception:
        current_gate = str(recommendation.get("current_gate") or "unknown")
    goal_id = str(getattr(goal, "id", "") or "unknown")
    goal_label = str(focus_context.get("goal_label") or goal_id)
    source = str(focus_context.get("source") or recommendation.get("source") or "goal_state")
    source_surface = str(next_action.href)
    recommended_surface = str(recommendation.get("href") or source_surface)
    recommended_label = str(recommendation.get("label") or next_action.action)
    return "".join(
        [
            (
                "<section id='action-notice-next-step-form' "
                "class='action-notice-next-step-form' "
                "data-action-notice-next-step-form='true'>"
            ),
            "<h2>Action Notice Next Step</h2>",
            "<p class='muted'>Continue directly from this return notice. The same confirmation screen still appears before any local write or local execution.</p>",
            action_form,
            "<details id='action-notice-next-step-evidence' class='action-notice-next-step-evidence' data-action-notice-next-step-evidence='true'><summary>Notice next-step evidence</summary>",
            _kv(
                [
                    ("action_notice_next_step_status", "available"),
                    ("action_notice_next_step_source", source),
                    (
                        "action_notice_next_step_goal",
                        SafeHtml(f"<a href='/goals/{quote(goal_id)}'>{_e(goal_label)}</a>"),
                    ),
                    ("action_notice_next_step_phase", phase),
                    ("action_notice_next_step_current_gate", current_gate),
                    ("action_notice_next_step_next_action", next_action.action),
                    (
                        "action_notice_next_step_primary_surface",
                        SafeHtml(
                            "<a href='#action-notice-next-step-form'>"
                            f"{_e(next_action.action)}</a>"
                        ),
                    ),
                    (
                        "action_notice_next_step_recommended_surface",
                        SafeHtml(f"<a href='{_e(recommended_surface)}'>{_e(recommended_label)}</a>"),
                    ),
                    (
                        "action_notice_next_step_source_surface",
                        SafeHtml(f"<a href='{_e(source_surface)}'>{_e(source_surface)}</a>"),
                    ),
                    ("action_notice_next_step_reason", next_action.reason),
                    ("action_notice_next_step_action_form_available", "true"),
                    ("action_notice_next_step_confirmation_required", "true"),
                    ("action_notice_next_step_write_on_get", "false"),
                    ("action_notice_next_step_provider_calls_taken", "0"),
                    ("action_notice_next_step_network_actions_taken", "0"),
                    ("action_notice_next_step_external_effects_created", "false"),
                    ("action_notice_next_step_push_created", "false"),
                    ("action_notice_next_step_pr_created", "false"),
                    ("action_notice_next_step_deploy_created", "false"),
                ]
            ),
            _ul(
                [
                    f"action_notice_next_step_now: {_e(next_action.action)}",
                    (
                        "action_notice_next_step_click: "
                        f"<a href='#action-notice-next-step-form'>{_e(next_action.action)}</a>"
                    ),
                    f"action_notice_next_step_source: <a href='{_e(source_surface)}'>{_e(source_surface)}</a>",
                    f"action_notice_next_step_gate: {_e(current_gate)}",
                    "action_notice_next_step_safety: reuses existing confirmed Goal action form",
                ]
            ),
            "</details>",
            "</section>",
        ]
    )


def _action_notice_recommendation(
    root: Path,
    current_path: str,
    state: dict[str, str],
) -> dict[str, str]:
    try:
        focus_context = _operator_focus_context(root, current_path)
    except Exception:
        return {
            "status": "state_unavailable",
            "source": "fallback",
            "action": "Open health",
            "href": "/health",
            "label": "/health",
            "reason": "state_unavailable",
            "phase": "unknown",
            "current_gate": "unknown",
            "current_step": "unknown",
            "form_available": "false",
            "confirmation_required": "false",
        }

    status = str(focus_context.get("status") or "state_unavailable")
    if status == "first_run":
        href = str(focus_context.get("target_href") or "/")
        label = str(focus_context.get("target_label") or href)
        return {
            "status": "first_run",
            "source": str(focus_context.get("source") or "first_run_progress"),
            "action": str(focus_context.get("next_action") or "Continue first run"),
            "href": href,
            "label": label,
            "reason": str(focus_context.get("next_reason") or "first_run"),
            "phase": "First run",
            "current_gate": str(focus_context.get("current_step") or "unknown"),
            "current_step": str(focus_context.get("current_step") or "unknown"),
            "form_available": str(bool(focus_context.get("form_available"))).lower(),
            "confirmation_required": str(bool(focus_context.get("form_available"))).lower(),
        }

    if status == "available":
        goal = focus_context.get("goal")
        next_action = focus_context.get("next_action")
        goal_state = focus_context.get("goal_state")
        phase = str(focus_context.get("phase") or "unknown")
        form_available = bool(focus_context.get("action_form"))
        current_gate = "unknown"
        if isinstance(goal_state, dict) and isinstance(next_action, GoalNextAction):
            try:
                _, _, current_gate = _goal_workflow_gate_summary(
                    root,
                    goal_state,
                    next_action,
                )
            except Exception:
                current_gate = "unknown"
        if goal is not None and isinstance(next_action, GoalNextAction):
            if form_available:
                href = f"/goals/{quote(goal.id)}#goal-action-dock-form"
                label = next_action.action
            else:
                href = next_action.href
                label = next_action.action
            return {
                "status": "available",
                "source": str(focus_context.get("source") or "goal_state"),
                "action": next_action.action,
                "href": href,
                "label": label,
                "reason": next_action.reason,
                "phase": phase,
                "current_gate": current_gate,
                "current_step": current_gate,
                "form_available": str(form_available).lower(),
                "confirmation_required": str(form_available).lower(),
            }

    saved_goal = str(state.get("open_goal") or "").strip()
    saved_project = str(state.get("open_project") or "").strip()
    if saved_goal:
        return {
            "status": "saved_goal_only",
            "source": "workspace",
            "action": "Open saved goal",
            "href": f"/goals/{quote(saved_goal)}",
            "label": "Open saved goal",
            "reason": "saved_goal_without_action_context",
            "phase": "unknown",
            "current_gate": "unknown",
            "current_step": "unknown",
            "form_available": "false",
            "confirmation_required": "false",
        }
    if saved_project:
        return {
            "status": "saved_project_only",
            "source": "workspace",
            "action": "Open saved project",
            "href": f"/projects/{quote(saved_project)}",
            "label": "Open saved project",
            "reason": "saved_project_without_goal_context",
            "phase": "First run",
            "current_gate": "create_first_goal",
            "current_step": "create_first_goal",
            "form_available": "false",
            "confirmation_required": "false",
        }
    return {
        "status": status,
        "source": str(focus_context.get("source") or "fallback"),
        "action": "Open resume",
        "href": "/resume",
        "label": "/resume",
        "reason": "no_saved_context",
        "phase": "unknown",
        "current_gate": "unknown",
        "current_step": "unknown",
        "form_available": "false",
        "confirmation_required": "false",
    }


def _notice_current_surface(current_path: str) -> str:
    parsed = urlparse(current_path or "/")
    pairs: list[tuple[str, str]] = []
    for key, values in parse_qs(parsed.query, keep_blank_values=True).items():
        if key == "notice":
            continue
        for value in values:
            pairs.append((key, value))
    path = parsed.path or "/"
    query = urlencode(pairs)
    if query:
        path = f"{path}?{query}"
    if parsed.fragment:
        path = f"{path}#{parsed.fragment}"
    return _safe_local_return_path(path) or "/"


def _nav_links(current_path: str) -> str:
    path = urlparse(current_path or "/").path or "/"

    def render_link(label: str, href: str) -> str:
        current = _is_current_nav(path, href)
        aria = " aria-current='page'" if current else ""
        return f"<a href='{_e(href)}'{aria}{_shortcut_attrs(label, href)}>{_e(label)}</a>"

    primary_links = [
        render_link(label, href) for label, href in NAV_ITEMS if href in PRIMARY_NAV_HREFS
    ]
    secondary_items = [(label, href) for label, href in NAV_ITEMS if href not in PRIMARY_NAV_HREFS]
    secondary_links = [render_link(label, href) for label, href in secondary_items]
    secondary_current = any(_is_current_nav(path, href) for _, href in secondary_items)
    more_current = "true" if secondary_current else "false"
    more_open = " open" if secondary_current else ""
    return (
        "<span class='shell-nav-primary' data-shell-nav-primary='true'>"
        + "".join(primary_links)
        + "</span>"
        f"<details class='shell-nav-more' data-shell-nav-more='true' "
        f"data-shell-nav-more-current='{more_current}'{more_open}>"
        "<summary>More</summary>"
        "<span class='shell-nav-more-menu' data-shell-nav-more-menu='true'>"
        + "".join(secondary_links)
        + "</span>"
        "</details>"
    )


def _shortcut_attrs(label: str, href: str) -> str:
    shortcut = ROUTE_KEYBOARD_SHORTCUTS.get(href)
    if not shortcut:
        return ""
    return (
        f" data-shortcut='{_e(shortcut)}'"
        f" aria-keyshortcuts='{_e(shortcut)}'"
        f" title='{_e(label)} ({_e(shortcut)})'"
    )


def _is_current_nav(path: str, href: str) -> bool:
    if href == "/":
        return path == "/"
    return path == href or path.startswith(href + "/")


def _focus_context_target(
    focus_context: dict[str, Any],
    current_path: str,
) -> tuple[str, str, str]:
    focus_status = str(focus_context.get("status", "state_unavailable"))
    focus_target = str(focus_context.get("target_href") or "/health")
    focus_target_label = str(focus_context.get("target_label") or focus_target)
    focus_source = focus_status
    if focus_status == "available" and isinstance(
        focus_context.get("next_action"),
        GoalNextAction,
    ):
        next_action = focus_context["next_action"]
        action_form = str(focus_context.get("action_form") or "")
        focus_target = str(next_action.href)
        focus_target_label = next_action.action
        focus_source = "next_action"
        if action_form:
            goal = focus_context.get("goal")
            if goal is not None:
                goal_path = f"/goals/{quote(goal.id)}"
                route_path = urlparse(current_path or "/").path or "/"
                focus_target = (
                    "#goal-action-dock-form"
                    if route_path == goal_path
                    else f"{goal_path}#goal-action-dock-form"
                )
                focus_source = "goal_action_dock_form"
            else:
                focus_target = "#operator-focus-current-action"
                focus_source = "operator_focus_action_form"
    return focus_target, focus_target_label, focus_source


def _breadcrumbs(
    root: Path,
    current_path: str,
    title: str,
    focus_context: dict[str, Any],
) -> str:
    path = urlparse(current_path or "/").path or "/"
    crumbs: list[tuple[str, str | None]] = [("Dashboard", "/")]
    family = _breadcrumb_family(path)
    current_goal = ""
    current_project = ""
    current_phase = "none"
    current_item = ""
    parent_href = "/"
    parent_label = "Dashboard"
    state = _load_workspace_state(root)
    saved_project = str(state.get("open_project") or "").strip()
    saved_goal = str(state.get("open_goal") or "").strip()
    saved_artifact = str(state.get("last_viewed_artifact") or "").strip()

    if path == "/":
        crumbs = [("Dashboard", None)]
    elif path.startswith("/goals/"):
        current_goal = unquote(path.removeprefix("/goals/"))
        parent_href = "/goals"
        parent_label = "Goals"
        crumbs.extend([("Goals", "/goals"), (current_goal, None)])
    elif path.startswith("/projects/"):
        current_project = unquote(path.removeprefix("/projects/"))
        parent_href = "/projects"
        parent_label = "Projects"
        crumbs.extend([("Projects", "/projects"), (current_project, None)])
    elif path.startswith("/delegations/"):
        current_item = unquote(path.removeprefix("/delegations/"))
        parent_href = "/delegation-runs"
        parent_label = "Delegation Runs"
        crumbs.extend([("Delegations", "/delegation-runs"), (current_item, None)])
    elif path.startswith("/runs/"):
        current_item = unquote(path.removeprefix("/runs/"))
        parent_href = "/delegation-runs"
        parent_label = "Delegation Runs"
        crumbs.extend([("Runs", "/delegation-runs"), (current_item, None)])
    elif path == "/artifacts":
        current_item = _one(parse_qs(urlparse(current_path or "").query), "path") or ""
        parent_href = "/workspace"
        parent_label = "Workspace"
        crumbs.append(("Artifact", None))
    else:
        label = next((label for label, href in NAV_ITEMS if href == path), title)
        parent_href = _breadcrumb_parent_href(path)
        parent_label = _breadcrumb_parent_label(parent_href)
        crumbs.append((label, None))

    current_goal, current_project, current_phase = _breadcrumb_local_context(
        root,
        family=family,
        current_goal=current_goal,
        current_project=current_project,
        current_item=current_item,
    )
    current_goal_label, current_goal_label_source = _goal_display_label(root, current_goal)
    saved_goal_label, saved_goal_label_source = _goal_display_label(root, saved_goal)
    if family == "goal" and current_goal_label:
        crumbs = [("Dashboard", "/"), ("Goals", "/goals"), (current_goal_label, None)]
    current_href = current_path or path or "/"
    focus_status = str(focus_context.get("status", "state_unavailable"))
    focus_target, focus_target_label, focus_target_source = _focus_context_target(
        focus_context,
        current_path,
    )

    rendered = []
    for index, (label, href) in enumerate(crumbs):
        text = _compact_label(unquote(label), 48)
        if href and index < len(crumbs) - 1:
            rendered.append(f"<li><a href='{_e(href)}'>{_e(text)}</a></li>")
        else:
            current_attr = " aria-current='page'" if index == len(crumbs) - 1 else ""
            rendered.append(f"<li{current_attr}><span>{_e(text)}</span></li>")

    rows: list[tuple[str, str | SafeHtml]] = [
        ("breadcrumb_status", "current_route"),
        ("breadcrumb_family", family),
        ("breadcrumb_title", title),
        (
            "breadcrumb_current_path",
            SafeHtml(f"<a href='{_e(current_href)}'>{_e(current_href)}</a>"),
        ),
        (
            "breadcrumb_parent_surface",
            SafeHtml(f"<a href='{_e(parent_href)}'>{_e(parent_label)}</a>"),
        ),
        (
            "breadcrumb_current_goal",
            SafeHtml(f"<a href='/goals/{quote(current_goal)}'>{_e(current_goal_label)}</a>")
            if current_goal
            else "none",
        ),
        ("breadcrumb_current_goal_id", current_goal or "none"),
        ("breadcrumb_current_goal_label", current_goal_label or "none"),
        ("breadcrumb_current_goal_label_source", current_goal_label_source),
        (
            "breadcrumb_current_project",
            SafeHtml(f"<a href='/projects/{quote(current_project)}'>{_e(current_project)}</a>")
            if current_project
            else "none",
        ),
        (
            "breadcrumb_current_item",
            _compact_label(current_item, 96) if current_item else "none",
        ),
        ("breadcrumb_phase", current_phase),
        (
            "breadcrumb_saved_goal",
            SafeHtml(f"<a href='/goals/{quote(saved_goal)}'>{_e(saved_goal_label)}</a>")
            if saved_goal
            else "none",
        ),
        ("breadcrumb_saved_goal_id", saved_goal or "none"),
        ("breadcrumb_saved_goal_label", saved_goal_label or "none"),
        ("breadcrumb_saved_goal_label_source", saved_goal_label_source),
        (
            "breadcrumb_saved_project",
            SafeHtml(f"<a href='/projects/{quote(saved_project)}'>{_e(saved_project)}</a>")
            if saved_project
            else "none",
        ),
        (
            "breadcrumb_saved_artifact",
            SafeHtml(_artifact_link(saved_artifact)) if saved_artifact else "none",
        ),
        ("breadcrumb_focus_status", focus_status),
        (
            "breadcrumb_focus_target",
            SafeHtml(f"<a href='{_e(focus_target)}'>{_e(focus_target_label)}</a>"),
        ),
        ("breadcrumb_focus_target_source", focus_target_source),
        ("breadcrumb_resume_surface", SafeHtml("<a href='/resume'>/resume</a>")),
        ("breadcrumb_write_on_get", "false"),
        ("breadcrumb_provider_calls_taken", "0"),
        ("breadcrumb_network_actions_taken", "0"),
        ("breadcrumb_external_effects_created", "false"),
    ]
    lines = [
        f"breadcrumb_now: {_e(title)}",
        f"breadcrumb_back: <a href='{_e(parent_href)}'>{_e(parent_label)}</a>",
        f"breadcrumb_resume: <a href='/resume'>/resume</a>",
        "breadcrumb_safety: read-only local route context",
    ]
    summary_rows = [
        (
            "route_parent",
            SafeHtml(f"<a href='{_e(parent_href)}'>{_e(parent_label)}</a>"),
        ),
        (
            "route_goal",
            SafeHtml(f"<a href='/goals/{quote(current_goal)}'>{_e(current_goal_label)}</a>")
            if current_goal
            else "none",
        ),
        ("route_goal_id", current_goal or "none"),
        ("route_goal_label", current_goal_label or "none"),
        ("route_goal_label_source", current_goal_label_source),
        (
            "route_project",
            SafeHtml(f"<a href='/projects/{quote(current_project)}'>{_e(current_project)}</a>")
            if current_project
            else "none",
        ),
        ("route_phase", current_phase),
        (
            "route_focus",
            SafeHtml(f"<a href='{_e(focus_target)}'>{_e(focus_target_label)}</a>"),
        ),
        ("route_focus_source", focus_target_source),
        ("route_resume", SafeHtml("<a href='/resume'>/resume</a>")),
    ]
    primary_focus_label = focus_target_label
    if focus_status == "available":
        next_action = focus_context["next_action"]
        primary_focus_label = str(getattr(next_action, "action", "") or focus_target_label)
    goal_label = current_goal_label or saved_goal_label or "No goal yet"
    goal_href = (
        f"/goals/{quote(current_goal)}"
        if current_goal
        else f"/goals/{quote(saved_goal)}"
        if saved_goal
        else "/goals"
    )
    project_label = current_project or saved_project or "No project"
    project_href = (
        f"/projects/{quote(current_project)}"
        if current_project
        else f"/projects/{quote(saved_project)}"
        if saved_project
        else "/projects"
    )
    focus_cards = [
        (
            "Next",
            primary_focus_label,
            SafeHtml(
                f"<a class='route-context-primary' data-route-context-primary='true' "
                f"href='{_e(focus_target)}'>{_e(primary_focus_label)}</a>"
            ),
            "data-route-context-next='true'",
        ),
        (
            "Back",
            parent_label,
            SafeHtml(
                f"<a class='route-context-secondary' data-route-context-back='true' "
                f"href='{_e(parent_href)}'>{_e(parent_label)}</a>"
            ),
            "data-route-context-back-card='true'",
        ),
        (
            "Goal / Project",
            goal_label if goal_label != "No goal yet" else project_label,
            SafeHtml(
                "<div class='route-context-duo'>"
                f"<a class='route-context-secondary' data-route-context-goal='true' "
                f"href='{_e(goal_href)}'>{_e(goal_label)}</a>"
                f"<a class='route-context-secondary' data-route-context-project='true' "
                f"href='{_e(project_href)}'>{_e(project_label)}</a>"
                "</div>"
            ),
            "data-route-context-goal-card='true' data-route-context-project-card='true'",
        ),
        (
            "Resume",
            "/resume",
            SafeHtml(
                "<a class='route-context-secondary' data-route-context-resume='true' "
                "href='/resume'>Resume workspace</a>"
            ),
            "data-route-context-resume-card='true'",
        ),
    ]
    focus_html = [
        "<div class='route-context-focus' data-route-context-focus='true'>",
        (
            "<div class='route-context-item route-context-current' "
            "data-route-context-current='true'>"
            "<span class='route-context-label'>Current</span>"
            f"<strong>{_e(_compact_label(title, 96))}</strong>"
            f"<a href='{_e(current_href)}'>{_e(current_href)}</a>"
            "</div>"
        ),
    ]
    for label, value, action, marker in focus_cards:
        focus_html.append(
            f"<div class='route-context-item' {marker}>"
            f"<span class='route-context-label'>{_e(label)}</span>"
            f"<strong>{_e(_compact_label(value, 88))}</strong>"
            f"{action}"
            "</div>"
        )
    focus_html.append("</div>")
    return "".join(
        [
            "<section class='panel route-context-strip' data-breadcrumbs='true' data-route-context='true'>",
            "<h2>Route Context</h2>",
            "<nav class='breadcrumbs' aria-label='Breadcrumbs'><ol>",
            "".join(rendered),
            "</ol></nav>",
            "".join(focus_html),
            "<details class='route-context-details' data-route-context-details='true'>",
            "<summary>Route evidence</summary>",
            "<div class='route-context-summary' data-route-context-summary='true'>",
            _kv(summary_rows),
            "</div>",
            _kv(rows),
            _ul(lines),
            "</details>",
            "</section>",
        ]
    )


def _breadcrumb_family(path: str) -> str:
    if path == "/":
        return "dashboard"
    if path == "/goals":
        return "goals"
    if path.startswith("/goals/"):
        return "goal"
    if path == "/projects":
        return "projects"
    if path.startswith("/projects/"):
        return "project"
    if path.startswith("/delegations/"):
        return "delegation"
    if path.startswith("/runs/"):
        return "run"
    if path == "/artifacts":
        return "artifact"
    for label, href in NAV_ITEMS:
        if href == path:
            return label.lower().replace(" ", "_")
    return "unknown"


def _breadcrumb_parent_href(path: str) -> str:
    if path in {"/", "/goals", "/projects"}:
        return "/"
    if path in {"/workflow", "/delegation-runs", "/actions", "/approvals", "/inbox"}:
        return "/goals"
    if path in {"/verification", "/ci-evidence", "/dogfooding", "/demo", "/health"}:
        return "/"
    if path in {"/memory", "/skills", "/profiles", "/workspace", "/resume", "/search"}:
        return "/"
    return "/"


def _breadcrumb_parent_label(href: str) -> str:
    if href == "/":
        return "Dashboard"
    return next((label for label, item_href in NAV_ITEMS if item_href == href), href)


def _breadcrumb_local_context(
    root: Path,
    *,
    family: str,
    current_goal: str,
    current_project: str,
    current_item: str,
) -> tuple[str, str, str]:
    try:
        storage = _storage(root)
    except Exception:
        return current_goal, current_project, "none"

    if family == "goal" and current_goal:
        try:
            goal = storage.get_goal(current_goal)
            state = _goal_state(root, storage, current_goal)
            return current_goal, goal.project_id, _goal_current_phase(state)
        except Exception:
            return current_goal, current_project, "unknown"

    if family == "project" and current_project:
        return current_goal, current_project, "none"

    if family == "delegation" and current_item:
        try:
            delegation = storage.get_subagent_delegation(current_item)
            if delegation is not None:
                project = _task_project(storage, delegation.parent_task_id)
                return delegation.parent_goal_id, project, "delegation"
        except Exception:
            return current_goal, current_project, "unknown"

    if family == "run" and current_item:
        try:
            coder_run = get_coder_worktree_run(storage, current_item)
            if coder_run is not None:
                delegation = storage.get_subagent_delegation(coder_run.delegation_id)
                if delegation is not None:
                    project = _task_project(storage, delegation.parent_task_id)
                    state = _goal_state(root, storage, delegation.parent_goal_id)
                    return delegation.parent_goal_id, project, _goal_current_phase(state)
        except Exception:
            return current_goal, current_project, "unknown"

    return current_goal, current_project, "none"


def _recent_items_panel(root: Path) -> str:
    items = _recent_operator_links(root, limit=8)
    used_defaults = not items
    if not items:
        items = [
            ("Goal cockpit", "/goals", "first-run"),
            ("Demo", "/demo", "fixture"),
            ("Verification", "/verification", "proof"),
        ]
    rows = [
        (
            f"<li data-recent-items-filter-item='true' "
            f"data-recent-items-filter-kind='{_e(kind)}' "
            f"data-recent-items-filter-href='{_e(href)}' "
            f"data-recent-items-filter-text='{_e(' '.join([label, href, kind]).lower())}'>"
            f"<a href='{_e(href)}'>{_e(label)}</a><br><span class='muted'>{_e(kind)}</span></li>"
        )
        for label, href, kind in items
    ]
    body = "".join(
        [
            "<aside class='operator-side' data-recent-items='true'>",
            "<h2>Recent Items</h2>",
            _recent_items_command_bar(root, items, used_defaults=used_defaults),
            _browser_route_history_panel(),
            _recent_items_filter_panel(items=items, used_defaults=used_defaults),
            f"<details class='recent-items-list-details' data-recent-items-list-details='true'><summary>Recent shortcuts ({len(items)})</summary>",
            "<ul class='recent-items-list' data-recent-items-list='true'>",
            "".join(rows),
            "</ul>",
            "</details>",
            "</aside>",
        ]
    )
    return body


